begin;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('7cd33083-a05e-5a3d-9835-1fe346d45d81', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-24', '16:30:00', null, '通常 / リストの使い方の習得', 'リストの学習は初めてとのことで、上記使用ツールと都道府県クイズを提示し、前者を選びました。 元のゲームを操作した上でリストの仕様をコードを見ながら説明し、その後は自由に作成をしました。 リストの基本的な仕様はすぐに飲み込めたようで、ひいろくんらしい鉄道クイズを作っていました。正解や不正解のときのスプライトの動きも工夫して、楽しいクイズゲームができていました。 基本的なリストの使い方はよくわかった、とのことです。', 'リストの基本的な使い方を学べたので、おばけのかくれんぼか神経衰弱を試してみても良いかと思います。', 'タイピング: チラシを渡して説明して、体験版をやりました。
盛り上がり: 6月以来の自由作成だったので、楽しそうに問題を考え作成していました。鉄道クイズにちなんだ豆知識？などもいろいろ教えてくれました。'),
  ('ed24b0a2-77ae-584a-bed5-7449b02bde9d', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2022-11-17', '17:30:00', null, '休み', null, null, null),
  ('f5060087-b3cf-5c32-ada9-db956870030c', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-22', '16:30:00', null, '振替え / 使えるコードを増やす だるまさんがころんだ', 'これまでの習慣で、ゲームを見せたらすぐに細分化を考え始めたので、そのまま記述させました。自身で作成する気満々だったため、チュートリアは見せませんでした。細分化の時点でアルごんの向きを数値で記載していました。 クリアのスプライトはメッセージを受け取った時に表示されることにもすぐに気づいて口頭で説明していて、メッセージを送るきっかけとなる主体のスプライトも理解して説明できていました。 ゲームを何度か見た上で、アルゴンの向きが左のときにアルくんが動いたら負けるということも自分で導き出せていました。 判定をコスチュームではなくて向きで細分化していたため、そのまま作成させました。「スプライトの～」ブロックがあることだけヒントとして教え、その後は「スプライトの向き」に独力で変更し、作成することができました。 振り返るタイミングなど、いろいろな数値を試してベストな時間を熱心に探していました。', null, 'タイピング: こどもタイピングの記録が順調にのびているのを喜んでいました。
盛り上がり: ゲームの仕様を自分で考えて理解すること、それを肯定されることをとても喜んで、楽しそうにしていました。 ほとんどの場合、たくやくんの理解であっているのですが、こちらでより簡潔な方法のヒントを与えたりすると、それはそれで素直に聞いて感心してくれていました。'),
  ('a25f3961-cdd5-5208-b820-f302692d9fc2', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-19', null, null, '通常 / 教室と授業に慣れる', '教材を提示しようとしましたが、本人が「今日やりたいこと」をしっかりと思い描いていて、一気に説明を始めたので、そうすけくんがやりたいことに教材の単元を落とし込む形で進めました。 上下左右の矢印キーが押されたときにスプライトを座標で動かす、スプライトの表示非表示、指定回数繰り返す、スプライトが指定した場所へ移動する、スプライトに触れたら隠すという条件分岐を学習しました。 座標については、なんとなくではありますが、覚えてきているようです。 表示非表示についてもすぐに理解していました。', null, '時間帯: その他
盛り上がり: ゲームを作るのが楽しくて仕方ない！といった感じです。 やりたいことがはっきりしているため、その作成に入ってしまえばこちらの説明もよく聞いて理解しようとすることができています。'),
  ('d3fb378c-5a2d-5b9a-8324-d280f2677fb1', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-22', '16:30:00', null, '通常 / 自分で考えて新しく作る。今日中に完成を目指す。 乱数・変数・メッセージを使ってオリジナル作品。 もぐらたたき。出現する猫を時間内に消すゲーム！', '魚がクリオネをたくさん食べるプログラムを提案しました。 向きがまだ苦手なようです。歩かすときに向きまで気が回らないようです。前回かなりしつこく言ったので、自分で思い出してプログラムし直しせていました。「回転方向を左右のみにする」というブロックも思い出せていたのでとても良かったです。 クリオネが魚を魚を食べたら、クリオネが他の部分に移動するプログラムをスムーズに作れていました！「どこかの場所へいく」の代わりにx座標、y座標にいれてもらい、そこで乱数を使ってもらいました。「スコアが50点になったら」の部分のプログラムが忘れてしまっていたので残念でした。かなり強調して説明しました。作品は完成しました！！ 時間制限をつけたかったので、変数と「〇秒待つ」の使い方を説明しました。', null, 'タイピング: 途中飛ばしてしまってキーの説明を見ず、いやになってやめてしまって残念でした。
盛り上がり: 先週やったことを比較的覚えてやってくれたので良かったです！！半袖で元気そうでした。'),
  ('a32a7222-4e1d-58e3-9123-8aa06a15b960', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-22', '17:30:00', null, '通常 / G１で滑らかなジャンプをやる→自由作成', 'G1は自分なりの方法で取り組んでくれましたが、すこし内容が複雑になっていたため、見本通りにプログラムしてもらって意味を考えてもらいました。しっかり理解できていました。 自由製作のときに、初めは横スクロールに挑戦してくれました。考え方は間違っていなかったので、時間があれば方法を紹介したいです。途中で方針を切り替え、スマブラっぽいゲームを作成することになりました。 前半学習したなめらかなジャンプを取り入れ、コスチュームの変化、スムーズな移動を行うことができていたのでとても良かったです。満足そうでした！スコアまでいっていないので、時間があればこちらも挑戦したいです。', null, 'タイピング: 集中して取り組めていました！
盛り上がり: 楽しく取り組めていました！良かったです！！後半はとくに集中して取り組めていました！！'),
  ('6ff75cf6-42f9-51a1-8c3b-e8276c3cb74c', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-22', '17:30:00', null, '振替え / 自由作成 完成までもっていく！', '最初にかみなりゲームを作成しました。こちらがとくに言わなくても、クリア画面、面白いかみなりの挙動を作ってくれました。カミナリが重なってしまう部分があったので、乱数の使い方について少しアドバイスをしました。 後半は前回作っていたゲームを整理＆修正しました。落下のプログラムの部分を整理しました。「ずっと」「もし」が及ぶ範囲について混乱しましたが、自分でプログラムをみて原因を解決できていました。最後に的が上に登ってくるようにしました。いろいろな方法で考えつつ、最終的にはうまく上に的が戻ってくるようになったので満足そうでした。こちらはほぼ新たなアドバイスをすることなく、少し間違えているときにツッコミをする程度でした。スコアも設定して完成しました。', null, 'タイピング: 集中して取り組めていました！！
盛り上がり: ひさびさに会いましたが、集中力がついたなというイメージです。 えらい！落ち着いていました！！'),
  ('3ba0d40a-2372-5d69-b7ef-df92984a8af0', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-19', null, null, '通常 / 「～まで待つ」と、音楽に関わるブロックの習得', 'ゲームを作るのが楽しい時期のようで、追跡ゲームにレベルアップが入れられた時も嬉しそうにしていました。 音楽をするときの反応は、はじめはイマイチでしたが、楽器のスプライトではなくて好きに作っても良いようにすると、乗り気になって面白そうに音をいじっていました。', '337拍子を開いて、繰り返しのパターンの確認だけしてあるので、次回は作成に入りたいです。', '時間帯: その他
タイピング: 相変わらず丁寧にがんばっています。
盛り上がり: 毎回作品を作るのが楽しそうです。どちらかというとゲームの方が好きなようですが、こちらが提示するものに対して基本的に受け入れて、がんばろう、楽しもうという姿勢が見られました。'),
  ('068a346d-ada5-5d42-839b-a21915105350', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-18', '17:30:00', null, '通常 / これまで習ったコードの復習', 'ドリルを読んでブロックにするのがあまり得意ではないようで、問題を読みながら頭を抱えていました。ブロックをまったく覚えていないわけではないのですが、文章を読解してブロックになおす過程で混乱するようです。 自由作成になってからは、とても生き生きと背景やスプライトを決めていました。やりたいことはスラスラと口で説明できて、さらちゃんもアイディアを話すときはとても楽しそうでした。', '金魚すくいゲームの完成を目指します', '盛り上がり: 自由作成になったとたん、一気に目が生き生きとして楽しそうに作っていました。 世界観を作るのは得意そうです。'),
  ('ca7116bf-5f31-5298-bc60-c62f57097716', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-11-21', '18:40:00', null, '通常 / ループの使い方の練習をする', '前半はアルスパークでおもてなしと言わせるプログラムを作りました。変数に文字を入れてその文字数回繰り返すループを作ることができました。ヒントを出しながらではありましたが自分でコードを書けたので、変数を使ったループには慣れたと思います。 後半はコードモンキーで、新しくforループに入りました。for... in... はバナナなどのグループがあるときにそれぞれの要素(バナナ)について繰り返し行うループだということを説明してやってもらったところ、ある程度自分でできるようになりました。サルを移動させるときに、向きを変えるのを忘れがちなので気を付けたほうがよさそうです。', null, 'タイピング: 集中していました
盛り上がり: もくもくと集中して作業を進めることができていました。わからないとき以外は手を止めずにやっていたので意欲が感じられました。'),
  ('5f115742-283d-5eb3-97f1-cf00b6ba72f3', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-11-21', '17:30:00', null, '通常 / 今までのコードを活かして自由に作品を作ろう', '先週に続いて太鼓の達人風ゲームを作っていきました。譜面が横に流れる仕組みをヒロト君と同様に以前作ったひよこのゲームから参考にしてもらい、この卵の動きはどう使えると聞いたところ、しっかりと動きのコードを指してこれ使えるとわかっていました。作り始めると、すぐに難しい大きい目標を立てて作ろうとするため、誘導させて小分けにやることを立て作っていきました。球が流れる仕組みは条件を2つ以上のときは「かつ」が使えるよと教えた所、手を止めることなくタイミングよく消す挙動すぐにできました。そのあと、今作っているものだと一定の間隔で流れてくるだけだったので、飽きそうになっていたので、流れる種類と間隔をランダムにして作ろうと提案しました。最初に掲げた夏祭りを作りたいと希望じゃなくてもこの提案に良いとおもっってくれました。種類わけの仕組みはできたので、次回は感覚のランダムとメッセージの送り先での流れの修正をしていけばいいと思います。', null, 'タイピング: 順調でした。'),
  ('7c2c114b-5113-584b-b479-ea58c467b601', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-21', '18:40:00', null, '通常 / スロットマシーン（https://app.arspark.jp/contents/5582）を行う', 'レース、スロット、３３７拍子をやってもらい、スロットを行うことに。 ▶︎乱数 ▶︎まで待つ〜 をいかにうまく使うか？が問題になりますが、一発で動きの乱数は気づきました。 コスチュームに乱数を入れること自体はやったことがなかったみたいで、乱数をコスチュームにも使えることを今日は学んでくれました。', null, '盛り上がり: 今まで習ったコードを使うか？の部分で色々とやり方はあるんだよ〜と話しながら進めてみました。答えが１つではないこと→自分のやり方でもコードの順番や試行錯誤をすることでできることを学び、とても充実した様子でした（細分化シートはあまり得意ではない様子ですが、体で覚えるみたいな感じでしょうか）やってみて、気づくという方が嬉しいみたいです。'),
  ('888ceb5d-85d9-5189-bf75-39cb36e7091a', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-11-21', '16:30:00', null, '通常 / 今までのコードを活かして作品を作ろう', '前回に続いて、太鼓の達人風ゲームを作っていきました。球が横に流れる動作を作るために、以前作った犬の動作を遊んでもらいました。コードを見ながら、動かしたい球の動きに改良できていました。球が右側に戻る時、どのタイミングで隠せばいいか悩んでいたので、コードと画面を見比べながら、球の位置関係を見ていき、一緒に入れる場所を発見できました。次に、タイミングよくキーを押したときに消えるようなコードを条件を2つ以上使いたいときに「かつ」を使うことを教えたうえで、作っていきました、キーと色判定を使って作っていたが、上手くできているかどうかわからない状態だったので、音をつけてみるとおいいよとアドバイスしました。基本的な構造は組めていたが、反応しないと一緒に悩んでいたが、ただ押すキーを間違えていただけでした。（笑）下のキャラクターに操作説明のセリフを加えるアドバイスもよかったです。', null, 'タイピング: 1つ1つキーを確認しながらやっていました。
盛り上がり: 悩み泊まるところがあったが、分かった時のリアクションは良かったです。'),
  ('6254763a-b95f-530d-939b-fc91112a1368', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-21', '16:30:00', null, '振替え / コンテストに出すパワポの確認', '最初に来た際に、USBを忘れてしまい急遽取りに行ってもらいました、 内容を確認し、春ちゃんの提出分と見比べ、自己紹介の部分（大会規定で書いてあった）が入っていないことと最後の終わりがないことが気になったので、そこを指摘しパワポ、原稿を修正してもらいました。音はまだ録音してないので、今日やってもしアップロードなどができなかった場合は明日の火曜日に来てねと伝えています。（まみさんにも連絡済みです）', null, '盛り上がり: ちょっと、生花の大会で疲れている様子であまりパワポも進んでいない感じでした。ただ、ここは入れた方がいいよなどアドバイスをすると「そっか」と理解していた様子でした。 また、自分の作品を色々な人に見てもらうこと自体が初めての経験だったのか少し緊張していた感じだったと同時に、嬉しさもあったようで私が確認したことで自信をつけて帰ってくれました。'),
  ('66ce6a36-4002-5f71-a32d-b4201430d3f9', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2022-11-21', '17:30:00', null, '休み', null, null, null),
  ('e5b9c5ac-4358-5373-955d-c08b8267c296', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, null, '2022-11-21', '17:30:00', null, '休み', null, null, null),
  ('270c17c3-b3fe-5068-baed-86e5084b5ec6', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-11-21', '16:30:00', null, '通常 / 今までのコードを使って自由に作品を作ろう', '先週に続いて自由作品でくじ引きを作っていきました。まず、ガチャガチャの作り方のチュートリアル動画を見せて、動画のどのコードがどうゆう風に使えるか考えてもらいました。そこで、コスチュームを番号を振り分ける知識も増えてよかったと思います。その後は順調に作っていき、完成した作品を見ると、銃があった時派手な演出をつけて面白みがありました。ただそれ以外のものが出てきたとき、出てきて3秒後に消えるだけの殺風景のだったので、音やいいものが出たよ演習を頼みました。自分でアイデアが思いついたら、声に出してくれるので、進捗状況がわかりやすいです。', null, 'タイピング: ミスタイプゼロでやっていました。
盛り上がり: 来たときはいつものようにおもしろ動画を見て、周りを巻き込み、授業中は作品が出来上がった時に見てみてと先生を呼びかけることがあって、楽しくやっていました。'),
  ('528a2268-429b-5d67-a21f-9f5d4529de69', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-21', '16:30:00', null, '通常 / コンテスト用の動画の確認、ファイルの送信まで含めて', '今日は動画を再度確認しました。音声と画像のタイミングはキチンと合っていたので、問題ないと思いました。送信まで手伝うことにしましたが、Googleの設定で２５メガまでしか添付ファイルとして送れないのがあるので、ギガファイル便で送る対応でお母さんと相談し、本日中に送ることになりました。', null, 'タイピング: スキップ
盛り上がり: 画像の中のはるちゃんは全然違う人に見えて、大人っぽく見えました。ちゃんと動画も画像と合っている様子でできていたので、素晴らしい！ またメールで送る際も色々とルールがあることを伝えたところ、少しずつ知識が増えていることに喜びを感じていました。'),
  ('1cb791e4-fb34-59f1-a6b3-d428a54f841d', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-18', '16:30:00', null, '通常 / チーズをさがせ！の続き', '敵が壁にあたったときの動きを作成するのにかなり迷っていたので、見本を見せながら敵の動きを分析して一つずつ動作を作っていきました。 壁に当たった時に、ネズミと同様に跳ね返る、向きを変えるという動きはすぐにできていましたが、向きを変えるブロックを何種類も作って敵が回転してしまっていたので、向きを変えるブロックを一つだけにさせて、どのような不具合があるかを実際に確かめさせ、解決方法を導き出させました。乱数を使うヒントは与えましたが、乱数と条件分岐を使うことで向きを変えるブロックが2つで済むことに自分で気づき、こういうやり方でできるんだと感心していました。 ゲームオーバーとクリアの背景を作成して、楽しそうに完成させていました。', 'ゲームクリアとゲームオーバーを時間ぎりぎりまで一生懸命作っていたので、座標と乱数の学習を復習がてら触れることができればと思います。', 'タイピング: 正誤率、打鍵速度ともに上がっています。
盛り上がり: 不具合が解決する方法がひらめいたとき、とても嬉しそうにしてくれます。 今日も、敵の動きのコードを作成して納得できたときは、きらきらしていました。'),
  ('d36f7b8b-d8db-5e57-b34f-c937910e7490', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-18', '18:40:00', null, '通常 / 放物線ジャンプで変数を使う▶︎オリジナル作品をつくる', '変数の使い所の理解 放物線のジャンプを演算を使いながら行う▶︎コードモンキーで関数などを使う時にも同じ意味があるんだよという説明のため ▶︎オリジナル作品で縄跳びを作成してもらいました。', null, 'タイピング: 前回よりタイピングの速さが早くなっているのか、成績がかなり増えていました（百円分のスコアが上がっていました。）
盛り上がり: 縄跳びの位置、判定の仕方など自分なりに考えていました。自分なりに考えながら作品へ落とし込んでくれていたので、本人も楽しかった様子です。'),
  ('ec97b151-b483-5ddc-ae51-37d2d0cd5f89', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-18', '17:30:00', null, '通常 / フリエを救え１（https://app.arspark.jp/projects/2665/editor）', '一度作ったことがあるものの、覚えていなかったため再度やってみることにしました。特にジャンプする部分は繰り返すというコードを使うことで動くことをビデオで再確認していた様子でした。少し違った単元をと思いジャンプの部分に変数を入れてみるということを教えてみました。今はわからなくても今後どこかのタイミングでまた変数の使い所がくると思うのでその時に思い出してくれたらいいなと思います。', null, 'タイピング: あ〜か行までの練習をしていました学校でもやっているようなので、かなり早くタイピングもできていました。
盛り上がり: チュートリアルを見ている最中はとても真剣にやっていて、ちゃんと判定をするかどうかまで見てくれていました。だんだんとコードを読む力が増えてきているなと思うので、写経をするのがとうきくんには合っているのかなと思います。'),
  ('a714d0af-03ff-5eb6-81bd-22081af8cff4', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-18', '16:30:00', null, '通常 / ジャンプゲームの続きと応用', '前回の続きで、ジャンプした時の音、スコア、ゲームオーバーの動作を作成しました。どのコードも使ったことがあるようで、お代を出すとすぐに対応できていました。 上記が完成後、応用ゲームを見せて、変わっているところを探してもらい、細分化をしたところで終了しました。', '応用ゲームを素材だけの状態から作成し始める予定です。', 'タイピング: 1年生のときからココアタイピングを自分のアカウントで進めているそうで、丁寧にうてています。
盛り上がり: 知っていることでも楽しそうに一生懸命取り組む姿勢がすばらしいです！ 応用ゲームで、背景が動くように見せるのをスプライトを2つ使ってやっていたり、木の本数の違いをコスチュームで表現したりしているところを面白がっていました。
備考: ココアタイピングをかなり先まで進めているようで、授業後は自分のアカウントで一生懸命練習していました。'),
  ('13949958-4452-566d-b872-e46c38ae361e', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-18', '16:30:00', null, '通常 / だるまさんがころんだを最終完成させる', 'もう一度チュートリアルを最初から見直して、鬼とプレイヤーのコードが逆になっていることを見直してもらいました。その上で最後に乱数の確認をしてみました（乱数ってなんだっっけ？の問い） サイコロをもう一度自分で作ったのを見直す→座標、秒などのコードで入れる数が変わるよという話までしました。', null, 'タイピング: うでだめしをやってLVを着実にあげていました！
盛り上がり: だるまさんがころんだの録音を楽しそうにしていました！'),
  ('6a8a9f12-cdf0-5cf1-babc-62c4120f3b11', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-18', '16:30:00', null, '通常 / 乱数のコードをどこに入れられるかを考える→だるまさんがころんだでコスチュームの判定をする際に、乱数と同じ考えで判定もコスチュームの何番で判定するを理解する', '乱数のコードをどこに入れるのか？を感じてもらうために最初に問題を出して、どれに入るか？をまずは考えてもらいました。 マルの部分に乱数のコードが入る、というのは理解できているものの、コードの意味合いを考えて入れることはしてない。→だるまさんが転んだでも判定がうまく行かない理由はコスチュームが何個あるや、確認をしないなどがあるので、そこで判定がうまくいっていない感じです。', null, null),
  ('d41ec122-02a2-510a-a7b4-fc23d6eb5ab4', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-18', '16:30:00', null, '通常 / 主体となるスプライトの理解', 'スプライトが2つあるプログラムにおいて、どちらのスプライトがどの動きをしているか、条件分岐の際に主体となっているスプライトや条件判断のもととなっているスプライトはどちらかというのを意識させて一緒に細分化をし、そのシートを元に作成していきました。 一つずつ質問する形では、多少迷うことはあるものの答えられるのですが、独りでみていくほどの気力はなさそうでした…。 メッセージの送信と、メッセージの受信による表示非表示などは自分でできていました。', null, 'タイピング: 毎パソに何度かチャレンジしていましたが、間でスペースキーを押すのを忘れたり、間違えた時の打ち直しに手間取るようで、最後は気分直し？にプレイグラムをしていました。
盛り上がり: 独りでやるのは面倒そうでしたが、一緒に考えていこうと促すと、素直に考える姿勢が見られました。なんだかんだ言いながらも、40分くらいですべてのコードを見て完成させることができていました。'),
  ('c5078d1f-bd7d-5f55-92ac-500c583687f2', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-18', '18:40:00', null, '通常 / おまつり射的ゲーム(自由作品)進める', '作っている作品の様子、構成を説明してくれました。論理的、具体的でとても分かりやすかったです。 敵が消える部分、スコアが足される部分は自分で考えて丁寧にプログラムすることができていました。「残り」の変数が0になっても弾が動けてしまう問題を改善してもらいました。演算のブロックを使ったり、制御のプログラムで論理関係を把握するのはまだあまり得意ではないようです。スプライト同士の関係も複雑になると混乱してしまう様子でした。 プログラムはできなくても、考えていることは筋道が立っていて素晴らしいです。作品は完成しました。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 授業最後にゆまちゃんと作品を見せ合ったり、遊んだりしていて楽しそうでした！'),
  ('be7be6b2-3e63-5e0b-ad53-fc9008015f7f', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-18', '17:30:00', null, '通常 / 演習問題 変数C 変数の使い方を学ぶ', 'だんだんはやく歩かすのは自分で考えてできていました。途中で関係のない演算をいれてしまっていたようです。スライダーで変数を変化させていろいろ試していました。 その後、1から100の足し算をプログラムしてもらいました。2つの変数が必要なことは理解できていましたが、その使い方は分からなかったようです。一緒にプログラミングしました。足す数と合計の変数の役割をとくに丁寧に説明しました。 「変数を変数ずつ変える」のブロックを作ったときに「あぁ～」と言っていました。あまり今までにない視点だったのかもしれません。', null, 'タイピング: 練習に2回ほど取り組んでいました。余裕がありそうです。大会に出れそうです。
盛り上がり: アレンジとしてコインをクルクル回すような動きを、コスチュームを次々と変えることで作っていました。けいとくんが興味津々でした。'),
  ('95635a5e-19ee-5bb9-81d4-f053da583c04', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-18', '18:40:00', null, '通常 / 演習問題 : B1〜3を先にやって自由作品', 'りんごとばななの演算の使い道がわからなかったというので、今座標の理解と共に演習問題をやることでコードの幅広い使い方が分かった様子でした。自由作品で射的ゲームを作りましたが、すべてに今日使ったコードを用いてもらうことで座標と言うを出しながら、弾が当たったら判定するまでを作っていました。', null, 'タイピング: こどもタイピングにそろそろ進んでもいい頃かもしれません。
盛り上がり: 判定とメッセージを送り合うなど、自分でゲームの進行を考える▶︎考えることが苦でなく楽しんでいたようでした。'),
  ('c008a551-b358-5097-a2f2-0de81cdb22b2', 'b2246586-4496-52f9-a825-be2488a00a31', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-17', '17:30:00', null, '通常 / 習ったコードをいかした自由作成', '「寝坊」というテーマで、ストーリー性のある動画を作成していました。', null, null),
  ('3300a35a-5860-50c6-8360-2f489c995b66', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-17', '17:30:00', null, '通常 / 単元別ドリルG-1 なめらかなジャンプ、自由作成', '最近のレッスンで何度かジャンプを取り扱ったので、復習と定着を兼ねてドリルをやってもらいました。 何度も作成してきたことは覚えているけど、自分で一から作成できるほどはわからない、とのことだったので、作成する変数とその初期値はヒントとしてこちらから提示しました。 横方向へのジャンプの動きは自力で作成できました。 縦方向の動きについては、変数を入れる演算式などはなんとなく覚えていたようですが、不等号の向きや変数を変えるタイミングなどは一緒にやる必要がありました。 ジャンプのドリル部分は完成できたので、ドリルで作成したコードをそのまま使った自由作成にうつり、スプライトが端までいったら背景を変える動きを作っていました。何をすればよいのかわからないとのことだったので、スプライトを手動で端に寄せさせて、そのときの座標をチェックさせたら、そのあとは自分で作ることができました。', 'ジャンプの後に地面にもぐってしまうバグがあるのを直すのか、先に行くか…', '盛り上がり: ジャンプの動きと背景を変えるところがスムーズに動くようになったときは、嬉しそうにしていました。'),
  ('7cd84c58-308e-5167-8061-7eec95c9dd2b', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-17', '16:30:00', null, '振替え / 選抜大会の動画作成', '制限時間ほぼぴったりの素敵な動画を作ってきてくれました！ 身振り手振りを加えたはるちゃん自身の映像を左下に小さく入れているところが、見ている人がより作品に興味を持てるようにうまく仕上げていました。 全体の感想を求められたので、スライドのタイトルと内容が誤解を招きそうなところの日本語を指摘しました。', 'はるちゃん自身の動画とスライドの動きがずれているところがあったので、それを直して持ってくるとのことでした。', '盛り上がり: 紹介動画として、はるちゃんらしく仕上がっていて、本人も楽しそうに作成できていました！'),
  ('5d0f194f-4e19-576b-a13c-6a9c6c7c4ef8', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-15', '17:30:00', null, '通常 / 以前の作品でシューティングに似ているのがある。上下左右の動きのプログラムを確認。その後、弾の挙動に注意しながらシューティングゲームを作成。', 'ずいぶん前に自分で作ったゲームを見返して、座標を使っての動かし方の確認をしました。敵の上下の動かし方に悩んでいたので、座標を使ってコントロールする方法を提案しました。「端で跳ね返る」を使う時に、座標で動かすブロックと併用できないことに注意が必要です。アバターの動かし方は自分で考えてプログラムすることができていました。 玉の動きの初期位置は、座標ではなく「〜へ行く」もこちらから少しヒントをあげると自分で気づくことができていました。ただプログラムを最後までキッチリ読むのがまだできていないので、「もし」「ずっと」の使い方を間違えてずっと玉が動き続けてしまい、かなり混乱していました。 最後にメッセージを使って終わりの表示をだし、ゲームは完成しました！', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 自分で考えつつしっかり取り組めました！楽しそうで良かったです。'),
  ('c20ca9df-c346-58ea-89a0-6276d880236f', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-15', '17:30:00', null, '通常 / 制御の単元別演習(F2ウォーミングアップ、F3、F4) 条件分岐を使った自由作品', 'F2、F3、F4どれも「もし」の使い方は良かったです。文章を読みながら整理しながら取り組むときには、あまり混乱しないのかもしれません。F4のとき、上下に動くプログラムに苦戦していましたが、少しヒントを出すと自分で気づいてスムーズにプログラムできていました。 オリジナル作品では、普段自分がプレイしているゲームの一面を作っていました。制御も正確に使うことができていたのでよかったです。ゲーム性も◎。時間内に完成しました。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: かなり集中して取り組めました！'),
  ('d9acabc4-9555-555a-994b-58cf3732c460', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-15', '16:30:00', null, '通常 / 角度をプログラムで制御する癖をつける。自由作品で楽しむ', '本人の希望で追いかけっこ風のプログラムを作ることになりました。自分の言葉でプログラムを説明することは出来ましたが、プログラムの言葉で表現するのは苦手なようです。 あるくんを動かすときに〇歩あるいてから向きを変えていたので、自分の実際の動きを考えてプログラムしてもらいました。プログラムする順番 「～に触れたら」というプログラムを作っていましたが、能動と受動の関係が曖昧で少し混乱している様子でした。 あるくんの頭の位置を固定することをリクエストしました。角度の復習をしつつ、「回転を左右のみにする」のブロックの存在を忘れていたので、紹介しました。自分がうまくプログラムできていない、間違えているときに「だめだ」と気づけるようになりました。最後にメッセージの送るタイミングについて一緒に考え、ゲームは完成しました！！', null, 'タイピング: 楽しそうに取り組んでいました。qの場所に少し戸惑っていたようです。'),
  ('488a9d04-f767-5cc6-8c88-1b5c4b5c59cf', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-17', '16:30:00', null, '通常 / 選抜大会の動画作成', 'PowerPointのスライド、Wordの原稿ともにある程度自作してきていたので、まずは完成させてから一緒に内容を確認していきました。 各スライドのタイトルやテーマと話す内容が微妙にずれているところを数か所指摘し、言葉を足したりしました。 記録ツールの使い方を説明し、ナレーションやポインタを一緒に使用してみました。 月曜日までにいろいろ試してみるそうですが、生け花のコンクールが重なっていて時間が取り切れないかもしれないとのことでした。', '動画の完成', '盛り上がり: 自分の好きなものを相手に伝えたいという気持ちがよく出ていて、楽しそうに作成していました。'),
  ('e33789ed-0d72-5b77-abde-1fb69b17db9b', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-12', null, null, '通常 / 基本操作コース04_追跡ゲーム 変数や演算式の導入', 'しばらく間があいたため、前回何をやったかあまり覚えていないとのことでしたが、ゲーム作成をするとわかると嬉しそうにしていました。 スプライトを矢印キーで動かしたりどこかの場所へ動かしたりすることは、これまでの学習が身についていたのか、特に迷うこともなくできていました。 変数や演算式も、今回の範囲は素直に聞いて理解できていたように思います。', 'レベルアップのスプライトを作成して完成させます。', '時間帯: その他
タイピング: ペースはまだゆっくりですが、丁寧にうとうとしています。
盛り上がり: ゲームが作れたことがとても嬉しそうで、お母さんにも得意そうに見せていました。 大幅な脱線もせず、丁寧に一つずつ作ることができています。'),
  ('57eeca79-85c8-5740-af79-7d4a0fe027f4', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '2863fe3b-74f5-59ec-b388-06ad4a82b75c', '2022-11-17', '16:30:00', null, '通常 / コードを読み解きながらジャンプゲームを作ろう', 'ジャンプゲームをコードを見せながら1つ1つ理解して写経して作っていきました。ｔころどころ「これはどうゆうコードかな」と質問して、しっかりと理解して答えられていました。写していく中にはまだ使ったことないコード（スプライトの他のスクリプトをとめる）もあったが、ただ写さず「このコード何？」と聞いて理解する姿勢を感じられたのがよかったです。アルくんと草のコードを描き終えたので、残りの草と木を次回作っていけばいいと思います。', null, '盛り上がり: 帰りにみずき君がジャンプゲームを大いに楽しんでくれました。'),
  ('02fa665d-8f8f-50bf-ae82-9b4ba779f330', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-11', '17:30:00', null, '通常 / 初めてのクローン', 'ゲームの体験時は、早々にカメラ部分をおさえてしまえばモーションセンサーが反応することに気付いて、裏技？で高得点をあげることに盛り上がっていました。 クローンを使って一つのスプライトを画面上にたくさん出していることを説明した後は、基本的には写経になりましたが、自分でアレンジしたコスチュームの数がどこの乱数に対応しているかなどもしっかりと気づいて数値を編集していました。', null, '盛り上がり: 写経になっても、しっかりとコードを見て作成できていました。 今までとは毛色の違ったゲームができて楽しそうにしていました。'),
  ('9d7a6f92-ea60-5f14-9ff6-c1483ee8d078', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-11-17', '17:30:00', null, '通常 / リストの使い方を学んで活用しよう', 'リストを使ったおボケかくれんぼを作成しました。スクラッチ歴は長いが、リストの存在は知っているはものの、使ったことがなかったそうです。でも、変数との違いはの質問に対してはしっかりとそれぞれの特徴を言い分けることができました。作成能力が高いので、リストの中に座標で分けるようにして少し遊んだ後フリーに作らせました。その結果、ゲームは普通に遊べたが、リストの使い方が無駄に無駄な重複があるような遠回り作りになりました。まだ知らなかったリストの長さや変数による番数の指定を教えてより良い作品に修正できました。アレンジも際立った個性になっていてよかったです。', null, 'タイピング: 作品作りのため無し'),
  ('cc09d6f4-7e17-5d33-a53f-eacb887bce22', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-11', '17:30:00', null, '通常 / 初めてのクローン', 'ゲームの体験時は、けいとくんととても盛り上がっていました。 画面上にたくさんスプライトが出ているにも関わらず、作成するスプライトが一つだけということに驚いていました。 コスチュームの数を増やしたりと、デザイン系のアレンジを楽しそうにやっていましたが、そのコスチュームの数がコードのどこに反映されていてどこを変更しなければいけないか、などは、自力では読み取り切れてないようでした。 写経したコードが何をしているところなのか、もう少しじっくり読み取っていきたい所です。', '足りないコードがあるため、プログラムが動かなかったので、次回はどのコードが何をしているのか振り返って問題点を自力で見つけることを目標にしてから次に進みたいと思います。', 'タイピング: 慣れるまでは少しやりづらそうでしたが、がんばっていました。
盛り上がり: 新しいゲームを作ること、写経しても構わないことについてはとても嬉しそうで、喜んで取り組んでいました。 ただ、作成後にプログラムがうまく動かなかった時の見直しはだるそうでした。'),
  ('4d81bca7-885b-551b-9586-bab885c6370b', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-11-17', '17:30:00', null, '通常 / リスト作品をアレンジしよう', '前回に引き続きリストを使ったかくれんぼのゲームを作りました。前回作るのに苦戦した乱数でリストの番数を指定するところを覚えているかどうか確認しました。難しいところであったが、説明できていたのでよかったです。残りのネコが見つかった時の、音がならないバグを直していきました。地球がネコに触れるの条件だとうまくかみ合っていなかったので、別の方法で区別する方法があるか考えてもらいました。誘導させてリスト番号が使えることに気づけて良かったです。そのあとのアレンジでは、することがないよつぶやいていたが、目が瞬きするのアレンジがリアル感があってよかったと思います。 全体的にゆきちゃんはリストは深く理解するまではいかない感じだったが、こんな使い方がある予定度には感じられたと思います。', null, 'タイピング: 体験版にも慣れてきて大会に出るそうです'),
  ('035c4e30-bcf7-56b9-92c9-c4f2d3aba852', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-11', '16:30:00', null, '通常 / だるまさんがころんだ', 'チュートリアルを丁寧に見て取り組んでいました。 ゲームで遊んでチュートリアルを見ているときは、どんな仕様かなんとなくわかっていたようでしたが、実際に作成し始めるとコスチュームの使い分けなどに少し混乱が見られました。', null, '盛り上がり: 前半は比較的集中して取り組めていました。 ゲームにも興味を持ってスプライトを選んだりもしていたのですが、好きなコスチュームを選んだり、単純に動かすときに次のコスチュームにするのではなく、コスチュームによって「だるまさんがころんだ」の判定をされてしまうことに少し混乱したようでした。 ゲーム自体は目新しく楽しんでいたようでした。'),
  ('0398c51b-2ede-5247-8bf3-6810bb74a71a', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-11', '16:30:00', null, '通常 / 背景スクロールの続き または だるまさんがころんだ', '授業開始時は「背景スクロールの続きをやる」と言って一度開いたものの、バグをつぶして完成させるのが面倒になったのか「新しいのをやりたい」と言って、たっちゃんと一緒に「だるまさんがころんだ」に取り組むことになりました。 「だるまさんがころんだ」をたっちゃんがプレイしているのを一瞥して「こういうのは知っているから自分の好きなように作る」と宣言して作成し始めましたが、わりとすぐに行き詰って見本を見たりしていました。 コードをぱっと見で判断して、そこから適当にアレンジをしてしまうのが惜しいところです。 最終的には写経でそれらしい感じにはなっていましたが、もっと細分化をして少ない一つ一つのコードをしっかり読み書きできることを目指していきたいです。', null, '盛り上がり: だるまさんがころんだを戦争反対？にアレンジしたりしているところは、とても楽しそうにやっていました。コード作成自体は熱心に楽しんでやれているのが良いところですが、根気が続かないので、与えるお題をもう少し単純かつ短めにして、自力での達成感を積み上げつつスキルを蓄積していけるようにしたいです。'),
  ('f59f6068-333e-5de5-b8e3-8fbb8a664a47', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-15', '17:30:00', null, '通常 / デジタル絵本水族館（https://app.arspark.jp/projects/20894/editor）を作っていたので、ここから条件分岐で隠すを増やしてみて実際に魚を釣っているようなゲームに変化させる', 'お兄ちゃんの追跡ゲームをちょっと見せながら、触れたら隠すというのをやってみようという話から最初に始めました（お兄ちゃんのゲームはポイントが入るというのでしたが原理は同じなので） ▶︎条件分岐を少しだけかじる感じで今日はやろうと思っていました。 ▶︎コードを写経（私のパソコンで見せて） ▶︎３つのさかな全部に同じコードを入れてみるまでやる その後、チュートリアル（C アイスを食べに1：https://app.arspark.jp/my/lesson_maps/basic）でもう一度条件分岐をやってみて、ゲームっぽいものを作るのに慣れるまでをやってもらいました。', '次回は一度条件分岐の部分を再復習して、サメから逃げるとかの追跡ゲームをやってみるといいかも。得点をつけるというよりかは隠す、表示するのほうで何回かやってもらいたいな〜と思います。', 'タイピング: タイピングはまだ手元がおぼつかないものの、ある程度打てる回数は増えてきている様子でした。
盛り上がり: 途中まではとても、？？？が頭に羽浮かんでいる様子でしたが、チュートリアルのアイスを撮りにいくゲームを見ながらを作り、最後はとてもうまくできたことに満足していた様子でした。'),
  ('181f0860-0f47-5400-b8a7-89f136324e88', '7d01236e-620e-5177-a6f4-af325a582aae', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-15', '17:30:00', null, '通常 / 乱数▶︎前回作った追跡ゲーム（https://app.arspark.jp/projects/22477/editor）の中で、獲物の動きを座標にしそこに乱数を入れるということで一度作ってみる', '乱数▶︎チュートリアルをみてサイコロのランダム表示を理解 ちょっと今回はコスチュームというので乱数を使ったので、追跡ゲームに戻ったときに座標に乱数を入れるというのが少し難しかったかもしれません。 ①入れる場所②入れる場所によって数字が変わるというのはなんとなく分かった感じでしたが、座標に関しては馴染みがない様子なので、乱数は今後 秒待つ〜、コスチューム、歩動かす、大きさなどの簡単なコードの方から乱数を使うことを慣らしていった方がいいかもしれません。乱数自体は理解しているのでそこは問題ないと思います。 また、座標を使って動かすがまだ上下左右でどっちにマイナスをつければいいのか？が混乱している様子でした。', '続きを行うか、もしくは違う単元を進めてもいいかも', 'タイピング: 授業がはじまるまでずっと一人でココアをやっていました。自分でタイピングすることがとても好きみたいで、レベルが上がることに喜びを感じていた様子▶︎もしかすると、アルスパークとかもクリアするみたいな喜びの方がいいのか・・・？
盛り上がり: サイコロの目をずっと動かすのが面白かった様子でした（ずっと変化するまでキー押していました）自由作品をつくるになった時に、きんぎょすくいを作ってもらいましたが、背景などお祭りっぽいのを選びたいなどディテールにこだわっているのもとても良いと思いました。'),
  ('e44753f3-2168-5785-b9bb-703a41b62535', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-15', '16:30:00', null, '通常 / スロットマシーン（shttps://app.arspark.jp/projects/19062/editor） スロットマシーンを乱数でコスチュームを変化させるを行った後、先週やっていたチーズを探せで邪魔者を追加する&乱数を使ってみるのをやる（アレンジ）', '▶︎チュートリアル乱数でサイコロをランダム表示 ▶︎その後に以前やっていたスロットマシーンのコスチュームを乱数でできるかどうかを試す ▶︎【DKゲーム】チーズを探せ 変更した箇所 チーズの動き「どこかの場所」▶︎乱数でXY座標、の最大最小の数字を確認した後にどちらにも乱数を入れてみる、〜秒待つに乱数', '邪魔者と触れたら〜の部分がまだ出来上がってないので来週その部分を違う単元で一度やってから、チーズを探せに戻るほうがしょうたくんの理解度が深まると思います。', 'タイピング: ステージ２を全てクリアできていました！だいぶタイピングの正確さ出てきたとおもいます。
盛り上がり: 乱数のポイント①入れる場所②入れる場所によって数字の大きさを変えること ↑しょうたくんはとてもものわかりがいいので、この部分をとても丁寧に伝えたところ、すぐ理解した様子でした。 また、自分で試す、違ったら変えてみるという試行錯誤など考える力があると思うので、ゆっくり丁寧に進んでいくと本人もとても満足するかなと思います！ゲームっぽいのはやはりすみきたいですね！'),
  ('4fb15d09-651c-558d-844a-86d0ec098c42', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-11', '18:40:00', null, '通常 / コードモンキー関数のあたりまでできるかどうか？', '多少時間が空いていたので少し忘れていた様子ですが、ゆまちゃんは英語がわかっているので、コードの何を今自分が書いているのかをきちんと理解しながら書いているのがよくわかります。特に for ~などの関数が入ってくると大人でもわかりにくい部分は、スラスラと解いていたので、文字のコードでゲームを動かすほうがもしかすると彼女には合っているかもしれないなぁと感じました（アルスパークでももちろんできているんだけど、文脈で捉えられるのは多分コードモンキーの方が楽しそう。）', null, 'タイピング: 5500円の利益を出せていました（タイピングの速さもないと利益がなかなか高額にならないので）'),
  ('95571a84-77cc-5675-8134-b6ee74290b84', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-11-14', '18:40:00', null, '通常 / 自由製作', '金魚すくいを作ると決めましたが、最初は上の方で色が変わっていく花火から作り始めました。いくつかある花火がそれぞれ違うスパンで色を変えるようにしたので、見た目が華やかになりました。水槽の上を金魚が泳ぐようにすると言っていたので水槽を最下層に持ってくるほうがよさそうですが、今日はそこまではたどり着けませんでした。', '金魚すくいの続き', '盛り上がり: 一生懸命作ろうという気持ちが強かったです。その分今日完成できなかったのを残念そうにしていました。'),
  ('c5b108ab-591e-5cc8-9f1f-db5f2ec809ff', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-14', '18:40:00', null, '通常 / コードモンキー', '最初は３週間ほど違うことをやっていたので忘れていたようでした。 ４２の答えを最初にみて、何をやっていたのか？を確認してから次に進むようにしました。 あらたくんの場合は、文字の意味が英語になるので、本人が英語の意味をわかっていないためか、何回も同じ部分で同じコードを書いていたりしていました。特にFor〜文の部分は多少関数っぽいのが含まれてくるので、何回も間違えてやり直しをしていました。', null, 'タイピング: タイピングは安定しているのでマイパソの検定に向けて準備を進めていければいいかなと思います。
盛り上がり: 今日はほかの子がどういう作品を作っているか？を途中途中みていたりしたので、多少息抜きになったようでした。期末が近いからか若干疲れモードではあり、それでもコード自体をやるという意欲自体はあったので、よかったかなと思います。'),
  ('af75b6ad-da75-579d-9ce7-f97627bcf2b9', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-11-14', '18:40:00', null, '通常 / 今まで作ったコードを基に自由に作品を作ろう', 'お祭りをテーマに自由に作品を作っていきました。最初の振り返りでインクリメント変数を見た時、拒絶反応が出ていました。それほど前回頭を使ったんだなと思いました。 作り始めは、いろいろなところにいるあるくんに行って、それぞれの屋台に行けるようなものを作っていこうとしていましたが、作り途中、それを作る大変さを知り、諦めて射的のみを作ることにしました。アルくんのデザインとか凝っていたのに消すのもったいないと感じました。その後、射的の基本的な形は作り上げたが、変数を使っていなかったので、変数を使ったコードを増やして提案しました。それを聞く耳持たずにほかのことをしようとしていたので、「的に当たったら落ちる」ことをアドバイスしました。それを聞いたら、ジャンプのところから引用してきて、そのコードを理解せずに使っていました。理解する実力はあるのにただ持ってきてつかうだけなのは少し残念です。 来週はもう少し要素を自分から考えて作ってほしいです。', null, 'タイピング: 作品作りのため無し'),
  ('d4632202-b313-5185-9ee6-3f8a73527275', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-14', '18:40:00', null, '通常 / ピンポンゲームまでやったコードで、今日のテーマ「おまつり」の自由作品がどこまでできるか？', '射的ゲームを作ることにしたようで、最初はたまがライフルの場所にいくというコードをまだ習っていなかったため、初歩的なシューティングゲームを見せて、これとおなじようにするといいかも〜と伝えました。 その上で、メッセージを送り合う、変数でスコアを使うなど自分なりに工夫をして敵とのリレーションを作ろうとしていました。まだ初めの方だったのでちょっと今日はびっくりしていた様子でした。（ちょっと彼には早かったか・・・？）', null, 'タイピング: 濁音文字のタイピングが苦手な様子ですがそれ以外は、スラスラとできていました
盛り上がり: ただ、げんきくんなりにやりたいことは明確にできていたので、今週金曜日もう一度自由作品の完成まで持っていければいいかなと思います。'),
  ('86e47ab9-af8c-5cfa-baf2-216a8961627e', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-14', '16:30:00', null, '通常 / テーマお祭りで自由作品を作ってみる', 'たいこの達人のようにタイミングを合わせた瞬間に、スプライトが踊るというゲームを作る予定で、まだ準備段階ではありますが大体どのスプライトがどの役目をするなどの使うコードの理解はできているようでした。', 'とても丁寧に作業を進める子なので、まだ１つのスプライトの動きも完成はしてないですが、ちゃんと細分化はできているので、来週はある程度ヒントを渡してあげて、どこまでできるか？をきちんと見てあげたいと思います。', 'タイピング: 以前よりローマ字うちには慣れてきている様子で、タイピングの速さも安定してきました。
盛り上がり: おうすけくんと同じ小学校だということが分かったので、2人でこういうゲームは？など相談しながら、じゃあこうしてみようかな？など和気藹々しており、彼の創作意欲がとても増していた様子でした。'),
  ('bf9bd587-15fc-52e4-a318-a4ff7317123a', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-11-14', '17:30:00', null, '通常 / 自由製作', '今までやってきた変数を使って何かゲームを作ってほしいと言うと、以前作ったジャンプゲームを応用してアスレチックゲームを作っていました。置かれている爆弾に触れると最初の場所に戻ったり、ゴールまで行くと次のステージに移ったりと自分なりのアイデアがよく組み込まれていました。「ずっと～」が必要な場所で入れ忘れることが何回かあったのでその都度伝えたのですが、バグに直結するので今後も意識してもらいたいところです。', null, null),
  ('179606c4-2db0-5e03-a84f-351794f2562c', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-11-14', '17:30:00', null, '通常 / 今まで作ったコードから自由に作品を作ろう', '今日あることを忘れていて30分くらい遅れてきました。お祭りをテーマに自由に作品を作っていきました。 最初に前回作った作品でどういったコードを作ったのか確認しました。跳ね返りが作るのがむずかったことの感想だけ覚えていました。 まつりの踊りを作りたいって言っていたが、それだけだと変数の使い道が欠けると思い、ゲーム性のあるものを作ろうとアドバイスしました。太鼓の達人風に枠組みだけを作って、それを次回作り続けると思います。', null, 'タイピング: 作品つくりのため無し
盛り上がり: アルスパークの踊れるキャラが少なくてがっかりしてました。'),
  ('7f11b3f6-e4ad-52f1-8b0d-fdb5e7686855', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-14', '16:30:00', null, '通常 / ピンポンゲームの最初おさらいをしてから再度スイッチ変数を使ったバレーボールを考える →主語が反対になっているだけだから、そこの部分だけがピンポンの応用だと考える その後「おまつり」をテーマにして自分で作品を作る', '自由作品に関しては、変数を使ってというお題を出して、くじ引きのゲームを考えていました。最初演算の不等号の向きを間違えたりして、うまく条件分岐の〜でなければを使った時にコードが動かないなどの不具合は見られたものの、シンプルに最初は考えてから、〜でなければを使うといいよと伝えたところ、うまくお金が減るシステムを作れていました。', '来週は景品が出てくるところまで', '盛り上がり: ちゃんとお祭りっぽい雰囲気にしたり、くじを引いて景品が出てくることなどを考えたりして、自由に自分で作品をつくる方が彼には合ってるみたいで、いつもよりとても集中していました。'),
  ('9b3904ce-8710-5897-9eaa-1cdaf3029837', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-11-07', '17:30:00', null, '通常 / ペンで図形を描く', 'えにしくんの学年だとまだ算数で角度を習っていなかったりして難しい部分もありましたが、ペンの使い方や繰り返しのコードの練習はできました。円の描き方を教えたあと、五輪のマークを描いてみようと言うと、少し時間はかかりましたが自分で考えて位置などを変えて描くことができました。途中で「ずっと」のブロックをたくさん重ねたりして遊んでいましたが、脱線から戻ってくることができました。', null, 'タイピング: 今回は少し長めにやっていました'),
  ('583615ff-caea-5714-80ca-9bfa035127b0', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-11-12', null, null, '通常 / 迷路ゲーム', '作成途中では、「ネズミが壁をすり抜けないようにしよう」「邪魔者のクモを動かそう」などと、作らないといけない場所を自分で考えることができていました。ネズミをキーで動かすときは、そのままの向きではなく進む方向を向いてから歩かせることを教えました。また、以前も扱った「～まで待つ」を使いこなす練習をすることができました。', null, '時間帯: その他
タイピング: キーの場所をだんだん覚えながら頑張っています。
盛り上がり: 自分の作ったゲームがちゃんと動いたのがうれしそうでした。'),
  ('17147e34-72e9-5044-8369-18e4ab20a2fe', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-11', '18:40:00', null, '通常 / 2回目。教室に慣れつつ！ 腕試しにピンポンゲームをどこまで自分の力でできるのかを挑戦！', 'とても論理的に考えることができていました。自分の使えるツールが多くあり、逆に考えすぎてしまう場面もありました。 パドルの動きはすぐに理解できていました。マウスのx座標を使うのが難しかったようですプログラムには少し時間がかかりました。 点数をいれるときに、端でバウンドしたときの細かなバグまで気をくばっていました。動きのスクリプトと点数のスクリプトを分けることを提案しました。ゲームは完成しました。 アレンジとしてホッケーのように2人で遊ぶものを考えてくれました。時間がなかったので出来ませんでしたが、次回挑戦するのも面白いかもしれません。', null, 'タイピング: 丁寧に取り組めていて良かったです
盛り上がり: 集中して取り組んでくれました！'),
  ('8eba7675-d13f-5203-a64b-5eac43624fb4', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-11', '17:30:00', null, '通常 / だるまさんが転んだ（動画をみながら作成）', 'チュートリアルを見ながら一緒に進めました。プログラムする場所を間違えることなくプログラムできていたので、しっかり動画をみることができていました。最初に〇分までは頑張る！と約束したのが良かったのかもしれません。最後までチュートリアルは終わりました。 途中、x座標の向きについて聞いたり乱数について質問したりしました。間違っていてもレスポンスが来るので良かったです。プログラムの順番や勝ち負けの判定については、追加で説明を加えました。 途中席を立つ回数が少し多かったのが残念でした。比較的集中できていたと思います。', null, 'タイピング: 楽しく取り組めていました。評価もSがほとんどで良かったです！キーの位置は把握でき始めているようです。
盛り上がり: 自分の声をレコードしたり、作品で遊んだり楽しんでいました。'),
  ('c613c3eb-4bf5-58e3-bc79-e831c9c8bb99', '13bd73d0-f535-5291-8362-6712e5cd7384', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-11', '16:30:00', null, '通常 / 基本操作ピンポンゲーム（https://app.arspark.jp/contents/6829）の完成とジャンプ（https://app.arspark.jp/contents/19670）を途中まで行う', 'ピンポン→スコアの判定で主語を入れ替えてしまったために、変数がうまく作動しないということはありましたが、そのほかはほぼヒントなしで自分で作れました！ ジャンプ→ジャンプ自体はすでに自分で何回も行っていたようなので、すぐ繰り返しでジャンプというのが理解していました。卵の動きをクローンを使ってやろうとしていたので、まずは最初に座標で動く〜というコードでやってみるといいよということと、やり方はもう一つあるからそれを違う時にまたやってみようと話しました。', 'ジャンプは最後のクリアの部分まで', 'タイピング: 最初は不安だったのか、練習モードでタイピングしていましたが、ちょっと簡単だったためうでだめしの方で2回目でチャレンジしてもらいました。多少寛太くんにとっては難しかった（ぎゃぎゅぎょなど濁音のタイピング）ものの、学年的には正答率などは素晴らしいので、今後は速さを一緒に身につけて行けたらいいなと思います。
盛り上がり: ヒントがなくても自分で考えることができること、またヒントが少しあるだけで修正でき、どんどん授業を重ねるたびに知識が増えることが嬉しい様子でした。'),
  ('dc602cf6-01d4-5f6d-8a8a-1ed2504aa757', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-11', '16:30:00', null, '通常 / 追跡ゲームの応用「チーズを探せ」（https://app.arspark.jp/contents/19662）', '追跡ゲームを１カ月半前ほどに行っているので、追跡ゲームのカードをみながら、どういうコードを書くのか思い出しながら作成してもらいました。最初はねずみとチーズの動きをできるか？をやってみる', '引き続き来週は、「敵」にあたったら〜のコードを書いてもらおうと思います。 ちなみに乱数は今の所使っていません。', 'タイピング: 正誤率76% だいぶタイピングには慣れている様子なので、今後はこども〜Playgramをやる方でいいかなと思います。
盛り上がり: →細分化シートに書いてもらってそれを自分なりの考え、できることで書いてもらいました。「ねずみが動いた時の向き」は忘れていたものの、多少ヒントをあげることで動作を作るまではできました。（迷路にあたったら跳ね返るのみ、どういう風にコードを書くのかを教えました）'),
  ('b28a0111-253f-5d8e-b32a-b7ba8963c885', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-11-10', '17:30:00', null, '通常 / ゲーム作成', '他の子はリストを使ったものを作っていたのでまさきくんもどう？と誘いましたが、自分のゲームを作りたいと言っていました。今回は、追いかけてくる猫から逃げるデスゲームを作りました。最近はストーリーものよりも操作して遊べるものを作ることにハマっているようです。完成したら先生に遊んでほしいということで、それまでは自分一人で完成させたいと意気込んで作っていました。', null, '盛り上がり: やはり自分の作ったゲームを他の人に遊んでもらったときに一番楽しさを感じているようです。'),
  ('b3145d07-f20a-5fe6-99fd-9af6eba29288', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-11-10', '17:30:00', null, '通常 / リストの使い方の種類を増やそう', '前回に引き続き占いのゲームの続きを作っていきました。まず、復習もかねて「この占いではリストはどのように使われている」って聞いたところ、選択肢と答えることができたので、この場合でのリストの使い道の理解は定着していたと思う。残りを作っていくと、ストップを押したとき、セリフが残らないバグが発生しましたが、コードの止め方の種類を検討して直せました。 次に、神経衰弱のゲームを遊んでもらい、承太郎君より早いスコアで勝ち誇っていました。そこでこのゲームでのリストの使い方を確認してもらいました。複数の座標の位置を記憶することができると共有しました。 その使い方をするお化けのかくれんぼのゲームを作りました。最初にフリーに作ってみて手放したが、リストの位置を記憶するコードは作れたが、どこから作ればいいか悩んでいたので、指針の手助けをしました。そこで、リスト内からランダムに選ぶコードの作り方に特に悩んでいました。ここの部分は、見よう見まねでなんとなく作っていた感じがしたので、1個1個コードの理解とともに作っていきました。このリストと変数の併用は難しいので、使い方さえ知ってもらえればいいと思う', null, 'タイピング: やるものが変わってもタイピングは速かったです'),
  ('eaa9272c-ae5d-58bb-80fc-4a0c22af6eb8', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-11-10', '17:30:00', null, '通常 / リストの使い方の種類を増やそう', '前回に引き続きリストを使ったゲーム作りをしました。振り返り代わりに前回ほぼ完成したコードをよりよくするために、リストの乱数による何番目指定にリストの長さに使ってみて作るように提案しました。間が空いたので最初は知らんって言っていましたが素早く自力で作ることができました。 次にゆきちゃんと足並みそろえるために、神経衰弱のゲームを遊んでコードを読んでみせました。難しいコードなので、完全理解とはなかったが、何とか理解をしようとする姿勢は積極的感じました。 それを簡易化したがお化けのかくれんぼのゲームは、特に迷うことなく1人で作ることができました。', null, 'タイピング: 1分間の練習だとおもったより打ててなくて少しがっかりしてました'),
  ('003e24b5-a7be-51fb-888a-8387ef970d35', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-08', '18:40:00', null, '通常 / 条件分岐、変数、乱数の使い方の習得', 'よくあるゲームのパターンを自分で作成するということで、とてもやりがいありそうに、熱心に取り組んでいました。 迷路を背景ではなくスプライトにして扱うことに感心していたようでした。 チーズがネズミに取られたあとの出現場所を、自作の段階では「どこかの場所へ行く」としていたため、何度かプレイさせてチーズが迷路の壁と重なって取りにくい状況になる場合があることを確認させ、解決策を考えさせました。その結果、座標の範囲を指定すること、範囲の部分をランダムにすることを導き出すことができました。 虫の動きについても、最初に作成したコードでは壁にあたったときに回る方向が一方向だったため、袋小路に入ってしまうと虫が同じところを回るだけになってしまうことを確認してから、どうすればよいかを考えてもらいました。乱数を使うこと、条件分岐で逆方向への回転を使うことは思いついていたので、乱数と等式のブロックを組み合わせるヒントを与えたら、正解にたどりついていました。', null, 'タイピング: 現時点ではスピードはそこまで速くないですが、丁寧なので、すぐに伸びるのではないかと思われます。タイピングに取り組む意図も説明し、納得して取り組んでくれているようです。
盛り上がり: ゲームを作ることがとにかく楽しそうでした。 今回作成したゲームで覚えたスキルを流用できそうなパターンを想像しているとき、とても生き生きしていました！ 今後自作するゲームで使えそうな「パーツ」を覚えることを喜んでくれているようです。'),
  ('73fea4de-6dc9-5cbb-8b32-e260daaed124', '7d01236e-620e-5177-a6f4-af325a582aae', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-08', '17:30:00', null, '通常 / プログラムを開いてもらって復習。ゆっくり思い出す。 教材を進める（追跡ゲーム）', 'ゲームの素材を自分で工夫しながら集めることができていました。x, y座標の使い方や、ずっとをしっかり覚えていてくれてスムーズに使うことができました。次に何をプログラムするのかも自分で考えてできていました。 「最後まで」音を流すブロック、スコアのつけ方（＝）、もしを使うときの注意点について説明しました。 10点になったらプログラムが終わるようになっています。勝利のメッセージの表示や、難易度アップは次回取り組みたいです。', '勝利のメッセージの表示・難易度アップのアレンジなど', 'タイピング: 授業前後にも熱心に取り組んでいました！えらすぎ！！かなり余裕そうだったのでPlayGramのとっくん「むずかしい」に挑戦してもらいました。次回から変更します！
盛り上がり: とてもたくさん喋って積極的に参加してくれました！楽しそうで良かったです！'),
  ('394fc930-f514-5cb3-aa1b-8ffe1e9d0d59', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-08', '17:30:00', null, '通常 / プログラムを開いてゆっくり確認したのちに、デジタルアニメ入門編（チュートリアルのやつはキャラクターが喋るけど、大きさを変えたり色を変えたりしてみたいと思います）', 'チュートリアルをみながら取り組んでもらいました。「〇キーが押されたとき」のブロックを注目してもらいました。 一通りできたあとで、復習としてスプライトのサイズを大きくしたり、色を変えたりするプログラムに変更してもらいました。またサイズを小さくするプログラムをこちらが作った上で、「〇キーが押されたとき」のブロックを持ってきて完成させてもらいました。 45分ほどで集中力が切れてしまったので、最後はかずとくんのプログラムをのぞいたり、逆に今日やったことをかずとくんに披露してもらったりしました。楽しそうで良かったです。', null, 'タイピング: 繰り返し挑戦できていたので良かったです。評価がなかなか上がらないので次のステージに進めていません。
盛り上がり: 授業前後に遊んでいるものからすると、ゲームに加えてアニメーションの方にも興味があるようです！'),
  ('9186b107-18f4-5b01-9f1e-194f71f97919', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-08', '16:30:00', null, '通常 / ひさびさなのでドリルを少し進めた後、やったことを使って自分でオリジナル作品を作る。', '自分で作品を作る時間を長めにとりたいとのことだったので、2題になりました。 問題15：「1秒待つ」をプログラムし忘れていましたが、それ以外はとてもよくできていました。 問題16：あまり見たことのないプログラムだったようなので少し混乱していました。プログラムを読むということがあまり慣れていないようです。 今日ドリルでやったことを使って自由作品を作ってくれました。かなり楽しそうに取り組んでくれたので良かったです。集中もできていました！ただテーマやストーリーがなく、自分が学んだものがただ並ぶような内容になってしまったのが少し残念です。少しずつ想像力が大きくなっていくと嬉しいです。', 'おいかけっこのプログラムを作りたかったそうです。次回も挑戦する予定です（ドリルをいくつか進めたあとにやるといいかも）', 'タイピング: 今日は普段よりも多くのステージに挑戦してもらいました！集中して取り組めていて良かったです
盛り上がり: 学校でプログラミングの本を借りたそうです。本を見ながら自分で作る予定だそうです。'),
  ('67211ae9-c2e5-5670-93a9-61e8afe26782', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, null, '2022-11-08', '17:30:00', null, '通常 / 比較的シンプルなゲームを自力で作ってみる→見本との違いをみて考える', '▼まず見本のゲームをやってもらい、どんな構成になっているかを口頭で分解してもらった。（それを、中島が紙に絵を描いた）どの順番でどんな動きをプログラミングするか？という問いかけに対し、パーフェクトに回答。①アル君が右に動く動き②アルごんがだるまさんがころんだと言う動き③最後に、クリアとまけの設定 ▼まずは自分で全部プログラミングしてみて、躓いたタイミングで「ヒント欲しい時言って！」と声をかけたところ、かなり自走できるた。 ▼条件分岐がどうしても難しく考えすぎてしまう傾向があり。 これは、ミズキ君に限らず、みんなに共通。条件分岐が整理できたら大したもんですが。 ▼「あるゴンのコスチュームが＃なら」のブロックは使ったことがなかったので、 このブロックを使うよというヒントだけで、使い方を習得できていました。 ▼音の「ピッチ」も使ったことがなかったので、試してみた。', '▼自分が作った作品で「条件分岐」の復習 ▼「〇〇〇のコスチュームが＃なら」と「〇〇〇のコスチュームが△△△なら」の違いの確認 ▼音の「ピッチ」の使い方', 'タイピング: ノーミスだったのがすごいです！！
盛り上がり: やりたいゲームがあった（Scratchで）ので、自力でだるまさんがころんだを仕上げたら、後はずっと自由でいいよというと、もースピードで進め始めた 笑）'),
  ('5654694f-b5b1-5bb8-911e-1a6c5b087e5b', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-07', '17:30:00', null, '通常 / コード探求⇒入れ子の構造、させたい動作をブロックで表す、変数', 'ゲームで遊んだ後に細分化を進めましたが、頭に入ったからというのでそのまま作成に入らせてみました。 ネズミの動きについてはプログラミング親子大会で作成した「クリオネのビーチクリーン」の仕様をよく覚えていて、自信ありげに作成していました。（キーが押されたときに、動いたあとに向きのブロックを置いているのは、一応指摘はしましたが今回はこれでいい、とのこと…） ねずみが迷路の壁にあたったときの動きは見本を何度も見せましたが、「跳ね返る」以外の言葉が出てこなかったようで、「もし端についたら跳ね返る」ブロックを使っていたため、同ブロックの意味を説明しました。「跳ね返る=逆方向に動く」がなかなか思いつかず、結局誘導尋問のようになってしまいましたが、一つ作成したら、残り3方向は自分で作れていました。1か所、条件分岐ブロックの位置を間違えていましたが、スプライトの動きを見て自分で間違えたところを見つけることができました。 チーズの動きも、以前の作品と同様に「どこかの場所へいく」で満足そうに作成していたため、今回はこのままにしておきました。後日乱数の使用例も説明しておきたいところです。 虫の動きについては何から取りかかってよいのかわからないとのことだったので、正解を写経してから説明しました。', 'チーズの動く位置や、虫の動きで使用している乱数についてあまり触れられていないので、乱数の復習をしてから先に進めると良いかと思われます。', 'タイピング: P検での前回の記録を抜きたいと集中して取り組んでいました。 毎パソの説明をしたところ、ぜひやりたい！と乗り気で体験版にチャレンジしていました。 慣れたらスコアが上がっていくことも実感できたようなので、毎回練習していきたいとやる気になっていました。
盛り上がり: ゲームらしいゲームが作れたことを喜んでいました。 チーズが迷路に隠れてしまうことなども「おかしい」と気づいて解決方法を探していました。 55分間、集中してがんばっていました。'),
  ('cf73f801-3582-5862-b86d-d5de4eccd136', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-07', '16:30:00', null, '通常 / 選抜プログラミング大会用の動画作成', '動画のもとになるスライド作成の続きをしました。 構成は自分の中でできているとのことだったので、まずは完成を目指してもらいました。', '木曜日にスライドを動画にして練習をする予定です。', 'タイピング: ローマ字、和文など3種類ほど試していましたが、ローマ字で練習して挑戦したいとのことでした。
盛り上がり: ゲームのイメージとも統一性がもてるよう、フォントや色使い、使用する絵のテイストなどにもよく気を配って作成していました！'),
  ('fb168a83-e824-5bc8-a9a8-5ef943ebbe70', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-11-07', '18:40:00', null, '通常 / 図形を描く', '今までのコードモンキーでは繰り返しが入れ子になっている構造が苦手でしたが、今回は入れ子をすんなり作ることができました。スプライトがどういう動きをするのかイメージすることができていたと思います。今回あらたくんにとって難しかったのはスプライトを回転させる角度の部分で、図を描きながら一緒に考えました。最終的には円を使った模様を描くことができ、図形の描き方はマスターしました。', 'コードモンキー', 'タイピング: 毎パソは初めてでしたが集中していました
盛り上がり: 淡々と集中して取り組んでいました。'),
  ('cdd96ed7-a7be-56aa-ae0f-c5b7ef184e76', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-07', '16:30:00', null, '通常 / バレーボールを変数で作る（https://app.arspark.jp/contents/6253） を最初のスイッチする部分の理解から始める', '最初はスイッチをスペースキーで判断するという部分からはじまり、バレーボールの触れたらスイッチが切り替わってボールが飛ぶというゲームへ作成することにチャレンジしました。 スイッチの部分は理解はとてもできているものの、触れたらジャンプしているようにボールを見せることができなかったので次回はその部分の説明からです。', null, 'タイピング: 最初は、スペースキーを入力するのに戸惑っていましたが2回目のチャレンジになると普段のタイピングになり、コンテストへ参加することにも意欲的でした。
盛り上がり: スイッチが切り替わる時に、押された〜ないまで待つのコードを使わないとバグが発生してしまうんだよということを伝えたところ、スイッチがきちんと切り替わっていたことに喜んでいました。'),
  ('8c2bf81f-263e-54ef-a6bb-43476bd89cde', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-07', '18:40:00', null, '通常 / リスト（https://app.arspark.jp/contents/3362）と1~100の和の数を使って、乱数の問題を作る→答えも乱数で正解かどうか判定する', 'インクリメントの変数、合計の箱という変数の理解を先にしてもらい、1~100の和を変数で計算してみる→リスト（https://app.arspark.jp/contents/3362）を行い、問題に対しても変数が使えること（問題の量が多くなると答えを合わせるのが大変だよねという話の流れにして）を伝えました。 その上で、単元別演習の乱数＋乱数の答えをリストで作るというのを作りました。 インクリメントの部分までは自分で答えることができましたが、乱数と乱数の足し算になると変数の使い所が増えるので多少混乱はしていたものの、解答の説明をしたところ、理解をした様子でした。 また演算のりんごとばななの使い所が今までわからなかったらしいのですが、今回の単元で該当の演算を使ったので、演算の使い道の広さを感じてくれたようでした。', '今回のコードを短くする？可読性を上げるコードにするか？', 'タイピング: ミスが5個以下だったので、タイピングのコンテストもぜひだいきくんには出てほしいと思います。
盛り上がり: 難しいところを考える部分がとても頼もしいです。'),
  ('db7658ae-890d-5278-840a-3ea25e4abf2a', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-07', '17:30:00', null, '休み / 当日連絡のため振替なし', null, null, null),
  ('bd8ddd0a-b5ce-581a-9214-76259e4de0a9', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-07', '18:40:00', null, '休み / 当日連絡のため振替なし', null, null, null),
  ('20f4d2d5-f461-59f6-80e9-b71eabb5f1c2', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-07', '16:30:00', null, '通常 / 先週の続き スロットマシーン（https://app.arspark.jp/contents/5582）', 'メッセージを送り、次の数字を止めるという部分で先週止まっていたのでその続きを今回はしました。判定の部分のみ、考え方が難しかったのでチュートリアルを見てもらいました。だるまさんがころんだで使った、コスチュームが何番目になったら答えが合うというのを使っているのを理解できた様子でした。 それ以外は、かなり自分の頭で考え言葉でも説明できているので、次はジャンプ系のコードへと進んでもよさそうです。', null, 'タイピング: プレイグラムで腕試しをしてみました。ちょっと難しかったようですが、レベル６は取れていたのと、チャートを見なくても打てるようになっているので、タイピングの練習は順調にできていると思います。'),
  ('ac968f29-0d07-5007-b9dd-e497fdf36033', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-31', '17:30:00', null, '通常 / 変数を使った等速ジャンプを学ぼう', '変数を使った等速ジャンプを作りました。まず、変数を使わず回繰り返すを使ってジャンプを作らせました。次に2倍のジャンプしてみてと作らせて、また元に戻す作業をしてもらい、手間のかかかることを体験してもらいました。しゅうくんはこの作業に少し大変といっていました、そこで、変数を使うことで直す箇所が減るという利点を体験できました。変数を入れるとき、マイナスの入れ方が菜穂さんの2，3度の説明で理解できて良かったと思います。そのあと、しゅうくんはアレンジ力がいいので、軽くゲームを作って完成させました。最後に遊んで終わりならないように今日使った変数を利点を確認しましたが、しっかりと答えることができたので理解はできていると思います。', null, 'タイピング: タイピング上手くいかずがっかりしていました
盛り上がり: 最初のタイピングを納得いかなかったで最後にもう1度やってベストスコアが出ました'),
  ('67657dce-6046-5609-b745-babd20fb9cfd', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-31', '16:30:00', null, '通常 / 計算を通してカウンター変数を学ぼう', 'はるちゃんと同様に１から１００までの和を表すコードを作ってもらいました。1から順序良く足していくように作ってっと指示したところ、「回繰り返す」のコードを使うというヒントを上げることなく作り上げていました。2の倍数のみの和も変更箇所をすぐに指摘できていたので、次に演算を用いた方法で作ってみて指示しました。えーわかんないとかこれでいいじゃんとか時間稼ぎの文句はあったが、いざやるとできたコードに違和感あるといっていたが、完成できていました。おうすけくんはプログラム的な思考の感が質問とかに出てきてよいです。 次に、乱数で選択した数字の計算問題を作りました。説明を聞いては一人では進んでいなったで、完成したコードを見て理解を深めていました。細かいアレンジを含んでいてよかったです。', null, 'タイピング: 今日はタイピングのモチベが低かったです
盛り上がり: ジョジョのはまりがなんかずれている'),
  ('f7342a82-0f2d-5c2e-b989-a822116619a8', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-31', '16:30:00', null, '通常 / だるまさんがころんだ（https://app.arspark.jp/contents/22487）の完成とスロット（https://app.arspark.jp/contents/19664）を細分化から始めて作成してみる', 'だるまさんがころんだは、判定の部分で「歩いている最中に振り向かれたら、まけ」を送る部分の考え方が難しかったようですが、新しく コスチュームの何番目と演算を合わせることで判定するという箇所を学んだことで、やれることが増えた楽しみを覚えたようです。 スロットは、考え方自体はとても良くゲームの仕組みを理解し、１が止まった後に２が止まるというリレーションも理解ができていたように思います。', 'スロットの続きから', 'タイピング: 着実にタイピングはローマ字の組み合わせが覚えられてきているので、早くなっていると思います。
盛り上がり: ゲームの過程を理解できている様子で、きちんと自分の言葉で説明できることが素晴らしい！'),
  ('c2dd0c74-59c2-5a71-bc1b-7f13f48ffd5e', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-31', '16:30:00', null, '振替え / 乱数入門', 'サイコロを自分で作れるというのがとても楽しかったようでした。コスチュームをランダムに変える⇒ランダム⇒乱数と、すぐに連想できたようで、乱数ブロックに設定する数もすぐに理解できていました。 完成したサイコロゲームで何度も次の目を当てるゲームをしていました。いずれテキストが進んだら、サイコロの目予測ゲームにアレンジしたら喜ぶかもしれません。 サイコロの目予測でとても盛り上がったので、そのまま対戦型じゃんけんゲームを作成しました。サイコロと同じように作るというヒントで、自分でコスチュームを見て乱数を設定できていました。 じゃんけんゲームに日本刀のスプライトを追加して、負けたらアオシ君がマウスで操作して負けた方のスプライトを消すように作成して大変盛り上がっていました。お迎えのおばあちゃんと弟君にも披露して、満足そうでした。', null, 'タイピング: 先週と同じ個所にチャレンジして結果がBからAへと上がっていたのが嬉しそうでした。
盛り上がり: サイコロやじゃんけんというランダム要素のあるものが、予想以上に本人にハマったようで、とても楽しそうに作成していました。 あかしくんに丁寧にゲームの説明をして遊んであげているところがお兄ちゃんぽかったです。'),
  ('d31b40e7-e8cf-5f88-9d56-1d964fad522c', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-31', '18:40:00', null, '通常 / 落下しながらジャンプするを理解するために変数を使う', '変数のルールを最初に説明、Y座標との関わり方、落下と地面で止まる、そこからジャンプすると分けて考えることを説明しました。 最初はちょっと分かりにくかった見たいですが、過去に自分でプラットフォーマーというゲームを作った時にやったことと同じコードを使ったといっていたので、どのコードを使ったかは覚えているようです。 落下が一番難しい部分ではあるので、今後もどこかのタイミングで練習させてあげるといいと思います。', null, 'タイピング: 1分間の体験Verで、５タイプのみのミス。だいきくんはタイピングは嫌がっていますが、本人の実力はかなりのものなので、ぜひタイピングコンテストに出てほしいと思います。 タイピングの正確性などもちゃんとしているし、ちゃんと練習を重ねればいい線までいくとは思います。
盛り上がり: 自分でできることや覚えていることがあると楽しい様子です。特に難しいコードになると集中力が格段に上がるので、だいきくんの場合にはちょっと難しいぐらいがちょうどいいのかもしれません。'),
  ('dd68f3ec-c314-5308-bc3f-37d6751c395b', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-31', '16:30:00', null, '通常 / 計算を通してカウンター変数を習得しよう', '1から100までの和を計算するコードを作るよう「合計」と「たす」の変数を用いて課題を出しました。あれこれ手を試していましたが、進まず悩んでいました。100回繰り返すという発想も思いついていなかったので、式を用いて各変数の動きを確認してみていきました。次に2の倍数のみを足していくように提案したとところ、変えるべき場所を直すことができていたので、理解はできていたと思います。図形のときにも思ったが、はるちゃんは数字や図宇敬は苦手かなと思います。 次に乱数を使って計算問題を作るとき、聞いて待つのところに乱数を直接入れていて、答えの演算の乱数と異なっていました。それがなぜだめなのか理解できていなかったので、変数の中に入れてあげることで固定をできるよと伝えて挙げました。', null, 'タイピング: スピードがはやくなってきました'),
  ('e939a7bf-51f1-59d0-9295-8121bac95cb2', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-28', '17:30:00', null, '通常 / 授業体験', 'Scratchのチュートリアルを見て自分でいろいろ作ってみているとのことで、ネコを歩かせる基本操作は全く問題ありませんでした。 洞窟ダイヤのアレンジでは、ダイヤをとったら次のステージにいって、次のステージでダイヤをとったらクリア画面を出すというアレンジを、背景のイベントのみを使ってうまく作成していました。 「【Prg】55 走ってゴールを目指せ！キャットランゲームを作ろう」「アクションゲーム_移動とジャンプ 」で遊んでコードを少し見せてから、アレンジよりもゲームを作成したい様子を見せたので、追跡ゲームに入りました。 基本の動きはすぐに完成できたため、アレンジを好きなようにやってもらいました。 スコアが増えるごとにスピードアップをさせたいとのことで少し考え込んでいたので、速さも変数にすることを提案したところ、あとは自分で作成できていました。 クリア画面を出すところでは「～まで待つ」のブロックだけ紹介しました。 ゲームをクリアしたあと、一気にスラボーのクローンが増えるアクションを作って喜んでいました。', null, 'タイピング: プレイグラムは学校でやったことがあるそうですが、タイピングは特別得意なわけではないとのことでした。
盛り上がり: 1時間半近く、夢中になって作品を作っていました。基本的なコードはほぼ作成経験があるようでしたが、基本を学ぶことの意味などもテキスト一覧表を見ながら説明し、理解してくれていたと思います。 アクション系のゲームが好きだそうで、作成しながらどんどんアイディアがわいてアレンジが止まらなくなる、といった感じでした。'),
  ('c1e8c569-81bb-5d0b-b104-12f950f2beee', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, null, '2022-10-28', '16:30:00', null, '休み', null, null, '備考: 11/22振替予定'),
  ('08c8dc1d-a935-530b-a9ab-61c9da7bff8c', '13bd73d0-f535-5291-8362-6712e5cd7384', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-10-28', '16:30:00', null, '通常 / 角度の確認、ピンポンゲーム', '角度はまだ習っていなかったため、初めはぴんとこなかったようですが、分度器を見せて実際の角度をはからせたところ、なんとなくイメージがわいたようでした。 ピンポンゲームのボールの動きについても、実際にスプライトを回して動いたときの様子を分度器と比べて納得していました。 マウスを使ってスプライトを動かすのはやったことがなかったようで、矢印キーでやりたそうにしていましたが、新しいスキルも覚えようということでまじめに取り組んでくれました。「マウスのx座標」を使うことには素直に感心していました。 「跳ね返る」という動きを、「動き」のブロックの範囲内で説明させ、答えることができていました。 跳ね返るときに角度を変えるだけだとうまく跳ね返らないことを実際に見せ、どうすればよいかを一緒に考えて「○歩動かす」ブロックを導き出すことができました。', 'スコアとクリア画面を作成予定です。', '盛り上がり: ピンポンゲームを作るのはとても楽しかったようで、チャイムが鳴ってからも「ここだけ仕上げたい」とゲームオーバーのコードを一生懸命作っていました。
備考: 家でもアルスパークを見てみたいようだったので、かんたくんのアカウントを教えました。'),
  ('a06692e4-25aa-5ef0-abbf-4e20db9cfd53', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-28', '17:30:00', null, '通常 / ポケテピ', null, null, 'タイピング: スロット/アルスパーク'),
  ('bcbd8e51-cc89-5b35-a25e-0ca3733d5ff3', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-28', '17:30:00', null, '通常 / スロット（新しいブロック/メッセージ）', 'コスチュームの変化速度をコントロールするための「〇秒待つ」が分からなかったようです。何回もやっているのに残念でした。数字の変化を止めるプログラムは自分で考えてできていました！ 数字を3つ揃えるプログラムでは、「数字が揃ったら」を「コスチューム番号が揃ったら」というブロックの言葉で置き換えすることができていませんでした。「もし～」のブロックをどう組み合わせるのかに苦戦していました。 判定のメッセージを送るタイミングをプログラムの言葉で説明できず、「キーを全部押したら」のタイミングをなかなか発案できずに困っていました。ゲーム自体は完成しました。 自分の言葉をプログラムの言葉に置き換えて表現するのが苦手なようです。', null, null),
  ('8f9772ae-0b7c-52a5-953a-a1d47c361018', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-28', '18:40:00', null, '通常 / 検定復習', '勘違いや文章の読み間違いが多かったようです。15分ほど時間を作って、自分が提出したものを見直してもらいました。ボールがうまく動かない現象が最後まで残ってしまいましたが、文章がきちんと読み切れず、プログラムの順番がうまくいってないからでした。ちなみに本番は終了2分前にアレンジをしていなかったので急いでやったそうです。 時間が余ったので、前回作ったクイズ問題のプログラムを活用しつつ、リストの説明をしました。', null, 'タイピング: 利益がしっかりでていました！すごい！'),
  ('c4637f14-521f-59fc-9b89-b1bffabc66c5', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, null, '2022-10-28', '16:30:00', null, '休み', null, null, '備考: 喘息だったそうですが、教室には2度ほど顔を出してくれました。'),
  ('f232f7f1-1f80-55b4-bfef-d35e90635701', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-28', '16:30:00', null, '通常 / 背景スクロールとジャンプの組み合わせの習得', '前回作成した背景スクロールがうまくいかなかったところのバグ探しから入りました。 一つ目の背景が左端まで動いた時のx座標をそのまま「x座標<-465」としていたため、<と<=の違いを簡単に説明し、解決しました。 ジャンプについては、最初はとらくんがおすすめというScratchのゲームを参考にしたがりましたが、コードが多すぎて自分でもよくわからなくなっていたので、「【単元】ジャンプの応用③ アル君の冒険（チュートリアル）」を参考にさせ、コードを写してから編集を自力でさせました。 いつもは参考にする作品について、「僕のおすすめはこっち」と言ってなかなか聞いてくれない所がありますが、今日はさすがにどちらのコードが見やすいか一目瞭然だったせいか、珍しく早々に折れてくれました。', null, '盛り上がり: 背景とキャラクターがゲームらしく動くようになったのは嬉しそうでした。 シンプルなコードの方が読みやすく作りやすいということを、ほんの少しだけ実感してくれたかもしれません。'),
  ('eccad3db-ff41-539b-a1e2-41793ac2d680', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-28', '17:30:00', null, '通常 / だるまさんがころんだ（https://app.arspark.jp/projects/21760/editor）をチュートリアルを見ながら作成してみる（乱数をどれだけ覚えているか？のおさらいを含めて）', 'チュートリアルを見ながら作成するのは、得意な感じ。今回はコードが少し長いだけに途中集中力がどこまで持つかが心配ではありましたが、なんとか全部終えることができました。 途中途中、なぜコスチュームが２の時に負けなのか？乱数ってなんだっけ？など質問をしながらおこない、ある程度コードの意味を理解してもらうように促してみました。', null, 'タイピング: 第１話がやっとおわった状態。FGHJは確実に理解をできているような感じです。
盛り上がり: 鬼が日本刀にするなど、自分なりにストーリーがあるようで、声を録音する際にも自分なりのだるまさんがころんだを録音して、遊んでいました！'),
  ('0910ee81-1bed-59ac-a2ae-f699642c6955', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-28', '17:30:00', null, '通常 / だるさんがころんだ（https://app.arspark.jp/projects/21760/editor）を最初から考えて作成してみる', 'どの部分で判定をするか？（コスチュームが左を向いた時に、まけになる）という部分は理解ができているものの、やはりコードを連続して書くことが苦手な様子。 着眼点がわかっているだけにとても勿体無い。ただ私が「こうじゃない？」「こうだと思わない？」など問いかけをすると軌道修正できる。', null, 'タイピング: 短い文章はお題をだされたら打てるものの、コードの方でメッセージに名前をつけるなどをめんどくさがる傾向。今後のコードの可読性などを考えると少しでもメッセージなどで名前をつける癖をつけたいところ。タイピングができるのにもったいないなぁと思います。
盛り上がり: まけ、クリアを自分なりに描いてアレンジすることができ、そういう部分はとても楽しそうにしてやってくれました。ただし、アレンジに引っ張られて本来のコードを書くことを忘れがちなので、本人がやりたい部分を途中で止めて、やらないといけない授業の部分になるべく早く戻してあげるのが必要かなと思いました。'),
  ('7979085f-ec5e-5306-be9f-1a42985008b8', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-28', '16:30:00', null, '通常 / 337拍子（https://app.arspark.jp/contents/8681）をやって、その後にチューリップの歌を自分で作ってみる→繰り返しのコードを理解する', '337拍子をチュートリアルを見ながら作成→今回のコードのポイントとして同じコードが使われている部分は繰り返しのコードを使うとコードを省略できるようになることを理解するのが目的でした。 基本的にはどこを繰り返すのか？を理解できているので問題はないとおもいます。チューリップの歌に関しても、どこが繰り返しなのかもよく理解はできていたと思います。 その上で、ジャンプのゲームにも繰り返しは使われているのだということを説明。 まだちゃんとは理解できているか？はわかりませんが、これから先繰り返しのコードを使うことを覚えてくれたと思います。', null, 'タイピング: 基本的にはタイピングはとても強いので、今後はタイピング大会にも出れるようにしていければなと思います。'),
  ('0bf978b8-f038-5e40-9695-2ebccd11ea36', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-24', '18:40:00', null, '通常 / 検定の復習', '検定の問題自体はよく読めているが、変数の使い方で裏の裏を書きすぎて、最初のコードの部分が躓いてしまっていた→そこから他の部分も動かないため確かめようがなく、問題の意味がわかっているものの、焦って答えを間違えていた様子。 全体としては悪くはないので、どの部分で変数をきちんといれるのか？また動かない時はどうしたらいいのか？などを再度おさらいしました。', null, 'タイピング: 集中してできていました。'),
  ('cfc17a05-9cfb-52cb-80cf-7c9b2dbe9a56', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-28', '17:30:00', null, '通常 / 放物線のジャンプをやってみるのが最終目的。その前にジャンプの応用として「【単元】ジャンプの応用 アル君の冒険」（https://app.arspark.jp/contents/22415）でどこまで習ったコードを使えるか、地面に触れるという判定をどのようにするか？を確認', '前回やっていたことのおさらいとして、まずは繰り返しを使ってジャンプ。 その後地面の判定の部分が難しかった様子でした。私があらたくんに手がかかってしまったため、きちんと教えられなかったのが心残りではありますが次回、地面の判定を再度おさらいしていければと思います。 ただ、全体のゲームをどう作成するか？の理解はできているので、問題はないかと思います。', null, 'タイピング: 段々と左手は薬指を使いながらタイピングできるようになってきました。まだ右手はひとさし指だけで打つ癖はあるもののだいぶ進歩したなぁと思います。'),
  ('46213ede-d024-5bc9-8b6b-4d8175330929', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-24', '16:30:00', null, '通常 / レースゲーム（https://app.arspark.jp/contents/4865）２種類目のの変数の使い方（カウント）→だるまさんがころんだ（https://app.arspark.jp/contents/22487）の判定の考え方', 'レースゲームでは再度変数の使い方をおさらいしました、ここではカウント（繰り返しを使うことで、〜と言うの羅列をたくさん使わなくてもできるということを認識）を行いました。 その後、判定の部分もキチンと理解できたのでだるまさんがころんだへ移りました。 だるまさん〜では、一番のキーポイントになるのはコスチュームということなので、見た目のコードをどれだけ使いこなせるか？という話をし、判定は触れる〜や点数だけではないということを理解してもらいました。まだ全てが完成しているわけではないので次回は続きから、です。', null, 'タイピング: まだ大文字と小文字の判断に悩む、濁点文字のタイピングが苦手な様子。それでも一生懸命タイピングしようとしているのをみると、乗り切ってやるという意気込みが見えて頼もしいです。'),
  ('7026a717-2180-537a-a992-c9e49cd103e8', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-22', null, null, '通常 / 337拍子（https://app.arspark.jp/projects/21551/editor） 音のツールを使ってみる→そこから337拍子を書いてみる（繰り返すというコードが入ることに気が付くのも含めて可読性を上げる）', 'まず初めに音のツールの使い方の導入から始めました。 音符自体が知らないようなので、音階はコンピューターだと数字で認識すること、また音楽を自分で作るためには楽譜を見ながら、その音に相当する数字を入力しなければならないことを確認。その後337拍子をチュートリアルを見ながら行いました。 音階自体がきちんと理解できているか？は微妙ですが、基本的なコードの理解（音を並べないと音楽が作成できない、同じコードが繰り返されてる部分は繰り返しのコードを使えばコードを省略できるなど）はなんとなく理解した感じです。', null, '時間帯: その他
タイピング: 中段のタイピングをおこなっています。基本的にはタイピング自体慣れている感じなので心配はしてないですが、今後何かのメッセージなどを送り合うなどの作業が入ってきた時にめんどくさがらずにに、ちゃんと名前をつける癖までつけてあげたいです。
盛り上がり: 音楽が作成できた時にとても嬉しそうにしていました。また違うゲームで、どの部分に音が使われているか？など自分で実際にゲームをおこなって音があることで楽しさが増えることも実感していたようです。'),
  ('ea8f9829-4f7d-5f97-a929-6160c2a2247b', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-27', '17:30:00', null, '通常 / リストを活用させていこう', '最初に先週のリストの振り返りをし、変数との違いも理解していました。リストを使った占いかお化け探しを遊んでもらい、占いを作っていきました。承太郎君との足並みをそろえるために、まず細分化をしてもらい、どこにリストを使えるか考えてもらいました。その結果、ゲームの流れを作れていて、占いの選択肢にリストを使うことが書かれていてよかったです。実際に作り始めると、リストに溜まり続けていて、指摘して全部消すのコードを追加していたり、ランダムを作る際に乱数が思いつかなかったり、少し忘れていたところもありました。途中で保存されなくて消えてしまうことがあったが、7割くらいは進みました。次回はストップ前のランダム表示から作っていけばいいと思う。', null, 'タイピング: コースの倍以上の金額になっていてすごいです
盛り上がり: 承太郎君に図形のヒントを出す際に大雑把感が楽しくできていました。
備考: タイピングが速いので、入力コンクールの話をしてみたところ、ぜひともやってみたい！とのことでした。（大原）'),
  ('bbb4cf70-380d-54d4-aecf-43ef996b877e', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-10-27', '17:30:00', null, '通常 / ゲームを作る', '最初作業を始めるまでには時間がかかってしまいましたが、今日はいつもとは違うものを作っていました。猫が人間に追いかけられて捕まったら終わりというシンプルなものですが、変数を使ってスコアもつけられていました。不必要にスクリプトを乱立させる癖があるみたいなので、できるだけまとめたほうがいいよということを伝えました。', null, '盛り上がり: 絶叫して机を叩くほどお餅ゲームに熱中していました。少し落ち着かせた方がいいかもしれません...'),
  ('50eb5c25-5316-5316-9257-20920e91bf87', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, null, '2022-10-27', '16:30:00', null, '休み', null, null, '備考: 当日欠席連絡(コロナ) 振替対象外'),
  ('481cf0ef-d093-5677-b897-e834121297a2', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, null, '2022-10-27', '16:30:00', null, '休み', null, null, '備考: 10/27現在 振替日未定'),
  ('20400c13-f08a-5019-912d-fb51a64f958a', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-27', '17:30:00', null, '通常 / コードの確認（だるまさんがころんだ）', 'ゲームで遊んだ後、素材だけのファイルを開いたとたんに何から手を付けていいのかわからなくなったのか、「めんどくさい」という態度を示していました。 完成版のコードを隣に開いて見せても、コードが多くて「何をすればいいのかわからない」とぼやいていたため、コードの少ない「クリア」「まけ」スプライトから見ていくことをすすめ、ゲーム開始時にはどうなっているべきか、どのタイミングで動きがあるかを答えてもらったところ、作る気になってくれました。 完成版のコードを少しずつ読んで、ここではどんな動作をさせているか、コスチュームの向きなども照らし合わせながら見ていくことで理解できてきたようでした。 「だるまさんがころんだ」の声のピッチが変わりすぎるのが不満だったようなので、どこを変えればよいのかを考えさせ、変数の範囲を変えることができました。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 最初は少しだるそうにしていましたが、一つ一つのコードと動きがつながってくると、一気に作品を仕上げることができていました。 完成後に、作成したコードの解説もすることができました。 【ゲーム改造】02 完成版 月面OMOCHI探査隊を、夢中になってやっていました。'),
  ('75bca946-c716-5495-9cb2-b89eeda063e7', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-27', '17:30:00', null, '通常 / 図形を描こう リストを活用しよう', '最初に先週のリストの特徴や変数の違いを問いましたが、不足なく特徴を答えることができました。 まだやってなかったペンを使った図形描きをしました。最初は余裕こいて正方形を描いていたが、正三角形を作るときに困惑していました。鉛筆を使って視覚的に向きがどう変化しているかヒントを与えた甲斐もあってできました。できていないときはいらいらしていたので、図形への苦手意識は意外とありました。書き方のコツを教えたうえで円を描いてみてと提案したところ、回転する角を小さくすればいいとすぐに方法を考え付いていたので、理解は深まったと思います。最後に星を描いてみた時は、計算が苦手みたいだったので、求める角度を誘導してやりました。 残った時間にリストの占いをしたところ、多少ごり押しのところもあったが、ゲームを動きは作れていました。次回少し中身を改良して、きれいなものにしたいと思います。', null, 'タイピング: ミスタイプが少なくなっていきました
盛り上がり: 最後に騒がないだろうと思っていてが、結局熱中して騒いでいたので面白かったです。'),
  ('f147a535-3787-55ab-94f0-c87e6a64d5ed', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-27', '17:30:00', null, '通常 / 現在のスキルチェック/検定3級問題', '検定を受ける意味を、資料を使って説明しました。しっかりと納得して聞いてくれ、自分のスキルを客観的にはかれるということにもとても興味を持ったようでした。検定もコンテストも「受けていいの？！」と、チャレンジできることを喜んでくれました。 問題は25分ほどで解き終わっていました。 使用しているブロックはすべて正解していましたが、2つのコードを1つにしているところと、繰り返すブロックの順番を変えているところがありました。動きには問題なかったので正解にはなると思われますが、コードを1つにするか2つにするかによって動きが変わることもあり、問題文もそのヒントになっていることを説明し、納得してくれました。', '2級の問題をぜひ見てみたい、とのことでした。', 'タイピング: タイピングはあまり得意ではないという自覚のようです。手全体を動かして打つ癖があるので、なるべくホームポジションを意識した方が結果的に速く打てるようになるという話をしました。
盛り上がり: 検定やコンテストにはとても興味を示していて、受けるように声をかけられたことを素直に喜んでくれました！ 検定問題に取り組むのも楽しかったそうです。'),
  ('e8527d14-3923-5b3b-95cd-5217f71db84f', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-25', '16:30:00', null, '通常 / スロット（自分でなんとなく細分化できるかな？ 前回使ったブロックの復習）', '「コスチューム」というキーワードが自分からでてきました。コスチュームを変えている最中の「〇秒待つ」もプログラムできました！スプライトを止めるプログラムも実際に遊んだものを思い出しつつ、プログラムできていました。 ＝の意味も説明しました。「コスチュームの番号が揃ったら」という発想はありましたが、プログラムするのが難しかったようです。前回使った調べるのブロックも忘れてしまっていたようです。 成功のメッセージを使いましたが、メッセージの意味もあまり覚えていないようです。はやとちりする場面もあり、少しもったいないなと思います。ゲームは完成しました。', null, 'タイピング: 時間は短かったですが、集中して取り組めていました！！
盛り上がり: 前半はよく集中して取り組めていました！'),
  ('a3e6f5d3-25e6-59fa-a4c9-c8e486f9a626', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-25', '17:30:00', null, '通常 / デジタル水族館の作成', '途中まで作成してあったため、魚を増やしたり、色を変えたりというアレンジを加えて完成させました。 さかなを追いかける人を作りたいとのことで、スプライトを一つ追加し、上下左右のキーで動かす手順を学習しました。かずとくんの作品を見て、マウスでも動かしてみたいとのことだったので、マウスの方へ動かすやり方も学びました。 音の編集をとても楽しそうにやっていました。', null, 'タイピング: キーボードの端のキーがまだあやふやなようでしたが、途中で教えたところ、s、a、lなどは打てるようになりました。
盛り上がり: スプライトをキーで動かす学習はまだ先の予定でしたが、かずとくんのやっているのを見て、自分もやる気になって、一生懸命作成していました。 お兄ちゃんに甘えにいくことも多いですが、それが自分の向上心につながっているところが良いと思われます。
備考: すっぱい飴を涙目で食べていて、その後いちごみるくをあわてて食べていました！'),
  ('c9000824-5078-5823-b39c-42ada0105f58', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-25', '17:30:00', null, '通常 / クイズ （リストの説明）', 'リストの作成方法と使い方を一通り共有した後に、計算問題を出題するプログラムを作ってもらいました。 質問と獲得したスコアを言うプログラムはスムーズに組み立てていました。出題の方法をランダムにしてほしいというリクエストも、変数と乱数を組み合わせてプログラムすることができていました。途中、正誤が正確に行われない問題に直面しましたが、試行錯誤して修正していました。 論理立てて考えるのは苦手ではないようです！完成しました！', null, 'タイピング: 集中して取り組めていました！！ミス率4％ととても低かったです！
盛り上がり: 90点近い得点で4級合格です！！'),
  ('34d6f28f-6738-577b-aa87-c9396583cfb9', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-25', '17:30:00', null, '通常 / だるまさんが転んだ(自分で細分化しながら)', 'チュートリアルを見ずに取り組んでもらいました。 あるくんの動かし方や、振り返る動作（コスチュームの変化に気づけた）をスムーズにプログラムすることができました。ゲームオーバーの表示の条件に困っていたので、実際のゲームを思い出してもらいながら条件に気づいてもらいました。前回勉強した乱数もしっかり覚えていました。もしを使うときに「ずっと」を忘れがちで残念でした。音楽をいろいろ試して、背景にあったゲームを作成できていたのでとても良かったです！ ゲームは完成しました！', null, 'タイピング: 集中して取り組めていました。ホームポジションをより意識していきたいです。
盛り上がり: 音楽を「ロボット化する」で遊んでいました！'),
  ('65fac795-a74d-5d85-a5e7-5841a9391888', '7d01236e-620e-5177-a6f4-af325a582aae', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-25', '17:30:00', null, '通常 / 物語の続き、サメから逃げろゲームの作成', 'サッカーボールを思い通りの軌跡に動かすことと、バウンドしたときに音を出すこと、ボールが地面に落ちたら背景を変えることで、「世界を創造しよう」の課題をクリアしました。ボールが思い通りにアニメーションのように動いたのが嬉しそうでした。 サメから逃げろのゲームでは、逃げやすいように矢印キーではなくマウスで操作するアレンジで作成しました。スプライトが四隅に逃げた時に安全地帯にならないよう、敵スプライトの角度をいろいろ試して調整していました。 「終わるまで音を鳴らす」のブロックの位置によっては、曲が終わるまで次の動作に進めないことを説明しました。', '追跡ゲーム', 'タイピング: それほど苦戦もせずに打てているのですが、ゲーム後半で集中力が切れるとキーボードを適当に打つことがあります。
盛り上がり: そうじくんもスプライトを動かすアレンジをしていたため、お互いに作成過程をのぞきあって、仲良く進めていました。 スプライトが意図した通りに動いたときはとても嬉しそうな顔を見せてくれます。 BGMなどの音楽を入れることも気に入ったようでした。'),
  ('ee029cdc-1be3-5271-a009-a296370021bb', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-25', '16:30:00', null, '通常 / 学習したコードの復習、探求', 'だるまさんがころんだの予定だったのを急遽変更しました。「チーズを探せ」は触ってみたことはあるけれどあまり覚えていないので、こちらをやってみたいとのことでした。 条件分岐を使った上下左右の移動はよく覚えていました。向きが少しあやしかったので、ブロックをクリックして出る矢印を確認しながら丁寧に設定していきました。 ゲームの素材を開いた瞬間、「迷路はスプライトなんだ！」と気づいていました。 迷路の壁にあたるということはどういうことか（スプライトに触れるということ）、触れたらどういう動きをすればいいのか、自分で説明ができていました。 チーズの動きは表示、隠す、どこかの場所をつかって自分なりに再現していました。 スプライトに触れ続けるとスコアが変わり続ける現象が起きることも覚えていて、1秒待つを入れて工夫していました。 しょうたくんの意向で、クリア画面を作成しました。', null, 'タイピング: Sランクが取れて喜んでいました。
盛り上がり: ゲームらしいゲームの作成で、とてもテンションが上がっていました。 こういう動きのときはどうするか、というのを、自分なりに考えて、しっかりと自分なりのプログラミングができていました！ チーズやクリア画面が思い通りに動作したときはとても嬉しそうでした。 お父さんにも得意そうに見せていました。'),
  ('1e3b649c-bf80-5204-95cb-cdcc35f32388', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-21', '18:40:00', null, '通常 / コードモンキーの変数に慣れる', 'テキストを打つのにだいぶ慣れてきたようで、用意されている入力ボタンもあまり使わず、自分ですばやく入力できていました。 変数の使い方もすぐに慣れたようです。 このようなループの課題にありがちなのですが、ループのせいで最後に不必要な動きが入るのが、あまり納得いかないようでした。 時間いっぱい集中して取り組めていました。', null, 'タイピング: いくつかのレベルを試していました。漢字仮名交じり文は、漢字変換するものとしないものが予想外だったりしてやりづらいとのこと、ローマ字の単語入力が一番やりやすく、コンクールに出るならこのレベルがよいとのこと。ここでは準1級を出せていました。
盛り上がり: 検定合格は嬉しそうでしたが、自由作成の項目の配点が0だったのは心残りなようでした。 コードモンキーは、キーを打つのが苦にならないタイプのせいか、意外と楽しんで、キャラクターの動きにツッコミを入れながらもきちんとマスターしながら進められています。'),
  ('b9a8ecf9-7f03-51d4-b685-4dd0641860e9', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-24', '18:40:00', null, '通常 / ジャンプゲームを応用に発展させよう', 'ジャンプの種類を発展させながら、ジャンプゲームを作りました。まず、等速ジャンプでは、教室ではジャンプのことをあまり触れていなかったが、家でいじっていたので、7割くらいはスムーズにつくていました。段差に乗る問題では悩んでいて手が止まっていたので、上の段差に乗るってことはあるくんがどうゆう状態であるかなどの思考のプロセスを助けなが、1人で作れました。放物ジャンプに移った時に、放物じゃんっぷの仕組みにを教えつつ、現実のじゃっぷに近づいていることを教えていたところ、マリオのジャンプみたいとたとえができていたので理解はできています。ただ、このジャンプで段差を乗りあがることは難航してしまった。 なので、次回は自然落下でじゃんっぷを付くて行こうと思う。', null, '盛り上がり: 検定の賞状に誇っていて、①，2級も取りたいそうです。'),
  ('3155d3e9-bd86-539d-9781-0754502c0a12', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-24', '17:30:00', null, '通常 / 復習も抑えながら、ピンポンゲームをやろう', '今までのゲームを少しずつ触れながらピンポンゲームを作りました。最初期にやっていたらしいので朧らかに記憶に残っていました。まず、ボールを向きを決めるところでは、スロットなどで乱数を触れたので、利用しました。角度の範囲が曖昧なところがあったがスムーズに作れました。少し気になったこととして、移動をするコードがあまり区別がついてないような気がします。後から違うとわかっても最初にどこかへ行くのコードを取っている気がします。バーの動かしのときも、マウスのx座標のブロックを使うことがわかっていたが、どの移動のコードにいればいいか判別がついていない気がしました。 反射の条件分岐のところでは、前のだるまさんが転んだのコードから参考にコードを作れていたので、理解はできていると思います。その後、スコアやゲームクリアオーバーは何の迷いもなく作れていました。ただ、変数の初期化の位置が並列でできているのでバグを起こしてしまうのが難点です。あとから気付いて一緒に直しましたが。 ゲーム自体は完成できました。', null, 'タイピング: スコアが伸びて喜んでいました。'),
  ('eb70f083-af08-5d6b-811e-98cb20600b16', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-24', '16:30:00', null, '通常 / リストの基礎を作ろう', 'リストの基礎を学ぶためにクイズを作りました。リストで初期化の全部消すの意味は溜まっていくことを体験しながら訪ねたので、すぐに気づけました。それに加えて、変数とリストの違いも共有してあげました。はるちゃんよりも作成スピードが速かったので、途中ブロックだけ提示さて自ら組むようにさせたところ、勘がいいので聞いてほしい質問が次々に来たので、随時「リストの長さ」はリストの中にある個数だよなどと上手く誘導しながら1人で作らせました。新しく番号の変数を使うことが気づけたりして、理解を持って進めていました。', null, 'タイピング: タイプ速度は遅いながらもミスタイプ0に収めることができました。
盛り上がり: ゲームを探し求めるがうまいなと思う'),
  ('49e1cf10-c81c-5dde-8489-cc65699cbba7', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-10-24', '17:30:00', null, '通常 / ピンポンゲームの作成', '難しいポイントは試行錯誤しながら作っていましたが、地力はあるようで、すらすらコードが書けているところが多かったです。スコア変数は初期化も忘れずにできていました。 ボールがパドルに当たった時に反射する動きを作る時は考え込んでいましたが、先週やった図形を描く動きと似ているよと伝えるとひらめいたようでした。5点獲得したらゲームを終了する部分では、「もし～」を使おうとしていましたが、それよりも簡単に書ける「～まで待つ」を新しく習得してもらいました。', null, 'タイピング: 今回含め毎回記録を伸ばしていてすごいです
盛り上がり: 最初のほうは静かでしたが、ゲームが完成してくると楽しそうにたくさん喋っていました'),
  ('4794f8f9-d2a1-58ed-9b4d-d2bd5ad96325', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-24', '16:30:00', null, '通常 / リストの基本を作ろう', 'まだ1度も使ったことがないリストの基礎を理解するために、クイズを作りました。まず、初期化のときにリストの全部消すがなぜ必要か考えさせたところ、リストの中に溜まり続けることをしっかりと把握できていました。それに加えて、変数とリストの違いを共有しておきました。チュートリアルの動画を丸々見せずとも使うブロックだけを提示して、それだけで組み立てることができました。回繰り返すのコードを使って複製せずに複数問クイズを出すコードを注文したところ、番号の変数の入れ場所に困惑していたので、画面とコードの進行を比較しながら一緒に考えながら作っていき、基本のところは完成しました。アレンジで正解数ごとに最後表示されるコメントが変わる仕組みができていて、変数の扱いも十分できていると思います。', null, 'タイピング: 徐々に調子を取り戻していきました
盛り上がり: 正解数を別のキャラクターに言わせているのがかわいかった。'),
  ('a76a8d1c-6899-52b7-8081-133ef5e1dd1b', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-21', '17:30:00', null, '通常 / 乱数を使ってみる', 'サイコロではいろいろな目を出す必要があること、それを乱数を使って作成できることは、すんなり理解したようでした。 サイコロがあっさりできてしまったので、もう少し乱数を使わせたいと思い、じゃんけんゲームを提案したところ「やってみてもいいよ」とのことだったので、対戦型じゃんけんゲームに挑戦しました。じゃんけんの場合は乱数が1～3の間の数になることも、きちんとわかっていました。 「最初はグー」を入れてみたいなど、とうきくんのアイディアも形にでき、じゃんけんの掛け声も録音して入れたりして満足できるゲームが仕上がったようでした。', null, 'タイピング: 赤い文字は右手、青い文字は左手で打つように勧めたところ、中段人差し指のキーはきれいに打てるようになっていました。
盛り上がり: サイコロもじゃんけんも、意外とノリノリでがんばって作成できていました！ ゲームの内容が想像しやすかったのか、使用するキーや「最初はグー」にするところなどのオリジナル部分にも積極的に意見を出してくれました。'),
  ('f95ef261-67cd-572d-94d1-53b234766361', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-21', '17:30:00', null, '通常 / 検定テストの復習', '今日は検定の結果発表と復習がメイン。 一番わからなかった箇所を一緒に読みながらコードを作成しました。 はるくんの特性として長く文章が続くと混乱してしまうようで、今回はそうした部分がごっそり抜けたせいで検定に合格できなかったというのが分かりました。 一緒にやってみると、「自分で理解する」ということはできていたので、今後は長く続くコードを書く練習をしてみるのもいいのかなと思います。', null, 'タイピング: 濁点のタイピングになると多少荒さが出てくるものの、はるくんの年齢にしてみればタイピングの速さはとても素晴らしい！と思います。'),
  ('1b6553b5-11ff-5cbd-b6e5-8da4ea71457d', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-10-21', '17:30:00', null, '通常 / 図形を描く', 'さらちゃんの学年の算数で同じ内容をやるので、頑張って理解してもらいました。最初は「～度回す」とするところを「～度に向ける」にしていたのですが、直線を書いて一定の角度回転させての繰り返しだと説明し、直してもらいました。また、何度回転させるのかというのを紙に図を描きながら一緒に考えると、自分で答えを出せました。六角形、円、星など色々描くことができました。', null, '盛り上がり: けいとくんの作っていた五輪を真似して似たようなのを描いていました'),
  ('5d1f8edc-4f0b-57a8-85cf-244795b70ec7', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-21', '16:30:00', null, '通常 / 背景スクロールのやり方の習得', 'とらくんと同様に、完成版を見せてから作成に入りました。 最初にどのスプライトをどの位置に置いたら良いのか、動かすためにはどうすればよいのか、動かすのを止める場所はどこか、そのためには何を指定すればよいのか、段階を踏んで問いかけていく形で進めましたが、基本的に素直で、質問に答える形で順調に作成を進めていました。背景スプライトを動かすことや、どこまで動かして、その後に何をすればよいのかなども、自分で思いつくことができていました。', '背景スプライトの１と2を3回繰り返した後に背景スプライト3にして終了したいのと、プレイヤーキャラクターが土の上でジャンプできるようにするのが次回の目標だそうです。', 'タイピング: なし
盛り上がり: とらくんと一緒の課題で、好きな単元だったためか、とても熱心にこちらの話を聞いて取り組んでいました。'),
  ('eb87327b-e033-5452-8545-323d796f3e30', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-21', '16:30:00', null, '通常 / 青木菜穂', '今日はどこが違ったのか？などを一緒に文章を読みながら、やってみました。 やはり読み飛ばしが多く、そのせいでちいさなミスが目立っていたように思います。 もったいない部分ではあるので、今日は優しさよりもすこし厳しめ（読み飛ばすのはダメだよ〜のノリではなく、すこしシャキンとさせるように）に伝えました。 ちょっとリレーションの部分が不安があったため、試しに洞窟でガイコツのゲームで、口頭問題でアレンジをしてもらおうと思い、ダイヤを掴んだら、ステージ２に遷移するというのをしてもらったのですが、どうしても文章の理解？がすんなり出来ず、とても悩んでいた様子でした。主語、動詞を逆に考えたり、すべてのコードを読みこの動作が、このコードという該当理解をしたくない（めんどくさい）感じがします。', '今後は、ある程度基本のアレンジを増やす方が良いように思います。新しいことをやるというよりかは、口頭で問題をだしつつ、コードを書く練習やそこからどんどんスプライトを増やしながらリレーションをきちんと使いこなすなどを、していったほうがいいのかなと・・', 'タイピング: タイピングに関してはとても良く出来ているので、自信をもって取り組んでいました。'),
  ('0ce470c3-d20d-54f2-ac9f-55cd9b9179fa', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-21', '16:30:00', null, '通常 / 背景スクロールのやり方の習得', '完成版を見せてから取り組みました。 前回のジャンプで変数を使ったのが印象に残っていたのか、やたらと変数を使いたがり、座標の指定など、あまり必要のないところを変数にしてブロックを増やし、途中で混乱する様子も見られました。 変数の他、必要ない条件分岐のブロックを持ってきて、僕はこれが使いたいからと条件ブロックの中を空欄にしておき、プログラムがうまく動かない場面もありました。 プログラムはなるべくシンプルな方が良いと勧めたものの、そのままでも実行できる箇所は直したくないようでした。 今日の内容は不完全に終わってしまいましたが、視点を変えると、前回のジャンプがよほど楽しく印象に残ったようにも思えました。', '背景のスクロールの完成と、プレイヤーキャラクターを作りたいとのことでした。', 'タイピング: なし
盛り上がり: オリジナルにこだわりすぎてたつきくんより全体的に遅れがちでしたが、前から作りたがっていたプラットフォーマー系のゲームに必須な内容だったため、とらくんなりに一生懸命考えて工夫しようとしていました。 背景が動いたときはとても嬉しそうでした。
備考: 検定合格は嬉しそうで、思ったよりも点数が良かったそうです。3級も受けてみたいとのことでした。'),
  ('a48d71fd-5366-5e4b-83e3-743d9d52aa07', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-10-21', '17:30:00', null, '通常 / 図形を描く', 'ペンで色々な図形を描きました。多角形の応用で円も描いてみて、オリンピックの五輪マークを作りました。けいとくんの学年にとっては難しい算数を使う内容ですが、1周が360度ということは知っていたりと部分的には仕組みを理解していました。ペンの太さや色などの設定を色々いじっていたので、ペンの使い方は慣れたと思います。', null, '盛り上がり: 五輪が完成したときテンションが特に上がってました'),
  ('df57cabd-629a-5249-9f2e-3dd975c213aa', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-10-21', '16:30:00', null, '通常 / 乱数の使い方を学ぶ', 'アルスパークのチュートリアルを見ながら、サイコロの目がランダムに出るように作りました。ここで乱数によってコスチュームを変えることを習得しました。そのあと、乱数を使って自分の過去の作品をアレンジしました。数字が入る場所なら基本的にどこでも乱数を使えることを伝えると、色や音、秒数など色々な要素をランダムに変えていました。 作業中、たまに本題から脱線しがちなところはあるかもしれません。', null, 'タイピング: 一種類のキーしか使わないものはすらすら打てますが、何種類かキーを使うものはまだ迷いながらという感じです。コツコツ頑張ってます。'),
  ('e3243fe5-7804-51cb-97e3-04515eac299f', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-20', '17:30:00', null, '通常 / リストの基礎を学ぼう', 'リストの基礎を学ぶためにクイズを作りました。コンテストで使ったこともあり、初期化で全部消すの意味を承太郎くんに知っているマウントを軽くとるように理解していました。その後の、複製を使わない複数問の作るコードは、変数や回繰り返すを使うヒントを与えましたが、悩んで止まってしまいました。コードの流れを見ながら、「次の問題に移る時、何を買えたらいい」と一緒に考えていき、承太郎くんの助言もありながら、完成しました。ゆきちゃんは、承太郎くんほどの理解のスピードはないが、本人のペースで1歩1歩進んでいけば、理解はできると思います。', null, 'タイピング: はやかったです
盛り上がり: ひさびさの承太郎くんとの作業で会話が弾んでいました。'),
  ('e2986eec-dce1-5ea9-8ce2-bd2df823f395', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-20', '17:30:00', null, '通常 / リストの基礎を覚えよう', 'リストの基礎を学ぶために、クイズを作りました。承太郎くんはリストは使ったことはなかったそうです。リストの全部消すを使う意味も、すぐに気づき、有無による違いも体験しました。そのご、順調に作っていき、複数問問題作るとき、複製でつなげるのではなく、繰り返すと変数を使って作ってみてと提案しました。少しは考えましたが、今ある知識で作り上げていました。回繰り返すのコードでリストの「リストの長さ」を使うことで、便利になることを共有できました。リストの長さはリストの中にはいっている個数を示していることも重要で使えるものであることも共有しました。 終わりのアレンジも検定で多く使った「と」もうまく活用できていました。', null, 'タイピング: いつも以上にお徳な金額になっていました。
盛り上がり: ひさびさのゆきちゃんとの共同で楽しくやっていました。'),
  ('b614693e-5378-5f58-a903-0e094e5c5f9e', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-10-20', '17:30:00', null, '通常 / 基本操作コースをもとに作品を作る', 'お手本のジャンプゲームと少し違うものにはなりましたが、「ジャンプで障害物をよける」、「よけていくとスコアが入る」、「障害物に当たるとゲームが終わる」などテキストに書いてある内容を満たしながら個性的なゲームを作っていました。障害物を斜めに動かしたり急に大きくしたりと工夫していました。', null, '盛り上がり: 自分の作ったゲームをみんなに遊んでもらったときは特に楽しそうでした！'),
  ('c0f6d5a6-e882-57e0-8ac7-2588d1cbff47', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-20', '16:30:00', null, '通常 / ジャンプゲームで座標で動かすことを習得する', 'ゲームをプレイしてから簡単な細分化をし、作成に入りました。 ジャンプの動きにはy座標を使うことはすぐに思いついていましたが、繰り返しを使用することはすぐに出てこなかったので、基本操作コース02「名前を動かそう」で大きさを少しずつ変えるときの動きを思い出すよう促しました。 跳びあがったあとに落ちてくる動きは、自分でしばらく考えた後、「マイナスを使う！」と思いつくことができました。 邪魔者の動きについては、テキストでは「○秒で座標を○○にする」を使用していますが、そうちゃんが「ジャンプはたての動きでyだったから、今度はxを使う」と言って、x座標を動かすのを横幅の分繰り返すことで作成していたため、そのまま続けさせました。 ひよこが邪魔者（りんご）に触れたら割れる動きは、すぐにコスチュームを使って作成できていました。スコアの変数も作成できました。', 'すぐにゲームオーバーにならないよう、どこをアレンジしたらよいかを考えてもらってゲームを完成させたいと思います。', 'タイピング: 使用するキーが全般にわたってきたせいか、少しクリアに苦労しているようでした。
盛り上がり: 最初のゲームをプレイしたときに、すぐにゲームオーバーになってしまったため、スプライトの大きさや動きの速さを一生懸命調整していました。 一度でも邪魔者に触れるとすぐにゲームオーバーになるのがイマイチだったようで、みずきくんやお母さんが遊べるレベルのゲームにしようと頑張っていました。'),
  ('f75a7ba3-886a-51cb-9fad-f47e863362da', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-20', '16:30:00', null, '通常 / ゲームの改造を通したスキルの習得（ブロック定義など）', '今日の課題に取り組む意義を説明してからゲームの完成編をプレイしてもらい、問題編の問いに取りかかりました。あっという間に完成させていました。 別のPCの完成編を参考に、写経してもらいました。ブロック定義は触ったころはあるけれど…という反応でしたが、この課題のブロック定義は使用している意味がわかりやすかったようで、定義の利用に納得がいくとのことでした。', null, 'タイピング: 問題なく取り組んでいました。
盛り上がり: 授業前に検定の合格を告げたせいもあるのか、比較的テンションも上がり気味で、楽しそうにしていました。 1級に挑戦する意欲もばっちりでした。 ブロック定義の使い道の他、「影」のスプライトの座標指定の仕方に興味を持っていました。'),
  ('8898f383-da7c-53d5-9b43-0e5f6ab05877', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-10-18', '17:30:00', null, '通常 / 小技を使ってみる', '今日は小技をやってみました。写経に近い形ではなりましたが、面白いものを作る経験ができたと思います。大きさを変えたり何秒か待ったりという基本的なブロックも使ったので少しずつ覚えてくれていると思います。まだ人見知りっぽくてあまり声は聞けていません。', null, 'タイピング: 頑張っていましたが、大文字と小文字の対応を覚えきれていなくて、打つときに迷うことが多かったです。
盛り上がり: 楽しそうにスタンプをぐるぐる押していました'),
  ('f0480869-ead5-5c72-b1bc-acfe1d45d8c3', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-18', '16:30:00', null, '通常 / だるまさんが転んだ コスチューム判定と向き判定の違い（プログラムに差がでることを学習！）', '前回の復習（～と聞いて待つ・答え）をしたのち、だるまさんが転んだに移りました。タイピングは苦手な様子でしたが、タイピング表をみつつ取り組んでいました。 今回はレッスンをみてやってもらいましたが、あまり内容が頭にはいっていない様子でした。こちらが確認したときの返事がかなりいい加減でした。うまくプログラムが動いていないときも、あまり積極的に欠陥を探そうとしていませんでした。こちらが問いかけるとそれに答えてくれましたし、再現したい事象を自分の言葉で答えることはできていました。 コスチューム判定から向き判定に切り替えるときも、そもそものプログラムの仕組みをあまり理解できていないため、プログラムの位置にかなり困っていました。本人が最終的に納得したかは微妙です。', null, 'タイピング: 集中して取り組んでいましたが、思ったより評価が伸びず、3分くらいで終了しました。
盛り上がり: どじょうを飼いだしたことを嬉しそうに報告してくれました。'),
  ('5e39de08-0234-56c6-b14c-ad6eef525bac', '7d01236e-620e-5177-a6f4-af325a582aae', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-10-18', '17:30:00', null, '通常 / アルスパークでストーリーを作る', '2人のキャラがサッカーをするお話を作っています。スプライトにしゃべらせる、どこかに行く、左右キーで動かすなどの基本スキルを身に着けてもらいました。自分から背景を変えたりスプライトを増やしたりということもしていました。まだ人見知りが続いているみたいで言葉が少なめでした。また、一時間集中し続けるのもまだ辛いようで、飴を何回かなめにいっていました。', '物語の続き', 'タイピング: 基本的な文字をスムーズに打てています
盛り上がり: 弟のそうじくんが何をしているか興味あるようでときどき見に行ってました'),
  ('b99c7c44-fcea-59cf-b844-af000dc65b0a', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-18', '17:30:00', null, '通常 / 4級の検定問題復習 図形の内角（ペンの使い方）（3角形、4角形、多角形、円）', '検定の復習はあまり乗り気ではなかったようですが、自分の欠点を見直すと効率よく復習できることを説明すると「やろっかな」と言ってくれました。プログラム自体に大きな間違えはなく、マイナスをいれるのを忘れていたようです。悔しい様子でした。 その後、図形を描きました。三角形・四角形は内角のことをよく理解してくれていたので、スラスラ進めることができていました。正八角形も、自分で計算をして正確にプログラムすることができていました。 円は難しく考えすぎていました。「正n角形のnを大きくしていくと円に近づく」ということを確認すると、うまくプログラムできていました。半径を大きくしてほしいというリクエストにも、丁寧に取り組んでくれました。 最後に、一般的な内角の和の求め方と対角線の本数の話をしました。', null, 'タイピング: ミス率も少なく、タイピング速度も速かったです。集中して取り組めていました。'),
  ('e62557db-1d76-53e2-9bcb-b8815b350636', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-18', '18:40:00', null, '通常 / コードモンキーをできるところまで進める', '２９ステージまでは順調に行っていたものの、最後の３０ステージでどのタイミングで何回繰り返すのか？がわからなくなってしまっていた様子でした（亀の甲羅に乗って、3回バナナを撮りに行くというのがどのタイミングで繰り返しなのか？ということ） この辺は、アルスパークでもそうですが繰り返しのコードがどの順番でくるかを理解していないと難しい部分ではあるので、あらたくんにとってそういう部分が苦手なのだなとおもいました。「コードの順番の理解」 最後鏡の中に歩く人の説明をしました。 この部分は今後学校でイラストなどをPCで作る場面が増えてくることも考えて取り入れました。レイヤーの理解というのが最初は難しいものの、あらたくんは絵で理解する部分はとてもできる子だと思うので、来週実際に作ってみたいと思います。', null, 'タイピング: いつもと同様に落ち着いてできていました。'),
  ('a0047b5e-2a5a-5877-b9df-c81c20ed5b18', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-18', '17:30:00', null, '通常 / ジャンプの自然落下をやりたい', 'ジャンプの自然落下をやりたかったのですが、先週の部分で自分のアレンジにすすみたい様子だったので、そのまま自分でやってもらいました。 以前よりも、「端についたら〜、当たったら〜という判定のコードってどこだっけ？、やった気がするんだよね」という言葉が出てきたり、ヒントを言えば、「あ、これだ！」という自分でコードを読んでこのコードを使うというのが増えています。 前回の何回繰り返してジャンプの部分は、きちんと変数を使って行うというのも説明できていたので、弦切三兄弟のなかでは一番コーディングを楽しんでいるような感じがしています。', null, 'タイピング: 指を置く位置、正確にタイピングしようとする姿勢がだんだん増えてきたと思います。 以前よりも乱暴にパソコンを使うこともしなくなったので、よかったです。'),
  ('f2e48024-8e21-54d7-82a1-e2560684dec9', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-18', '17:30:00', null, '通常 / 図形、鏡、ジャンプの中から選んで好きなものを学習してみる', 'やはり最初から乗り気ではない様子で、３つどれがやりたいかを確認した後に、鏡だけをやりたいと話したので、レイヤーの話を交えながら説明してみました。 ３つレイヤーがあるときにどれが後ろにくるのか、最前面にくるのかを理解はできているものの、実際にやってみると人の二人目の順番を間違えてしまうなど、集中力に欠けてしまう部分がありました。 その後、ゆきさんに少しバトンタッチして、図形をやってもらいました。 角度の問題なので、多少数学ができるのであれば簡単ですが、どうしてもイヤイヤやっている感があるためか、思考停止になってしまい、三角形を描くところでストップ。', null, 'タイピング: 少しお休みしていたためかタイピングスキルが多少下がってきている感じがします。もしかすると集中力と関係しているだけかもしれないので、最近の様子からすると仕方ないことなのかもしれません。'),
  ('4f62d2b4-9514-5ed3-a1de-272ffab381e9', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-17', '16:30:00', null, '振替え / 追跡ゲームで条件分岐、キーのイベントで左右に動かす、点数が一定の得点になったらクリアの画面を出す https://app.arspark.jp/projects/21211/editor', '条件分岐になるとずっとが入る入らないがどのタイミングでつけたらいいかなど、コードを読む力はとてもあります。いろいろなメッセージを使えるようになったのはいいのですが、コードが反応しないというバグが起こり、私自身もバグを最後探しきれずに終わりました。 もしかするとイベントの並立をしすぎているのが問題なのかな？とも思うのですが、来週はそこを再度一緒に確認したいと思います。', null, 'タイピング: たくやくんもまだローマ字タイピングが覚えきれていないためか、片手タイピングになっていました。まだ、教室にはいって日も浅いのでもう少し気長に待ってあげれば良いかなと思います。'),
  ('e7d823a8-aa39-5e13-b5bc-29723ecd4556', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-17', '16:30:00', null, '通常 / レースゲームのもし〜ならの使い方の確認&判定、変数の使い方ポイント以外でhttps://app.arspark.jp/projects/21216/editor', '３つのなかから好きなゲームを選んで作ってみる すろっと、だるまさん、レース レースがやってみたいとのことで、まずは条件分岐でキーをそうさすること、判定をやってもらいました→この辺はさんざんやってきたので、ヒロトくんはお得意です。 変数（順番）を考えるのがちょっとこの単元は難しいので、実際のマラソンなどに準えて、順番を考える＝レフリーがいてその人が変数の元になっていることを実際に理解しながら行いました。おそらく半分理解はしているものの、実際自分でコーディングするところまでになると不安が出てくるとは思いますが、実際に変数を使ってできるものが増えた楽しさはあったようです。', null, 'タイピング: だんだんとペースが慣れてきたのか、以前よりローマ字読みを覚えてタイピングができるようになってきました。まだまだ正確性と速さが一緒には比例はしていないものの、正確にタイピングしようとする、指の置き場所など正確にしようとする気持ちが表れていると思います。
盛り上がり: 自分ができるものが増えてきていると同時に、ずっと〜の使い方が意外に難しいと漏らしていたヒロトくん＝これってコードがちゃんと読めていないと言えないことばなので、とても素晴らしい成長だなと感じます！次回の検定には参加してもいいのでは？と思っています。'),
  ('9f14b5f0-7863-59a9-9d61-e2b16b633b20', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-17', '18:40:00', null, '通常 / スクラッチで図形を描こう', 'ペンの機能を使って図形を描く練習をしました。正三角形になると、やはり内角の60度を使ってミスっていました。そこで、絵にかいて鉛筆を使って向きがどのように動いているかシミュレーションで提示すると、ひらめいたようにコード作成に取り掛かり、正しいコードを作ることができました。その後の正六角形も作り最中は何度か失敗したが、自力で作れました。円については、発想の広がりスムーズにいき今日の中で1番素早くできたと思います。星もしっかり計算してできていました。最後に途中で失敗してできた幾何学模様に気に入っていたので、自由に作らせました。 ヒカル君はまだスクラッチの知識は少ないながらも、発想のつなげ方は上手にできていると思います。', null, 'タイピング: スコアが伸び始めてきました。
盛り上がり: 図形のできた時の驚き喜びの目がよかった。'),
  ('0e0e521b-e7fc-5ced-93ea-95170d939c2a', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-17', '18:40:00', null, '通常 / スクラッチで図形を描こう', 'ペンの機能を使って図形を描いていきました。ノーヒントで正方形を描かせたところ、座標を使って書いていたので回転と「歩動かす」を使って各ように提案したところ、少し悩みました。だが、時間はかかって自走で作り上げたが、「繰り返し」を使わずコードが長くなったできていました。そのあと、ヒカル君とできたものを見比べ、繰り返しのコードを使ってあるのも見て、「そうゆう風にも書けるね」と認知はさせました。正三角形になった時、上手く行かなったが、コツコツと少しずつ数字をずらしながら、適切な角度を見つけていました。完成したコードも最初と同様に長くなっていました。 無理に繰り返しコードを1個1個動作を大切に作っていく大貴君の考え方はそれはそれでいいと思います。回転角の決め方は小4で深くは理解できていなかったが、この考え方でうまくいかされていると思います。円は上の成果でずっとと回転を小さくすることを認知できていたのでよかったです。 最後は好きな感じに幾何学模様を作って楽しく追われました。', null, 'タイピング: ミスが減って喜んでいました
盛り上がり: 奇麗にできた時に驚きの目は良かったです'),
  ('97922b2b-4105-5e82-96bd-5d41493955c6', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-17', '16:30:00', null, '通常 / スクラッチで図形を描こう', 'ペンの機能を使って図形を描きました。最初ノーヒントで正方形を描くことをしたら、「度向ける」を使って各方向に向かせてから作っていました。そこで、頂点ごとに曲がっている方向は同じだよねということを確認してから少し悩んだが、繰り返す」を使って作ることができました。正三角形を作る時、流れで内角の60度を使ってミスっていました。その後、悩んでいたので、ペンを使って分かりやすく向きがどう変化したか確認し、図形を描いて回転する角度は直線から内角の角度を引いた角度だよ確認しました。そのあとの6角形同様に考えられていてよかったです。円を描くときも、多角形は正三角形と正方形でコードに何が変わったかを触れさせ、多角形で数が大きくなるほど、円に近づくことを一緒に考えました。 はるちゃんは、図形に関する質問をしたところ、少々時間がかかって答えていたので、図形はあまり得意ではなさそうです。 星を描く際に、曲がる際にどこを見ればよいが再確認させたため、スムーズにできました。', null, 'タイピング: 久々でスコアが点数が下がってしまいました'),
  ('8cc8bf18-4bab-5844-a6a2-dfd332f0d3c4', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-10-17', '17:30:00', null, '通常 / だるまさんがころんだの作成を続ける', 'しゅうくんはだるまさんがころんだの鬼が後ろを振り返るときに向きを-90度に変えていましたが、コスチュームで変えた方が効率よいということを伝え、それに沿ったコードに変えてもらいました。ただそれに伴ってバグが出てしまい今日は直し切れませんでした。また、不必要にスクリプトの数を増やしてしまう癖があるので、できるかぎりまとめたほうがバグりにくいし他の人が見たときに読みやすいよという話をしました。', 'だるまさんがころんだのバグつぶしから始める', 'タイピング: ベストスコアのタイ記録を出せました
盛り上がり: たまにやる気をなくすときもありますが、基本的に作品を作ろうという意欲は高いです！'),
  ('569c0c67-d8f2-5f27-a2cb-b134995b12d4', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-17', '17:30:00', null, '通常 / スクラッチで図形を描こう', 'スクラッチを使って図形を作りました。まず、ペンの使い方がわからなかったので軽く遊ぶ程度に使ったところ、「この角度星がかけるよ」と言いながらもう星を作っていました。なんか動画を見たらしいです。ほかの人の人にペンを使ったヒントも上げることなく、「回繰り返す」を使ってスムーズに作り上げていきました。正方形から正三角形の変わった時に回転を60度とすることなく最初から120度でやり、外角で曲がればいいと理解していました。円もスムーズにできました。 時間が余ったので、ペンを使ってガーンの背景描写を写経でやろうとしました。だが、変数とかムズか良しいコードなどがあったのか背景に書くことで無理やり作っていました。おうすけくんは知っている範囲で工夫を凝らして上手く描写するのが得意だと思います。', null, 'タイピング: ミスを減らすことができました
盛り上がり: boketeの大喜利動画が最近のブームぽい'),
  ('ed96744a-1afd-52ca-b138-713633e68ed0', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-15', null, null, '通常 / 追跡ゲームの完成、演算式、～まで待つの使い方', 'なぜ演算式の〇=〇を使用するのか不思議そうにしていたので、算数の話をし、=の左と右は同じという意味だということを説明したら納得したようで、演算式を完成させることができました。 「～まで待つ」を使うときには「ずっと」がいらないことにも不思議そうにしていたので、「ずっと」を使う条件分岐との違いの例を紹介しました。とりあえずは納得したようですが、何度か使い分けをしてみるとよいかもしれません。 勝利の音楽にこだわって、熱心に探していました。 一つのゲームが完成したことが嬉しそうでした。 15分ほど時間が余ったのでゲームをしたがったのですが、クローンを使ったシューティングゲームを始めたところでコードを見ることを勧めたら、素直に中をチェックして、敵HPを200にし、クリアするまで根気よくプレイしていました。', null, '時間帯: その他
タイピング: かわべの竹林第二話に一生懸命取り組んでいました。タイピングは速くはないですが、正しい指使いでとても丁寧に打てています。
盛り上がり: 運動会で疲れていたにもかかわらず、休憩も拒否して熱心に作成していました。 ゲームが形になっていくのが楽しそうでした。'),
  ('5ab5a350-f4f4-535f-bcb2-8bc9962aa0e9', '80660755-d846-5cdd-91a4-0ab78fe29034', null, null, '2022-10-15', null, null, '休み', null, null, '時間帯: その他'),
  ('bc2574d4-5b02-55c5-aa3c-9f6ead3668be', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-15', null, null, '通常 / 「コード探求スロットマシーン」 コスチュームの活用、メッセージの送受信、コスチューム#の活用等', '細分化はよくできていますが、ゲームの細かい仕様（左から順番でないとスロットを止められない）などは気づかなかったようでした。ゲームを少し触ってパッと把握できる分、ツッコミというか探求が甘いところもあるかもしれません。Scratchに対する慣れで、目の付け所も変わってくると思われるので、いろいろなタイプの作品に触れさせていきたいところです。 コスチュームでスロットの動きをさせているのは思いつかなかったようで、感心していました。（一つ一つの数字のスプライトをメッセージの送受信で切り替えていると予想したようです。） 一つ目の数字が確定したメッセージを受け取ったら、次の数字は「もし～キーが押されたならスクリプトを止める」、そうでなければコスチュームを変え続けるというコードを作成していて、数字の動きがおかしくなったと考えこんでいました。数字が動き出すタイミングに着目し、「緑の旗が押されたとき」「メッセージを受け取った時」を使い分け、コードを並列に書くこと、「～まで待つ」のブロックの使い方の説明をしました。 3桁そろったときのあたりを作るところは、「メッセージを使う」こととそのタイミングのヒント、「スプライトのコスチューム#」を使うというヒントを与えたら、自力で作成できました。', null, '時間帯: その他
タイピング: 最上位のランキングに入っていました。タイピングコンクールのお勧めをしたところ、とても乗り気で嬉しそうにしていました。
盛り上がり: タイピングのコンクールやプログラミング検定の話に食いついてきていました。連続で受験というのも苦にならず、やってみたい！という感じでした！ 何を勉強しているのか、何のためにこのコードを学んでいるのかを理解していると、より飲み込みが早く、食いつきも良いようです。多少理屈っぽくなってしまっても、そのあたりを説明することによって、とても熱心に取り組んでくれました。
備考: タイピングコンクールの練習予定'),
  ('2eb195bf-6736-5ea2-b15d-6cb5a5bc924d', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-14', '17:30:00', null, '通常 / かけ算（「～と聞く」と乱数・変数の使い方の確認）', '正解と答えが一致するときを考えるとき、「スコアが〇点になったら～」を参考に説明したらわかりやすかったようです。「もし～」ではなく、「もし～～でなければ～」を使うようにアドバイスしました。 〇と×を表示するためにメッセージを使おうというアイデアが自分ででてきて素晴らしかったです！表示のタイミングと同様に、質問のプログラムの進み具合も自分で考えて「〇秒待つ」をプログラムできていました！！ 今回はとても楽しかったようです！最後に作品をお母さんに見せていました！ 次回は、点数を入れてゲームとして整えていく予定です。タイマー方式はあまりしたくないようです。', null, '盛り上がり: 掛け算の仕組みができたところで、「これで自動計算機作れたよ！！」という話をしたら、とても嬉しそうでした'),
  ('4bae1a22-e3dc-5803-b1e1-702483059049', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-14', '18:40:00', null, '通常 / テキストベースのプログラムに挑戦！', '初めて取り組みました。英語の入力もとても速く、スラスラと進みました。 「〇回繰り返す」のようなコードの使い方が少し難しかったようですが、スキルよりかは考え方にポイントがあることを説明しました。 こちらがヒントを教えることなく、レベル30まで終えました。 最後に時間が余ったので、中級ものぞいてみました。かなり難易度も上がって難しそうでした。本人も少しびっくりした様子でした。', null, 'タイピング: 楽しく取り組めていました！集中力がすばらしいです！'),
  ('4fa0b90b-c0b8-5ff2-85f4-3cf45f110861', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-14', '17:30:00', null, '通常 / ジャンプの２種類の違いを確認する&変数の使い方を学ぶ', '回数を繰り返し＋変数ジャンプは、何も言わないでもできているので、左右の動きも同じように変数を使う→もし〜キーが押されたらのコードに変えながらやってもらいました。 自然落下のジャンプの方は、一旦コードを見てもらう→写してみてどうしてそうなるのか？を説明してもらうことにしました。（最初のコードの方が自分でできているので） 自然落下の方は繰り返しのコードを使わないでという意味なので、落ちてくる部分がどうして、あのコードになるのか？が半分理解できたような感じではありましたが、覚えるのは難しいじゃんと言っていたので、虎くんと同じようにバックアップに保存し今後のゲームに使おうとしていました。', null, 'タイピング: なし
盛り上がり: 今日は検定後だったのですこし、ゲームを多めにしてみました。やはりテストが難しかったようで多少落ち込んではいましたが、ジャンプのやり方を学べてある程度持ち直した感じかなと思いました。'),
  ('3411d53b-e1d4-514b-9839-5e40a9742679', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-14', '16:30:00', null, '通常 / ジャンプのコードを覚える→変数のやり方、回数でジャンプ、自然落下で', '今日は２種類のジャンプの種類をやりました。ただその前に変数を使うことで、簡単に数字を変えられること、変数の使うルールを覚えてもらいました。 その上で、ジャンプのコードが２種類あることを考えました。 おそらく、1個目の回数繰り返しジャンプ＋変数の方は理解はできたと思うのですが、自然落下の方はざっくり理解したという様子です。 また、左右に動きながらジャンプするのコードを書こうとする時に、並立してコードを書かないと動かないということを学び、今後の自分の作品に役立てたいと意欲をしめしていました。', null, 'タイピング: なし
盛り上がり: ２種類目のジャンプは覚えられないと言っていたので、バックアップに入れて今後使おうと楽しみにしていたようすなので、どこかのタイミングで使えることがあればいいなぁと思います。'),
  ('768056b1-5ac9-5a07-9272-e3bd2796e0de', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-14', '17:30:00', null, '通常 / アイスクリームを取りに行く→自分でアレンジする（敵がどんな動きになってほしいのか？アイスクリームを受け取った後にどんな動きになってほしいのかなど）', '今日はアイスクリームを取りに行くをアレンジにチャレンジ。 キーのイベントで動かす→もし〜キーがおされたら動くにコードを変更、また新しく変数のを使って点数を増やすなどを追加で教えました。 今までやっているコードを自体はとても覚えていると思いますし、「これはなんだっけ？、どうするんだっけ？」と聞くとちゃんと言葉で説明できるようになってきました。 来週あたり、もう少しやれることを増やす メッセージ、もし〜なら、点数を回数をこなして、違うゲームが作れるようになるといいなと思います。', null, 'タイピング: まだキーボードの位置が画面を見ながらタイプするというのが慣れていないようで、大まかにキーを押している感じ。周りのけいとくんなどに言われて、画面をちゃんと見ればタイピングできるよと聞いてからは、真剣に画面を見るようになりましたがそれでも大文字と小文字の違いがあるためなかなかタイピングするのは難しい様子。 本当は小文字表示であるといいんだけどなぁとは思います。
盛り上がり: 自分で考えられるのと、やりたいことが繋がってきている感じがします。'),
  ('e0a83d52-1f61-58ce-989e-acfbaf8f60d8', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-14', '16:30:00', null, '通常 / 教室の使い方の把握、細分化', '体験会で作成した追跡ゲームや洞窟ダイヤのアレンジを家でも何度かやっていたとのことで、基本操作コースの表を見て、やったことのない操作はないと言っていました。 試しに単元の内容を使って「名前を動かそう」を作成させましたが、問題なくできていました。 お話作成とゲーム作成のどちらがよいかで、「チーズを探せ」を選びました。 ゲームをプレイして細分化をしましたが、「ネズミのスプライトが虫のスプライトに触れたらすべてを止める」「ネズミのスプライトがチーズに触れたらチーズがどこかの場所に移動する」「ネズミが迷路のスプライトに触れたら反対の方向に戻る」など、ブロックの用語で丁寧に答えることができていました。', '邪魔者バージョンの敵の動きから続き予定', 'タイピング: 自分で5エリアのおらが峠まで進んでいるそうです。 キーの位置は大体把握できているようでしたが、長い単語になると時間切れになって先に進めないとのことでした。
盛り上がり: Scratchで作成するのが楽しくて仕方ない！という感じでした。名前を動かそうで、一つ一つの座標を指定するときなどは「これって意外と大変だよね～」と言いつつも、面倒がらずに細かく作成していて、スプライトをきれいにそろえるために、全部のy座標をあとからそろえてみるといった地道な作業も集中してやっていました。
備考: レゴで作った車とプログラムを見せてくれました。レゴはWeDoで作成していたそうですが、Scratchの追加機能でレゴがあることを自分で見つけ、Scratchでプログラムをかいているそうです。'),
  ('8d1a94b3-d60a-5ae2-84d3-9f8631b321f0', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2022-10-13', '17:30:00', null, '休み', null, null, null),
  ('bd946481-67e7-59b8-9a71-37bae97dcfc3', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, null, '2022-10-13', '16:30:00', null, '休み', null, null, '備考: 9/30振替済み'),
  ('ee1abefd-ecc3-514f-8688-acba41be6d6b', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-10-08', null, null, '通常 / 教室に慣れる、現状のスキルチェック', 'いくつか指示をしたコードを作成してもらって、基本的なことはできそうだったので、ピンポンゲームに取り組んでもらいました。 ゲームで遊んでから細分化シートを書かせ、それをもとに作成しました。 さすがに中学生だけあって、細分化シートの記述からコード作成までもスムーズでした。単純な形のスプライトを使用したゲームだったせいか、スプライトは既存のものを探すのではなく、すべて自作してました。 バーでボールを跳ね返すところは、自力で角度を変えるところまでを作成していたので、乱数を使ってみるよう課題を出しました。乱数は初めてのことでしたが、すぐに理解できていました。 上記のコードは、角度によっては問題なかったのですが、入射角が浅いとバーからすぐに跳ね返らなくなる現象が起きたため、その理由をコードを見ながら一緒に考えました。 繰り返しのコードが待ち時間なく実行されているため、ボールが回転してもすぐに「触れた」判定になって、そこが延々と繰り返されていることを、誘導尋問のようにして気づかせ、それを解決するために、繰り返しの中に「〇歩動かす」「〇秒待つ」のコードが必要なことを一緒に考えていったところ、納得がいったのかしきりと感心していました。 変数や「まで待つ」などは、問題なく理解できていました。', null, '時間帯: その他
タイピング: タイピングはそこそこ得意とのことで、あえて練習をしたいという感じではなかったですが、月に一度くらいは実力チェックをしてみようということでP検タイピングに取り組んでもらいました。準2級相当の結果を出せていました。
盛り上がり: 簡単なゲームではあるものの、座標や角度とコードの微妙なタイミングなどを駆使するプログラムだったせいか、やりがいをもって取り組めていたようでした。 コードの順序や構成の意味が納得できると、スッキリするようでした。
備考: ゆくゆくは検定やコードモンキーのお勧めもありかと。'),
  ('b06ac6ee-496d-5f9a-984a-270c5409bea8', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-10-13', '17:30:00', null, '通常 / オリジナルゲームの作成', 'ビルが爆破されて驚くキャラクターたちのストーリーを作っていました。秒数を使ってキャラクターを動かしたり、コスチュームを自分で書いたりしていました。自分の想像したとおりのストーリーをプログラムで再現できていたと思います。', null, '盛り上がり: いつにも増してハイテンションでした！'),
  ('ce1602fa-7523-5030-aecb-8eaf146fc944', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-13', '17:30:00', null, '通常 / ジャンプゲームをすすめよう', '先週に続いてジャンプゲームを作成していきました。木の上に乗りたいと作り始め、色判定だけっだったらうまくいかなかったところ、座標も判定条件に入れて、上に乗るコードができていました。そこから、重力も対応できるようになっていて気から自然に落ちる動き作れていました。自分でエラーを見つけ出して、改良できる能力が備わっていて、更なるに美を感じます。色版の基準はあいまいだから厳しめにした方がいいよとかアドバイスなども素直に取り入れてくれて、自惚れず耳が広くていいです。背景のスクロールもできたので、来週でゲームが完成しそうです。', null, 'タイピング: 正答率が2倍になったそうです
盛り上がり: 背景は細かくこだわりたい派だそうです。'),
  ('8bd89873-a496-524d-b2aa-53075d0bd5a5', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-10-13', '17:30:00', null, '通常 / プログラミングでいろいろな図形を描く', '難しい算数の内容が絡んできましたが、これからの学校の授業でも同じようなことをやるということで頑張りました。正方形を描くプログラムは動画に沿って完成させ、そのあと応用として三角形、六角形、円(に近い多角形)、星型、ひし形も描くことができました。直線を書いた後に角度を何度回すかというのが難しい所でしたが、図を紙に描いて考え方を共有したら理解したようで、最後は自分で考えることができていました。', null, 'タイピング: 寿司打のゲームの結果として2000円以上得することができました。
盛り上がり: いつもやらない寿司打をやっているときは楽しそうでした'),
  ('8086ac37-2bc6-53ff-b8b3-b99029173e70', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-13', '17:30:00', null, '通常 / ジャンプゲームを木の上に乗ろう', '最初に今まで作ったジャンプゲーム類を振り返りしました。今回は放物ジャンプで木の上に乗ることを目標にしました。まず、過去の作品を見ながら作ってみてと頼んでみましたが、「色の触れたら」とかの近しいブロックは持ってこれたが、木の上に乗ることができませんでした。「木の上で止まるとはどのコードを進ませなければいい」と誘導していって、木に触れた時に「まで繰り返す」のループの抜け方や色判定の位置を誘導していって取り組みました。やっている最中はストレスをためる場面はあったが、やり終えた時の嬉しさは吹っ切れたものでした。', '今日作ったものからアレンジを作れたいいかな', 'タイピング: 集中してできていました'),
  ('6507b45d-e7a2-5159-ae4c-c359272f94fa', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-13', '16:30:00', null, '通常 / コードの細分化に慣れる', 'スロットマシーンを事前にプレイしてもらったところ、とても盛り上がって遊んでいました。 こちらから聴きとる形で細分化シートを埋めていきました。その際に着目する視点を最初に教えたところ、似たような箇所は自分で文章にできるようになりました。 （例:数字のスプライトが動く速さの違いや止めるためのキーの違いなど） 細分化シートを一生懸命に見ながら作成していました。今日はそうちゃんが把握した通りに作ってもらったため、メッセージは使用せず、すべてのスプライトを個々に数字キーでストップされるところまで作成しました。', 'スロットマシーンの数字を順番にとめる仕様にアップデート', 'タイピング: しばらく家でやっていなかったそうで、大文字と小文字が一致しなくなっている文字がありました。特に「Ｉ」と「l」の混同が見られ、クリアできないステージがあって悔しがっていました。
盛り上がり: 今までやったことのないゲームだったため、とても興味をもって取り組んでくれました。 数字を変えるためにコスチュームが必要だということも、すぐに気づいていました。 できたスロットマシーンをみずきくんとお母さんにプレイしてもらって、得意そうでした！みずきくんにとても丁寧にプレイの仕方を教えていました。'),
  ('0187e4c8-6459-5c7e-b2e3-9dc88021f13c', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-08', null, null, '通常 / 教室の使い方の把握、基本的なブロックの使い方', 'ストーリーを作成するのはとても楽しそうで、覚えたメッセージの送受信、座標を指定しての移動、最前面と最背面の指定を駆使して作品を作り込んでいました。', null, '時間帯: その他
盛り上がり: 考えたストーリーを形にできるのがとても嬉しそうでした。 座標やメッセージはよく使いこなせています。'),
  ('bbd7b026-1941-551d-abf9-d62ac7bed1b3', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-11', '17:30:00', null, '通常 / 先週のおさらい', 'お兄ちゃんのとなりで動きの練習をしてもらいました。覚えている範囲がまだ少ないので最初はお兄ちゃんの真似をしながら動きがどれぐらいできるかを積み重ねしていくのがいいのかなと思います。 一応今回は大きくなるなどのコードをやりましたが、来週も同じようなことを行ってもいいかな？ゲームをひとまずやりながらキーを使うことの大切さなどを実体験した方が、いいかなとも思っています。', null, 'タイピング: レベル１で頑張っていました。'),
  ('91569515-a9d3-5bd8-96f8-841f77d492f8', '7d01236e-620e-5177-a6f4-af325a582aae', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-11', '17:30:00', null, '通常 / 先週やっていたことのおさらい→キーで変化させる&大きさを変更する&音を追加する', '緊張していたためか、言葉数少なめで、先週のおさらいもちょっとうる覚えな感じでした。 最初に色々おさらいしてから、キーでコスチューム、大きさを変化させること、最初に100%にしないと初期設定から始まらないを伝えてみました。 その後、アルスパークで魚が自動で泳ぐというチュートリアルを見せながら、動きの再度おさらい→ずっと、何歩動く、端にあったったらなどをやってもらいました。', null, 'タイピング: レベル３まで進み、順調にタイピングにも慣れてきている様子でした。
盛り上がり: キーを変えると、コスチュームが変化するなどできる範囲が広がってくるととても楽しそうにしていたので、もう少し緊張が解けてきたら、作りたい作品に向けて使えるコードを増やしていきたいとおもます。'),
  ('f27db22c-d22b-5c77-97a6-e0c50702b0cf', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-11', '17:30:00', null, '通常 / ピンポン復習（回転・動き・演算子）', '一度作ったことがあったので、ゲーム本編はスラスラできていました。最初にボールのプログラムから作り始めたのも、とても良かったです。 最初に得点によって、ゲームオーバーとクリアの表示をしてくれました。こちらから、得点によって演出を5通りに分けるようにお願いしました。＞、＜と「かつ」を使って、工夫してプログラムしてくれました。演算子で表現している数字には、その値が含まれていないことを説明しました。プログラム自体は完成しましたが、最後に別のプログラム方法（もし～ではないなら～を使うもの）も紹介しました。 ＞,＜はまだうまく使えていない部分はあります。数をこなす必要があると感じました。', null, 'タイピング: 集中して取り組めていました！
盛り上がり: 前回より少し落ち着きがなかったです！残念！！'),
  ('57a0fec7-095f-5197-8abc-b2abae5cf8e2', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-11', '17:30:00', null, '通常 / 座標ドリル 【47、48、49】 →→ 乱数と座標の組み合わせ', '初めてドリルに取り組みました。 47：自分でしっかり文章を読んで取り組めていました！ 48：よくできていました！ 49：初期位置はヒントを読んで自分で取り組むことができていました。こちらから問うと、「下にいったとき」というのも自分で言葉にできていました。最後に上に戻るというのも、適切な場所にプログラムできていました。 ただどれも自分でしっかりと考えるというよりかは、試してみてたまたまうまくいった側面も大きい感じでした。こちらから問いかけると手を動かしていましたが、自分だけでは手が止まっていました。 最後に乱数と座標を使って、ランダムな場所に移動させることについて説明しました。', null, 'タイピング: あまり乗り気ではなかったのですが、しっかり取り組んでくれました！'),
  ('40150c30-7cad-5fb4-9da9-0e4485ac65e5', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-11', '16:30:00', null, '振替え / 2級検定問題（シルバー級第11回） 答え合わせから！', '家に持ち帰ったものの、最後まで終わっていなかった（半分ほど取り組んでいた）ようなので、20分ほど時間を渡して取り組んでもらいました。新しいものをやるのも提案しましたが、本人が最後までやりたかったようなので！ 20分しっかり集中して取り組めていました。4箇所ほど、思い込みで「ずっと」をいれてしまっていましたが、その他のプログラムはばっちりでした。かなり悔しがっていました。アレンジも、ゲーム内容に沿ったもので素晴らしかったです。 残った時間で、また違う検定問題（第12回）に取り組んでくれました。取り組んだ部分に関しては全てできていました！', null, 'タイピング: 真剣に取り組んでいました。
盛り上がり: 寿司うちにはまっているようです。'),
  ('8c263842-30de-593a-afd6-ab8a77b424c9', 'b2246586-4496-52f9-a825-be2488a00a31', null, '4ba9d68b-4972-5a0e-a883-4a9311c1acdc', '2022-10-11', '17:30:00', null, '振替え / たのしむ', '教室に来て一番初めに見せてくれたゲームは、窓が割れたり、人が現れたり、とてもうまくできていました！ 乱数を使おうとしていたけど、敵とプレイヤーのプログラムが混乱してしまったようです。。「ランダムな攻撃の仕方を作るために、メッセージを使うことを提案しました。メッセージの使い方は覚えていたようですが、乱数をいれる場所が分からなくなってしまい、創作が終わってしまったようです。 ゲームの仕組みが破綻していたのかもしれません。途中まではトライできていました。', null, null),
  ('4a92e747-5639-5e63-b09e-98a17ad32af1', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-11', '16:30:00', null, '通常 / クイズ問題を作る、演算の要素も少しいれながら、答えというコードをどう使うのか？など', '最初に、自分の名前を入れて演算のりんごとばななを組み合わせると答えをいれたら自分の名前を返してくれるなどの見本を見せた後に、チュートリアルでクイズ問題を作ってもらいました。 問題のタイピングを行うのが大変そうでしたが、タイピングの良い練習になった感じがします。当たりとはずれで音を追加し、あたり・はずれと言うというコードの順番の後にしたほうがいいと考えてくれていました。', null, 'タイピング: 中段をうまく使いこなそうと頑張っていました
盛り上がり: 長いタイピングをしたのが初めてだったのか？自分で打てたことにとても満足していた様子でした。'),
  ('08edc20e-202e-5ef2-bd19-dcee06ca77b8', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-11', '16:30:00', null, '通常 / 問題を聞いて待つ&答えがあっていたら、あたりという条件分岐まで', 'クイズの問題と答えを作成するのがとても苦労していた様子ですが、クイズが出来上がった時に自分でできたという達成感があったような感じでした。アレンジをしていいよと話した際に動きをつくってでもいいし、音でもいいよと伝え、見本も見せましたが周りに引っ張られる感覚があります。隣のしょうたくんがやってたコードを使っていたので、周り流されず自分ができるものをやってほしいかなと思います。', null, 'タイピング: 中段をやることにとても苦労している様子でした、もう少しローマ字のタイピングに慣れていかないとと思うので、しばらくぽけでびで様子見かと思います。
盛り上がり: 自分で問題を作成できた達成感があったようです！'),
  ('0bcb0a45-1527-5a2a-8d90-169f36e38bda', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-03', '16:30:00', null, '通常 / チーズを探せをやってみる→色の判定、スプライトの判定、どう当たったらネズミが跳ね返るのが違うのかを検証し、理解する、またチーズが出る範囲を座標の乱数を使うとどのように表示されるのか？を理解する', '左右上下のキーでネズミが移動する、乱数を使ってチーズをいろいろな場所に表示させるは、自分でもすぐに書けることができています。 ここで新しく、もし〜当たったら〜の部分ですが、色で判定するのと、スプライトで判定するのではかなりネズミの跳ね返りが違うこと、また数字もどのくらい跳ね返る時に大きくするのか？を実践して理解した様子でした。 また再度となりますが座標の乱数をつかうこととは、どういうことになるのか？を座標のチャートを見て確認し、自分で今後ゲームを作る際の材料にしてもらったと思います。', null, 'タイピング: 少しずつタイピングに慣れてきている様子、ただまだローマ字打ちが覚えきれていないため、ひらがなのタイピングになるとチャート表が必要になります。'),
  ('91449883-b5ee-5a68-bafe-3d0463152b24', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-07', '17:30:00', null, '通常 / 検定４級 応用問題 １７', '「メッセージを送る」はできるものの、「受け取る」ことを忘れてしまう様子。 ちゃんと文章を読むことでそこは解消されると思います。また問題文に書かれてないコードを使うこともあるため、文章を読む正確さが彼女には求められると思います。 ただ解答合わせをした際に、自分でもちゃんと文章を読むことを理解しているので、使うコードをきちんと確認していけば、４級は合格すると思います。', '今後メッセージをの受け取り、マウスポインターが触れたらなど、コードのタブを変えるものを少しずつ増やしていった方がいいかなと思いました。', 'タイピング: なし'),
  ('41a463f5-e5b2-52fb-8fb4-c1fd52961607', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-03', '17:30:00', null, '通常 / 変数の使い方に慣れよう→アンカー・フラグのように使って一気に数を変えるやり方を覚える', '歩数を変数でフラグにして変更させるというのをやってみました。（何歩にして、何歩にしtて〜と言ってめんどくさいという気持ちを持たせて、変数を使うとそこが一気に変わるよと伝えました）途中、本当に嫌がってしまったかな？と思いましたが、えにしくんが成長したこともあり、変数をうまく使ってくれ歩数分動くというコードを書いてくれました。 今後変数のフラグの部分では今回のところを見返して思い出してほしいと思います。', null, 'タイピング: しばらくレベル２で推移していますが、それでも一生懸命にタイピングをしていました。 ただ彼の場合はぽけでびのアイテムの方に重要度が向いている→それでも以前よりもチャートを見なくてもひらがなを打てるようになったので、遊びながらでもタイピングになれてくれたらOKかなと
盛り上がり: 自分でここをこうしたい、このコードを書きたいという意欲が増えてきたように思います。1ヶ月ほど会ってませんでしたが、会わない間にとても理解度が増し、自分でもコードを読んでいるということをよく理解していると思います。'),
  ('4282c8e6-8e00-569b-97ce-1f44f2155d19', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-08', null, null, '通常 / 追跡ゲーム', 'まだどの動きで、このコードを使うなどの自信はないものの、コードを作ってみると熱中しやっていたので、少しずつコードを覚えていくのが今は優先かなと思います。', null, '時間帯: その他
タイピング: タイピングは、まだキーの場所が確定していないので、少しずつaはどこにあるなどの練習が必要かなと感じました。
盛り上がり: 自分のこうかな？と思ったことがまだ、聞けないものの、多分そうだなと思っていることはあるみたい（向きがこうなったほうがいい）でもちゃんとゲームが動いたのを見た時の目のキラキラした感じは、ゲームを作るのが好きなんだと感じました。'),
  ('3964b551-47f2-5621-aaf8-b6b148cc4089', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-08', null, null, '振替え / 検定の過去問をずっとやっていたので、今日はネズミがチーズを追いかける、迷路ゲームを自分でどこまでできるか？をやってもらいました。', '細分化で自分で書くのが嫌のなので、まずこちらからお題をだして ・ネズミが動いて跳ね返る ・チーズがランダムに出現する ・敵が動く この３つだけ先に作ってみようと話し、やってもらいました。 ネズミの動きに関してはは上下左右に動くことに関しては問題ないものの、やはり色で分別する方が当たった判定しやすい？と思っていたためか、バグに繋がることに疑問を持っていました、また数字をどれぐらいマイナスすれば跳ね返ったように見えるのか？が知らなかったみたいなので、そこは「このぐらいの数にすると跳ね返った感じに見えるよ」と伝えたら、納得していました。 心配な部分としては、自分のやりたいことに傾倒しやすい→やってねと言ったこと自体を忘れてゲームの面白さを追求してしまうこと。いい点ではありものの、時間通りに終わらない原因でもあるので、今後は1個ずつお題を与えて次、次とやってもらう方がいいのかな？', null, '時間帯: その他
タイピング: タイピングが嫌だと言うので今日はスキップ
盛り上がり: ゲームを難しくすることは本当に素晴らしい！ただそこに熱中しすぎることで本来の目的を忘れてしまいがち。'),
  ('1517c2ab-b6a4-5314-b0ec-e4e0087f20e3', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-07', '17:30:00', null, '通常 / 座標・回転の復習', '前回やったことあるとのことでしたが、「あまり覚えていないかも」とのことだったので取り組んでもらいました。 角度がまだ苦手なようです。「〇度にする」と「〇度回転する」の違いがまだはっきりしないしないようです。ゲームオーバーのプログラムで「無理ゲー」を作ってしまったことに気が付いてくれました。「歩いている最中に振り替えるとダメ」ということは分かっていたようですが、プログラムは分からなかったようなので「かつ」を紹介しました。 座標は大丈夫そうですが、回転はあまり得意ではないようです。ゲーム自体は完成しました。', null, 'タイピング: 集中して取り組めていました！すごい！！！'),
  ('c287c612-08e8-521a-8682-895ca05c09db', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-07', '18:40:00', null, '通常 / コードを読んでプログラムする', '検定対策は大丈夫とのことだったので、ゲームをプレイしてから3つのミッション取り組みました。 どう取り組めばいいのか分からないようだったので、矢のプログラムにとくに注目するようにアドバイスしました。 コスチュームでコントロールしていることには自分で気が付けていました。最終的には見本と違うものができましたが、「次のコスチューム」ではなく「〇〇コスチュームにする」のブロックを使ってくれていたので良かったです。 最後にまゆねこを使って、クローンの説明をしました。本体と子分の説明をして、子分の方が動くということを説明しました。なんとなく分かってくれたようです。', null, 'タイピング: とても集中して取り組めていました！！かなりお得でした！とても楽しかったようです！
盛り上がり: 時間が余ったので寿司うちに取り組みました。かなりはまっているようです。学校で本気は出さないそうです。'),
  ('1eb57f2f-0b8b-52d7-b7af-4f2489becbe1', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-07', '16:30:00', null, '通常 / スプライトに触れた時のコードの理解', 'アイスを食べたらすべてが止まる仕様になっていたため、次のステージ作りを提案したところ、とても乗り気になってくれました。「次のステージの進む」というゲーム性があるところが気に入ったようでした。 「スプライトに触れた時」「背景が変わった時」の使い分けや、スプライトの動きを止めるブロックの使いどころなどを、色々と自分で検証しながら作成することができていました。', 'アイスを食べには完成したので、次の課題に進められます。', 'タイピング: ミスも少なく、よくできています。
盛り上がり: 何度かとらくんのところの様子を見に行ったり、たくやくんの作成画面をのぞきにいったりもしましたが、ゲームを面白くしようという意欲が最後まで見られました。 思い通りに動かなかったときも、回答をほしがるのではなく、どのスプライトをチェックするか、どういう動きをしているところをチェックするか、などのヒントだけで、自分で考えることができていました。'),
  ('44f2b8f3-af46-5305-bdf3-873fbd115cfa', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-07', '17:30:00', null, '通常 / ４級テスト過去問 応用15', '本人が前半からゲームに熱中してしまい、テスト自体をやることを拒む。ただ今回は心を鬼にして「やる約束」というのを明確にしながら、問題の途中まで一緒に文章を読み、後半からは本人だけでやってもらいました。 文章を読むのが嫌い＆順番がどこのコードの中に入るのか？が理解できないものの（たぶん慣れの問題もある）自分で半分はできるようになってきました。 本番50%ができることを目標に、コード自体を「簡単」というのであれば言葉で理解がどこまでできるか？をテストで感じてほしいと思います。', null, 'タイピング: なし'),
  ('2c5a8c4c-cbbb-539d-a713-1472824e9ffc', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-07', '17:30:00', null, '通常 / ４級の応用問題 15', '猫の足もとが動かない（コスチュームの動き）があったものの、それ以外は概ねできていました。本番用のテストとは違い使うコードの指定がないものの、それでも文章をちゃんと読んで確認作業もしてくれていたので、当日は問題はないかなと思っています。 答え合わせをした際に、本人も自信がついてきたようで、帰り際は満足げに帰って行きました。', null, 'タイピング: なし'),
  ('914b17d7-f3a6-59e6-84f8-806861b4d8f5', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-07', '17:30:00', null, '通常 / ４級テストの最後の過去問試験', '多少コスチュームの指定間違いがあったものの、言葉を読み解く力がだいぶつき、問題特有の難解な言い回しにも惑わされずにほぼ正解しました！またアレンジ自体も正確に動くようにもできるようになっているのが素晴らしいと思いました。', null, 'タイピング: なし
盛り上がり: 自分でできることに自信も持っているし、ちゃんと見直しもできていて本番に向けても心配はないかなと思います'),
  ('d4656daa-00b8-504d-8539-132299fb0943', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-07', '17:30:00', null, '通常 / シューティングゲームのコインのVERで同じようにできるか？ ＞＞変数の復習も兼ねてhttps://app.arspark.jp/contents/18473', '途中まで動画を見ながらやってもらい、わからない箇所は一緒にビデオを見ながらやってみました。作成中、変数（スコア）をつけるのはどうしたらいいの？と聞いてくれて、先週やっていたことを覚えていてくれたみたいです！これはやったなという記憶が続いてくれているのはとても嬉しい！ 本人の集中力もかなり伸びているので、今後は少しずつでもチュートリアルのもので写経のような感じでもいいからゲームをたくさん作るのに触れるのをしていくのがいいのかなと思いました。', '＊ロンのPC', 'タイピング: 中段のキーボードFGHJはなんとなく覚えてきている様子。タイピングの速さもまぁまぁ速くなってきているので少しずつアルファベットの理解が進んできていると思います。 まだ日本語を打つことはできないものの、数字などはキーボードでも打とうとしてくれているので、4月よりはかなり進歩したかと！！'),
  ('5a5b0e78-696c-5cc7-8cc3-9bbd4b8103d9', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-07', '16:30:00', null, '通常 / リレーションを深める→ゲームで当たったら、メッセージを送って〜を学ぶ', '概ね自分の力で考えて前回やっていたことをおぼぼえている様子でした。 あたらしく条件分岐で触れたらメッセージをお送るというので、そこから動きを作るというのをしてみて、見た目を変えることをしたりおしゃべりするというコードを使っていました。', null, 'タイピング: 全てのレベルが終わりました。おおよそタイピングのスピードが安定しているので、今後はこどもタイピングに進んでも大丈夫かなと思っています。'),
  ('27008cb3-3079-5bbd-b285-8da12629c611', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-10-03', '18:40:00', null, '振替え / 検定の3回目をやって定着させる', 'レッスン最中は、真剣にとりくみきちんとコードをかけていました。途中動きには問題ないものの、１問だけ書かれた文章とは違うコードを書いていましたが、ほぼ受験に関しては問題ないと思っています。', '次回は、もう一度検定を行うかコードモンキーを行うかどちらかです。', 'タイピング: なし'),
  ('cac70086-6f18-5c1b-8e18-d5985c3e0c13', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-09-30', '17:30:00', null, '通常 / 変数：得点を追加するの紹介', 'シューティングゲームを作ってみようで、比較的自分で嬉しそうにしていました。 お母さんにも終わった後にとても喜んで紹介していたので、ゲームっぽいものを今後も作成するのでいいかなと思います。', null, 'タイピング: なし'),
  ('d987f96a-c211-5b38-8493-dc7b4610ea0b', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-06', '17:30:00', null, '通常 / 教室に慣れる、Scratch習得度の確認', 'Scratch歴は4年あるとのことで、名前を動かそうを使いながらブロックの知識について確認しました。座標、変数、乱数、メッセージ、条件分岐等、問題がなさそうでした。 ジャンプを作るのは得意とのことだったので、【prg】初級ジャンプゲームを見せ、コードを全部削除して、新規にゲームを作ってもらいました。ジャンプは慣れているようで、変数と2つのコードを使ってスムーズなジャンプを作成できていました。 背景はいつもクローンで作成しているとのことなので、まずはシンプルなものを作ってみてほしいと要望を出してみました。このようなときに、自分のやり方に固執せずに、素直にこちらの方針で作成しようとしてくれるところは助かります。', '木を真上から踏んだらOKという判定をしたいとのことで、これを完成させる予定です。', 'タイピング: 学校でもよくやっているようで問題なくできていましたが、学校では単語の早打ちがはやっているようで、あまり文章は打っていないとのことでした。
盛り上がり: 自由なアレンジをさせても、こちらが問題を提示しても、いずれも楽しそうに取り組んでくれました。1時間があっという間だったそうです。
備考: 学校ではiPad、家のパソコンはMacだそうで、Windowsのキーに少しとまどうところがありましたが、教えるとすぐに覚えていました。'),
  ('a8f0b2fd-0d5c-5bda-a686-f724ddc9dad4', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-10-06', '17:30:00', null, '通常 / 検定練習', '練習問題を解き終わって見直しをすると、「隠す」のブロックを入れる位置が違っていました。問題文を読むときに、「もし～なら」や「ずっと～」の中に入れるコードを一つのまとまりとして見てもらうことでこういったミスは減らせると思います。そのほかの場所はよくできていました。苦手な問題が来てしまうと試験時間内にアレンジをする時間があまりなくなってしまうかもしれませんが、色や音を変えるなどでさくっと作れれば大丈夫そうです。', null, '盛り上がり: 途中で間違いに気づいて最初からやり直していましたが、あきらめずに完成させました！'),
  ('dc7bc2b4-f655-5b4d-addd-571a417c5ca9', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-06', '17:30:00', null, '通常 / 下迫田', '2級の検定練習を2問続けてやりました。1つ目のロケットの問題は、演算式で作る条件の部分は迷うことなく作れていました。回答に支障はないが、不等号の条件式の作り方としてなるべく対象の変数を左辺において作るように確認しました。 2つ目のじゃんけんの問題は、1つ目で集中力が切れたか、じゃんけんの勝利条件の組み合わせに迷っていました。もし1分考えてわからないところがあったなら、次の問題進むようにアドバイスをしてあげました。集中力が切れて、最後の方に「ずっと」と「回繰り返す」の読み間違えはあったが、全体的には解けていた。 両者ともに２，３ミスで検定に落ちるほどには支障なくできていたと思う。', null, 'タイピング: 検定練習のため
盛り上がり: わからなくても最後まであきらめない姿勢は良かったです'),
  ('4bbd9922-c2b2-5bcb-b764-8157683a00c5', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-06', '16:30:00', null, '通常 / 音楽をスクラッチで作ることを楽しむ', 'ピアノを3年以上習っているとのことで、嬉しそうに演奏していました。 音楽に合わせて上手にクジラピアノを演奏してから、音設定の作成をしていました。 鍵盤を弾くときにスプライトが動いてしまうのを解決したいといって、途中までデフォルトの座標を設定したり、台座が背面にいくように設定したりと工夫をしていました。', null, 'タイピング: すべての文字に慣れてきています！
盛り上がり: 座標の設定で時間切れになってしまいましたが、楽しそうに楽器や音の設定をしていました！同じ音でオクターブ音程を変えてみたりして楽しんでいました♪
備考: ピアノは3歳から結構本格的にやっているようで、ドイツ音名を答えてくれたり、聴音をしている話をしてくれたりと、色々話してくれました。'),
  ('26ead416-70fe-5a4b-9000-86b5e2265a24', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-04', '17:30:00', null, '通常 / 教室に慣れる', 'まだ人見知り中なのか、ほとんど言葉は発してくれませんでしたが、徐々にこちらが話しかけた時にうなずいたり笑ったりしてくれるようになりました。 テキストにはまったく乗り気でなかったので、アルスパークで目を留めていた「楽器で遊ぼう」をプレイし、同じようなものを作ることから始めました。 「このスプライトが押されたとき」「音を鳴らす」のパターンを数個作成したところで、お兄ちゃんの「回転」が目に入り、あっという間に作成したスプライトを全部削除して、かずとくんの真似をしながら「繰り返し」と「回す」コードを学習しました。 何かを作っては、すぐに全部消して新しいものにしたがる傾向があります。おもちゃを片付ける感覚なのか、作成したものが残っていることが嫌なようです。できたものは保存して、新しく作成しなおす方向に誘導したいところです。 録音の真似をしたがりましたが、自分で声を出すのは恥ずかしいようで、何度もかずとくんに無言でお願いしていました。それでも、録音した声の加工などはとても面白がって、このあたりでようやく笑い声を聞くことができました。。。 かずとくんと同じく、ショートコントのような作品を作りたがったため、「表示」「かくす」を教えてみたところ、作品らしくなって満足そうにしていました。', null, 'タイピング: なし
盛り上がり: 作品ができたときは、満足したのか嬉しそうにしていて、何度も再生して自分の作品に見入っていました。'),
  ('072325c5-38db-5c34-ac9d-ea3a0c832ecd', '7d01236e-620e-5177-a6f4-af325a582aae', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-04', '17:30:00', null, '通常 / 教室に慣れる、アルスパークの使い方に慣れる', 'Scratchの忍者ゲームがしたくて気もそぞろで、学習に入るまでに少し時間を要しました。 自分の名前のアルファベットを入れることにはまったく興味を示さなかったため、好きなスプライトや背景を選ばせてモチベーションを保たせながら進めましたが、テキストの順序通りには進められませんでした。 興味を持ったこと、本人が面白いと思ったことはとても熱心に取り組みます。回転と繰り返しの併用や録音した音の使用、座標でスプライトを動かすことなどは、とても面白がって、何度も熱心に作りなおしていました。 忍者ゲームのようなものを自分で作りたいという目標があるようで、そのためにはスプライトでいろいろな動きを作れるようにならないと、と説明をしたところ、テキストを進めることに乗り気になってくれました。', '「ゲームを作りたい」という意思がとても強いので、先に追跡ゲームなどをやってもよいかもしれません。', 'タイピング: やったことがあるそうで、指使いにも気をつけて打てていました。
盛り上がり: スプライトを座標で動かしたり録音した音を活用したりすることがとても楽しかったようで、最終的に、ショートコントのような作品を作って満足そうにしていました。
備考: 忍者ゲーム 「忍者遊戯」https://scratch.mit.edu/projects/224624124/'),
  ('24f4a9ae-610e-5074-87ae-54c055a6ab34', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-10-04', '16:30:00', null, '通常 / 繰り返しの位置や対象に留意して思い通りのリズムのコードを作成する', '最初は自分で考えることが面倒だったようで、解説動画の冒頭の通りにすべてのブロックを並べていました。本人がどうしても動画の通りにやってみたいというので、一度好きにやらせてみてから、同じブロックを探させて「少ないブロックでやってみよう」というミッションを与えてみました。繰り返しの使いどころに気付いてからは、休符の位置などもよく考えて作成することができていました。 アレンジがなかなか思い浮かばなかったようなので、マリオのスタートの音楽を作成して見せたところ、ものすごい集中力で写経していました。 こちらがひたすらブロックを並べて作成したものから、繰り返しブロックを使えるところを探して改造してもらい、最初のフレーズを完成させることができていました。', null, 'タイピング: 順調に進んでいます！
盛り上がり: レッスン動画やこちらの提示した作品の、ある意味面倒な写経を嫌がらずにやりきったことに驚かされました！ 黙々と長い作業をするよりも、考えることの方が面倒なようですが、作業していくうちに本人なりの気づきもあるのがメリットかと思われます。'),
  ('fb9dc54e-7453-5c71-a0a0-3b0d3b3e503b', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-04', '17:30:00', null, '通常 / ピンポン復習（回転・進む・跳ね返り） 最後にアレンジ', '最初にパドルの動きを作りました。ヒントとして「マウスのx座標」を紹介しました。その後、自分で考えてパドルの動きを再現できていたのでとても良かったです。 ピンポン玉の動きをプログラムするのに時間がかかりました。複雑に考えすぎていたようです。猫の歩く動作を思い出してもらいました。 パドルで回転するプログラムはすぐにできました。見本をみて「回転している」ということに気が付けていてとても良かったです。スコアのプログラムもよくできていました。 勝利のメッセージを出すときに「10点になったら」というプログラムが難しかったようです。演算子のブロックと変数のブロックの組み合わせについて説明しました。ゲームは完成です。 アレンジとしてピンポン玉の初期位置を設定していました！', null, 'タイピング: ミス率1%未満でした！すごい！'),
  ('6b345a38-7d2e-5931-a62e-d3ec459572d7', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-04', '17:30:00', null, '通常 / 検定問題4級（応用問題・第17回目） パターンに対応できるように！', 'シンプルを意識してプログラムしてくれました。1箇所、プログラムする順番を間違えていました。悩んだ末の間違いだったようです。よく文章を読み、指示通りにプログラムするようにアドバイスしました。やり直したら、気が付いてくれたので良かったです。アレンジもとても簡潔にできていました。 その後、オリジナルのサッカーゲームを作りました。ボールをけるときの動作として、ゴルフゲームが参考になりそうだったので紹介しました。', null, 'タイピング: 集中して取り組めていました！ミス率0％!!すごい！
盛り上がり: 1時間集中して取り組めていました！'),
  ('c2d94ce1-af48-5655-8b59-517e4d91d71f', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-04', '16:30:00', null, '通常 / 337拍子（音楽 新機能）', '「〇回繰り返す」を確認しました。同じ音を繰り返すことはスラスラできていましたが、「〇回繰り返す」の中に「〇回繰り返す」をプログラムするのは少し違和感があったようです。すぐには思いつかないようでした。音は自分でいろいろ試していましたが、あまり興味はない印象でした。 その後、音に合わせてスプライトが旗をふるようにアレンジを加えました。ツールの使い方について説明しながら一緒に作成しました。 音楽よりも見た目の変更に興味のある様子でした！', null, 'タイピング: ホームポジション意識してできています！'),
  ('dd8fe3b1-8b40-5447-8a47-99aa9a28d38b', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-03', '18:40:00', null, '通常 / 跳ね返りと乱数の使い方を学ぼう', '最初に「チーズを探せ」を遊んでもらい、口頭で各スプライトの動きをしっかりと答えることができました。ネズミを動きを作る際に、向きの概念が曖昧だったので図を使ってもう1度確認しました。そして、ネズミの跳ね返りは少し自分で考えたそうだったので、考えさせると、「ー歩動かす」をヒントなして見つけ出せ、マイナスの方が大きくなることは自ら発見できました。「どこかへいく」と乱数の座標移動の違いも自ら説明できたし、色判定とスプライト判定の違いの良さも一部気づけていました。 最後に、虫の動きをコード見ながら確認してゲームは完成しました。', null, 'タイピング: スピードは速くなっていました
盛り上がり: えにし君が遊んでいるゲーム少し夢中になっていました。'),
  ('c74132ad-af25-50ee-9089-729c28bfb741', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-03', '17:30:00', null, '通常 / 検定の練習', '4級の検定の練習をしました、最初に、なほさんにだれないように矯正したが、やはり少し途中でだれてしまいました。内容としては１文の読み飛ばしと難しく考えすぎて違うコードになったくらいで、アレンジも程よく加えられてできていました。集中力の途切れやすさは気になるが検定は安心して受けられると思います。', null, '盛り上がり: 車は赤の方がいいらしい'),
  ('2da2de9f-6183-51b1-bf11-658663d1cf4d', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-10-03', '18:40:00', null, '通常 / 検定練習', '前回練習問題をやったときはバグの原因が見つかりませんでしたが、一行ずつコードを確認することでだいきくん自身が入力ミスを見つけることができました。今回の問題は25分ほどで解き終わりましたが、先生と一緒に見直しをする意味を理解できずにごねてしまいました。最終的に、プログラマーとしてゲームを作ろうとしたときに他の人と一緒にチェックするのは必要だということで納得してもらえました。見直すと、動きには関係ないものの余計なコードがついていました。動きが問題なくてもコードが間違っていることがあるということをわかってもらえたと思います。', null, '盛り上がり: 楽しそうにコードを書き進めていました'),
  ('390a1a7d-b8f4-55ce-a909-f7fd9f854a70', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-10-03', '16:30:00', null, '通常 / 検定の練習をしよう', '3級の検定の練習をしました。検定の練習は間が空いたので、前回解いたものを復習をおこない、旗を押されたときの読み飛ばしをしないように注意しました。検定をやっていくと、初期準備に不備があったにもかかわらず、正常通りの動きが作れていて、良かったです。１つ秒数の変化がなかっただけで他は間違っていなかったです。安心して検定を受けられると思います。', null, 'タイピング: スコア着実によくなっています'),
  ('a25e25f4-06ec-5ec8-a486-4d692cc4a3d6', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-03', null, null, '通常 / 検定2級問題演習', '前回うまくいかなかった理由をおさらいしてから、今日の問題に挑戦してもらいました！ 3か所ほどうまくいっていない部分がありました。 ひとつめは、文章は理解できていてプログラムが思いつかなかったようです。文章の意味をもう一度読み直して大小関係をひとつずつプログラムするように伝えました！ もうふたつは、文章を読み飛ばしてしまって、プログラムする順番を間違えてしまっていたようです。もう一度文章を読み直して復習しました。 他の部分はバッチリできていました。条件分岐や変数のプログラムもひとつずつ丁寧に取り組めていて良かったです！アレンジは時間の都合上できませんでした。', null, '時間帯: その他'),
  ('22a87795-2318-5c70-8a52-6e98648e4d4c', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-10-03', '17:30:00', null, '通常 / スロット→だるまさん（演算） コスチュームでコントロール・乱数の使い方', '見た目と動きのスクリプト分けた方がプログラムが見やすくなることをアドバイスしました。 乱数は前につかったことがあるみたいです。「タイミングをランダムにしたい」とのことだったので少し声をかけたら思い出してくれました。 アルごんが振り向くプログラムは、コスチュームの変化ではなく向きを変えてプログラムしてくれました。アルごんにプログラムするのか、アルくんにプログラムするのかを議論できました。スロットを復習して、「調べる」のブロックと演算の＝ブロックをうまく組み合わせることが出来ていました。アレンジにも楽しそうに取り組めていました！ まだプログラムの内容が難しくなると、ブロックにある言葉で説明する難易度が上がるようです。', null, 'タイピング: 集中して取り組めていました！！
盛り上がり: 1時間しっかり集中して取り組めていたので良かったです！！'),
  ('96d954a4-7aef-59b7-a8df-b901834c166c', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-09-30', '16:30:00', null, '通常 / 物語を作る', '物語は途中までできていたので続きをやりました。テキストに書いてあることとして、スプライトを押したときに色を変えたり、録音した音を使ったりしました。アレンジとして、猫や熊が走っているときに足をバタバタさせました。そのときに「～秒ごとにコスチュームを変える」コードを習得しました。', null, 'タイピング: まだ慣れていないキーもあるみたいですが、集中してやっていました。
盛り上がり: ちゃんとしたストーリーを組み立てられていました。'),
  ('ce9a5c5a-566a-55f4-b018-8cf6341c350c', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-30', '17:30:00', null, '通常 / 検定準備', '初めての検定問題への取り組みで、問題文の読み込みに少し苦戦しているようでした。 時間内での完成は難しかったようで、アレンジも含めて最終的に10分ほどオーバーしていました。', null, 'タイピング: 久しぶりに今月のタイピングをやっていました。最後まで続けられるようにはなりましたが、間があいたせいか、いつもよりゆっくりめのペースでした。
盛り上がり: いつもより疲れは見えましたが、40分間、問題文と取り組めたのはさらちゃんの成長だと思われます。
備考: 八王子親子プログラミング大会の抽選でロボタミが当たったそうです！'),
  ('9030f136-9621-53d4-94c8-49773411d391', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-30', '17:30:00', null, '通常 / 検定準備', '問題文とブロックの関連はそこそこできているのですが、数問解くと飽きるのか、ゲームを実行して適当に遊び始めてしまいます。その後、どこまでやったのかわからなくなるのか、問題文を飛ばして次の枠の問題にいってしまうことが多々ありました。 一文の中に複数の課題があるのが苦手なようで、読み飛ばしが多いです。一文ずつ問いかけるとできるのですが…。 問題文の最初に「旗が押されたとき」「①の続き」など、どこにコード作成をするかのヒントがあることを伝えたところ、そこは注意できるようになったようでした。', 'もう少し問題に慣れる必要があるかと思われます。', 'タイピング: 今日はタイピングの気分だったのか、50分ごろまでやっていました。
盛り上がり: 調子よく解いているときは、楽しそうではありました。'),
  ('c2a16acf-a290-58cc-afc8-7722d738297a', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-09-30', '17:30:00', null, '通常 / 迷路ゲーム：ねずみの動きをスムーズにする', '最初にだるまさんがころんだを行ってから、座標で動かすやり方を学んでもらいました→スムーズな動きにした方がゲーム性としてよくなるので。 そこから、再度ねずみの迷路に戻り、座標を使いならが動きをやり直ししました。 途中迷路に当たった時に跳ね返るという考え方がどうしても色で判定してしまうと突き抜けてしまうバグにつまずいていました（ここで何回かに一回だからいいか！という妥協になっていたので、そこをもう少し深掘りしてバグをちゃんと潰すことに意識を注ぎました）', null, 'タイピング: なし
盛り上がり: 自分でコードを考える力がついてきて、「ここをこうしたらこうなる」→予測する力もついてきたように思います。'),
  ('7f9fea99-4629-5c56-bc2a-bf072adfa10b', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-30', '17:30:00', null, '振替え / 選抜大会への作品提出', 'アルスパークからのファイル保存の方法、sb3ファイルのzip圧縮を教えました。', null, '盛り上がり: 作品提出が終わってほっとしたようでした！'),
  ('aa8166a3-10a7-5c4a-af77-c951c2e86b67', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-30', null, null, '振替え / 選抜大会への作品提出', 'ファイルのzip圧縮の方法を教えました。 応募フォームの入力を一緒に確認後、提出しました。', null, '時間帯: その他'),
  ('fac59eb6-8d01-5868-8d77-b0feb70e4bb0', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-09-30', '16:30:00', null, '通常 / 検定４級 サメから逃げる', '今日は検定４級の過去問を行いました。 概ね問題の理解はでき、文章の通りに問題を解くことができました。ただし自分が使いきれていないブロック（クローン）を使おうとするので、そのあたりで動きが固まったり、問題の通り解答できなくなってしまったりするのが、あります。 バグになりやすいので減点にもつながるかなと思いました。', '４級の過去問、もう一度行う', 'タイピング: なし'),
  ('085d3a71-36e3-5191-a680-03b341a3fabd', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-09-30', '16:30:00', null, '通常 / 検定過去問 サメから逃げる', '今日は検定４級の過去問を行いました。 概ね問題の理解はでき、文章の通りに問題を解くことができました。ただし、文章を読み飛ばす癖があるのでそこを潰せば大丈夫かなと思います。', '次回は検定もう一度過去問を行って本番に備えていきたいと思います。', 'タイピング: なし'),
  ('f1353313-3679-5c68-b7c9-5aa1fa8897b4', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-30', '16:30:00', null, '通常 / 迷路ゲームを通して座標を利用した動きの復習など', '最初だけチュートリアルを見ましたが、アルくんを矢印キーで動かすところができたら、あとはゲームの内容を思い出しながら自分でどんどん作成をしていました。 アルくんが道からはみ出たらスタート地点に戻らせたり、敵キャラの邪魔をする味方キャラを作ったり、ゲームバランスを考えて動きの速さや待ち時間を設定したりと、かなり熱心にゲームの構成を考えて作成することができていました。 色に触れたら、というブロックを新規にマスターしました。', null, 'タイピング: 5分間集中力を持たせてがんばりました！
盛り上がり: とらのすけくんが検定準備をしていたせいか、久しぶりに自分の作業に集中して50分間頑張ることができました！ 自分が思う動きをさせるために、どのスプライトにコードを書いたら簡潔に済むかなども考慮して、作成ができていました。'),
  ('45ce4080-ad8c-5a5c-aa2b-d008ec2976d2', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-09-26', '18:40:00', null, '通常 / 検定の練習をしよう', '2級の検定の練習でロケットのクイズゲームをやりました。やり終えた時の手ごたえはあまり自信がなかったそうです。一緒に確認をしていくうちに、多かったミスはみどりの「〇と〇」が使えてなかったことと「まで繰り返す」と「もし」が混同していました。「〇と〇」は変数の丸いブロックも使えるから普段使い慣れてなかったからしっかり確認しておくように言いました。2つ目は問題文の最初に「まで繰り返す」が多く出てきたことで、迷ってしまったといっていました。基本、○○のときは「もし」が多く使われることがあるので、助言しておきました。ほかに、入力した回答が答えと一致したときの文は、コードでは数式でなっていたから文の簡潔さからつくりだすのも難しいといっていました。 全体で25点の減点くらいでした。', null, 'タイピング: 正答率が前より上がっていました。'),
  ('ae41510d-b886-5d4c-96f6-df20e13dd553', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-09-26', '18:40:00', null, '通常 / 検定練習', '途中までは問題なく進めていましたが、魚のy座標がずっとランダムに変わり続けるバグがあって時間内に直りませんでした。あとでゆき先生が検証したところ"-240"のマイナスが抜けていたことが分かりました。試験中にバグが起こったら自分一人で直さないといけないので、その練習が必要かもしれません。', null, 'タイピング: 集中していました'),
  ('6e5838f2-0158-5afb-8a0a-339a1c67cd3a', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-09-26', '17:30:00', null, '通常 / 検定練習', '前回のポイントの振り返りをしてから今日の練習問題を解きました。前回で慣れたのか、時間を10分ほど残してアレンジまで終わることができました。答え合わせをしたところ、動作には関係ないものの、コードの順番が入れ替わっているところがありました。それ以外のところは、前回ミスした場所を含めてすべて完璧でした。「動きが同じなら順番違ってもいいじゃん」と言っていましたが、検定だけは指示書の順番通りに書かなければ減点されてしまうということを説明しました。', null, 'タイピング: 今日はいつもよりスコアが少し下がってしまい、実力が出しきれていない様子でした。
盛り上がり: 問題が終わって時間に余裕があったので、どんどんアレンジしていました。'),
  ('9d0fcb56-d479-53af-b76f-aa8d4a324db9', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-26', '17:30:00', null, '通常 / スロットマシーンの完成', '作成ちゅうだったスロットマシーンをプレイして前回の復習をし、完成を目指しました。 スロットマシーンの数字がそろうということはどういうことかを自力で考えてもらってから、「コスチュームの番号を調べる」コードを教えました。 最初はスプライト3つ分のコスチュームを一度に調べるコードを作成していましたが、うまく動かなかったため、2つずつ順番に調べたらどうかという提案をしてコードを修正してもらいました。 自分で作成した細かいコードがじゃまをしているところもあったりして、スロットがそろったときの音がそれ以外でも鳴ってしまう現象がおきましたが、自分で原因を見つけることができていました。', '最後のバグ探しで少し疲れたようで、スロットマシーンはもう完成！とのこと…', 'タイピング: 正誤率が初めて9割になりました！
盛り上がり: スロットがそろったときの動きができたときは嬉しそうでした。'),
  ('599a98dc-159f-5cb7-b175-a7c9b73f7afb', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-26', null, null, '通常 / 追跡ゲーム（復習しつつ進める）レベルアップの文字だしと、勝利のメッセージの表示、アレンジ 時間があれば乱数についてのチュートリアル', '前回やったことを復習しつつ、勝利のスプライトを表示しました。「もし」を使うときにずっとも使うことを覚えていてくれました。初回から学んだことを復習しつつ、最後にヘーゲルが踊るアレンジを追加しました。プログラムの止め方についてかなり思考錯誤していました。「全てを止める」「他のスクリプトを止める」など、新しいブロックについても確認しました。 乱数チュートリアルを確認しました。内容はしっかりと把握できたようです。実際の使い方についても紹介しました。', null, '時間帯: その他
タイピング: 長文でしたが、根気づよく取り組むことができていました。
盛り上がり: キューブの戦いで一緒に遊びました！！ぼろ負けしました。ひかるくん強いです。'),
  ('4bd6acfd-ea53-5234-88b6-5b266f32b3f3', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-09-26', '17:30:00', null, '通常 / 聴いた通りのコードを作ってみよう', '前回、テストという形式で検定の問題をやろうとして、いやいやとなってしまったので、今回は問題文を読み聞かせて魚釣りゲームを作っていきました。ゲームを最初みせた時、自由に作りたいといっていたが、どの座標に置けばいいの、どのむきにすればいいのと悩んだ時に、ヒントを与えるように問題文を読み聞かせてえにし君に機嫌を損ねないように作り始めていきました。その流れで、問題文を読んで、えにし君自身がわかりやすいようそれに合うにコードを復唱するという形式でを自ら行ったのはいいと思いました。完成まで、気がそれることなく作れることができました。アレンジも応援する個を入れてよかったです。これを含めて40分ほどで終わったので残りは遊んでもらいました', null, 'タイピング: 集中して取り組めていました
盛り上がり: 応援するキャラクターを入れるなんてかわいいとおもいました'),
  ('41416e22-ad18-5a07-8d11-11bcd0a4f134', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-26', '16:30:00', null, '通常 / ドリル少し（3問目くらい）/単元別演習 メッセージ（2問くらい）基礎を確認！', '（ドリル）文を読んでのプログラムはおそらく初めてでしたが、とても丁寧に取り組めていました。最初は自分でアレンジしてしまっていましたが、すぐに慣れたようです。3問ほどで終わろうと思いましたが、本人の希望で5問進めました。嫌いではないようです。4問目、5問目になると文章が少し複雑になり、混乱している様子でした。一緒にひとつずつ読み直して確認しました。 （単元別）メッセージの使い方を忘れてしまっていたようなので、説明しました。テレパシーのようなものだと説明しました。少し思い出してくれたようです。', null, 'タイピング: ゆっくりでしたが集中して取り組めました！
盛り上がり: そろそろ運動会があるようです！'),
  ('2a940616-39c5-5466-9eee-1d4f429494e2', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-26', '17:30:00', null, '通常 / クイズ問題（今日中に完成）時間内に終えることを意識する！', '自分でオリジナルのクイズ問題を作ってもらいました！ほぼ全て自分でプログラムできていました。 つまづいた点は「メッセージとずっとの併用」です。メッセージが終わったあとも「ずっと」があったため、プログラムが二重で作動していました。本人に見直してもらい「ずっと」の及ぼす影響力について再度説明しました。メッセージの使い方が整理されていて、プログラムを確認したときにとても見やすかったです。また、変数と定型文を同時に言わせることができる「～と～」のブロックも紹介しました。', null, 'タイピング: 上位20%でした！素晴らしいです！！
盛り上がり: オリジナルでキャラクターを作ってくれました！'),
  ('b262fda6-e843-56a9-9fd4-5884972601c7', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-26', '16:30:00', null, '通常 / 選抜東京都大会作品の完成、フォーム入力', 'カメが二酸化炭素を消すゲームで、ゲームオーバー後の再挑戦スタートの際、カメがゲームオーバー時のセリフを言ってしまうバグを直したいと言って、コードを見直していました。 逆算的にコードを見ることを勧め、「ゲームオーバーのセリフを言うきっかけのメッセージの確認」「そのメッセージを送る条件」とさかのぼって見ていき、条件のうちのスコアの初期化がゲームオーバー後の再挑戦のときにされていなかったことを発見できました。 再挑戦のときに、1度目のときよりも二酸化炭素が増えてしまうバグの修正をしました。しもさんの助言で、クローンの設定を見直し、1度目のクローンが再挑戦のときに削除されるようにして自力で直すことができました。 作品の完成後、応募フォームの入力をしました。', '検定の準備', '盛り上がり: 見直すところのヒントを出すと、自分できちんと修正箇所を見つけて直すことができていました！バグが解決したときは満足そうにしていました。
備考: フォームに入力する内容をGooglekeepに入れて、ブックマークバーに保存しました。'),
  ('46e5a020-31ad-5ec2-bce5-663fbc72d7c6', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-22', '17:30:00', null, '通常 / コンテスト作品完成及び応募フォーム用文章の確認', '作品自体は自力で修正して完成できていたので、制作背景、作品紹介、アピールポイントの文章の見直しをZoomで行いました。 審査員が読みやすく、目に留まる文章にすることを目標に一例を示したところ、すぐに対応して文章の読みづらい癖を改善できていました。 人とは違うことを書くことを目標にしていたら、あっという間にエンディングのストーリーを書き上げてくれました。作品紹介に入れるだけではもったいないということで、現在完成している作品を複製して、エンディング追加バージョンをギリギリまで作成することになりました。', null, '盛り上がり: Zoomとアルスパークのメッセージでのやり取りでしたが、満足そうに受講してくれました！ 一緒に考えた文章についても、「これいいね！」と喜んでいました。
備考: 必要があればLINEやアルスパークのメッセージで対応することになっています。'),
  ('e7c24405-7ed1-5be3-a394-4f16b385005e', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-09-22', '17:30:00', null, '通常 / ジャンプの基礎を変数を用いてみてみよう、異なるジャンプを見比べよう', '最初に先週作ったコードを正解のものと見比べました。変化を見ていくうちに、バグができた場所も直ちに気づけて、それを修正して楽しみを持っていました。 次に、変数を使って、高さと回数がジャンプの登り幅として変数が活用できるよということを共有しました。最初の2倍にジャンプするというめんどくささも実感できて、その後、変数をいじってジャンプを遊んで、モチベを保てていました。 そして、教材の等速ジャンプのコードを見せて、何が違うかを考えさせました。下る時にも変数が活用できることを共有しました。ついでに、放物ジャンプも軽く見せて、滑らかなジャンプでいいと重力の良さも気づけて絶賛していました。終わった後にゲームでも同じジャンプ使われていることを核にしました', null, 'タイピング: 少しまた遊び気味でやっていました
盛り上がり: 終始モチベが下がらずできていました。'),
  ('af07a9b9-949a-5d8e-bdef-43e6e4a35223', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-09-22', '16:30:00', null, '通常 / 様々な音の鳴らし方を学ぼう', '基本操作コースの音楽のところをやりました。前回やったドラムやシンバルの鳴らし方をスムーズに作れていました。そして、ほかのキーに新たな楽器を追加して、とても賑やかになりました。録音も本人自体は嫌がっていましたが、そのやり方を共有できました。コスチュームの変化で音が鳴っているようにするコードを最初は一緒に作っていったが、次の楽器では、違うように作ってしまい、前に作ったのとどこが違うか助言しながら、その違いに自分で気づけました。 基本操作コースは1項目以外終わりました', null, 'タイピング: 左手も使えるようになっていた
盛り上がり: どの楽器の音もファの音階が好きそうです。'),
  ('6d74c1de-525e-5d6f-8b0f-e8495d7ebc41', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-22', '16:30:00', null, '通常 / コンテストの準備', '自分で直すところを決めていたようで、メッセージの名称の手直しや発車時刻のランダム化などをしていました。 メッセージの数が多く、探すのが大変そうだったので、ctrl+Fで検索ができることを伝えたところ、それなりに活用しているようでした。 15分前にきちんと作品を完成させたため、残りは久しぶりに自由時間にしました。', '検定の準備に入ります。', 'タイピング: 淡々と的確にこなしていました。
盛り上がり: 作成してきてくれた八王子親子大会決勝用の原稿がとてもよくできていました！ひいろくんの目標通り、ケーブルカーに興味を抱かせる内容でした！ ゲームをプレイする人への気遣いやスポンサーへの気遣いなど、とても大人びた視点で作成できていました。発表が楽しみです！'),
  ('e1000b54-a159-5ba1-9123-b189c4ee179c', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-20', '17:30:00', null, '通常 / 検定4級/1回目に取り組むものの復習', '10分くらいで一通りプログラムし終えてしまったようです。前回は「なめすぎていた」ようです。アレンジとしてはBGMの設定を考えてくれました。 アレンジの難易度が高かったので、元のプログラム自体が混乱してしまっていました。アレンジがなければ、しっかりとできていたようです。アレンジをやり直してもらいました。バグがなく、スムーズにプログラムが動くことが大事だということを伝えました。 後半はキックゲームを作成しました。サッカーゴールが動く新しいゲームの形だそうです。ゴールが端に行ってしまったらそれ以上戻らなくなることが気になっていました。迷路での壁で跳ね返る動きを参考にすることを提案しました。≧≦の向きが完全に理解できているわけではないので、場数を踏んで考え方のコツを知る必要があると思います。', null, 'タイピング: 集中して取り組んでくれました！
盛り上がり: 1時間集中して取り組めていました！！'),
  ('2ebadab6-66fb-5016-8869-79f7054f320f', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-20', '16:30:00', null, '通常 / 迷路チーズ続き（③スコアの設定（ゴールの設定）、①チーズの挙動、②邪魔者スプライト）', '乱数忘れちゃってたみたい。サイコロのチュートリアルをみて復習しました。チーズの挙動が、まったくアイデアが浮かばないようだったので「乱数」のキーワードを説明しました。乱数も忘れてしまっていたようなので、サイコロのチュートリアルをみて実際に手を動かしてもらいました。x座標、y座標の上限と下限についての意識もなかったので、座標の絵を示して説明しました。スコアの設定もスムーズではありませんでしたが、自分でできました。ゲーム自体は完成です！ こちらからの問いかけでようやく考え始めるという印象でした。', null, 'タイピング: 集中して取り組んでいました！キーの位置を覚えつつあるようです！
盛り上がり: 心ここにあらずという感じでした。'),
  ('3929fa27-5955-5fdf-a870-09881bc3dee3', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-20', '16:30:00', null, '通常 / ドリル問題9以降（基礎の確認）', '前半いくつかコードを見ながら復習しました。言葉を読み上げると、プログラムがなんとなく想像できるようでした。ゆっくりでしたが、どれも自分で考えながらできました。ひとつひとつ丁寧に確認していました。 前半で「旗が押されたら」の動作になれてしまった影響で「キーを押されたとき」の指示に少し混乱してしまった様子です。向きも角度ではなく矢印の機能を使ってプログラムしていました。 日本語をしっかりと呼んでプログラムすることができるようです。円形に動かすプログラムも自分で考えて作ることができました！すごい！', null, 'タイピング: Sでした！！とても集中して取り組めていました！
盛り上がり: 1時間しっかり集中できていました！'),
  ('1be51318-ff77-529b-9d2e-38cbd000b6ff', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-13', '16:30:00', null, '通常 / 基本的なブロックの使い方に慣れる', '今日はしょうたくんと席を離して担当講師がわかれたせいか、ほぼ1時間集中して取り組むことができました。 「チーズを探せ」と「スロットマシーン」の両方をプレイして、「チーズを探せ」を選びました。 ネズミの向きを変えることで、すべての方向の動きを「〇歩動かす」で対応できることには自分から気づいていました。 チーズがランダムに出現するコードは、自力で「どこかの場所へいく」を使って作成できていたので、とりあえずそのまま進めておきました。 この単元で出てくるコードについてはほぼ覚えていたこともあるのか、自分の知っているコードで作成しようと工夫している態度が良かったです。 ①動かすは完成できたので、②邪魔者に入りました。邪魔キャラの動きはコードを写しながら説明しました。', '座標でなく「どこかの場所へいく」を使ったため、迷路にチーズが重なってとれなくなることの解消、邪魔者スプライトの動きの改善', 'タイピング: 左右の指の使い分けを丁寧に見ていました。タイピングは丁寧に取り組んでいます。
備考: しょうた君と別々に担当がついて、しょうた君に話しかけにくかったせいか、時間いっぱい集中して取り組めていました。'),
  ('e97a40ca-74b5-5ec6-8961-e45a82a3be1b', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-09-19', '17:30:00', null, '通常 / レースゲームを完成しよう', '前回に続いてレースゲームを作りました。最初はアイデアが思いついていないのか乱数をいじって秒数を変えているだけでした。ちょうどいい秒数が決まると、動くときの相手の向きも丁寧に変えて、プレイヤー側も進む歩数を乱数などにして、とてもゲーム性があるものが完成できました。いい考えが思いついた時の、作りのスピード感は素晴らしいです。', null, 'タイピング: 早く終わらせていました
盛り上がり: 自分が作ったものほめてくれました。'),
  ('36435b9f-505f-5563-9c9d-55e27cf5016b', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-19', null, null, '通常 / 追跡ゲーム もし/まで待つの使い方', 'サメから逃げろのチュートリアルで「もし」の使い方を確認してもらいました。 「もし」と「～キーが押されたとき」のブロックを組み合わせて上下左右の動きをスムーズに作ってくれました。音を鳴らすときに「最後まで鳴らす」というブロックを使うこと、「どこかの場所へいく」というブロックには秒数つきのものもあることを伝えました。初めての変数でしたが、スムーズに理解できたようです。「0にする」をいれる位置もバッチリでした。 レベルアップとして、「①背景の変更」「②ダイヤの動く速さのアップ」「③レベルアップの文字だし」のリクエストがありました。「～まで待つ」と「ずっと」「もし」の組み合わせ方を説明しつつ、①を終えました。②に関しては自分なりに考えてくれましたが、「～まで繰り返す」と「～ずっと」を組み合わせた方法も紹介しました。論理的な考え方が出来ていて素晴らしいです！ ③と勝利のメッセージの表示が終わっていません。', null, '時間帯: その他
タイピング: ホームポジションをしっかり意識して取り組めていました！素晴らしいです！
盛り上がり: こちらの提案したプログラムが理解できたとき楽しそうでした！良かったです！'),
  ('e4330b60-47ca-53d5-a82d-1c7f218f44fc', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-19', '17:30:00', null, '通常 / 3級検定問題に挑戦', 'テストとして挑戦してもらいました！ 「変数歩もどる」というプログラムに困っていました。「-10歩進む」という考えは持ってくれていたので、そこを糸口に説明しました。文を隅から隅まで読むことはできていなかったので、プログラムする順番や新たに旗を作るタイミングをいくつか間違えていましたが、ひとつひとつの説明されている内容に関してはしっかりプログラムできていました。 時間内でアレンジまでは到達できていませんでしたが、集中してできる限り取り組むことができていました！本人曰く難しかったそうです！', null, 'タイピング: 集中して取り組めていました！'),
  ('a1208818-ead4-5bde-9cc9-63e56f47ca72', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-09-19', '17:30:00', null, '通常 / 文章からコードを作ろう', '検定の過去問を検定といわず、テストといってやろうとしましたが、「前もって言ってないじゃん」「やだ」と駄々をこねるような嫌がり方でした。それを落ち着いて、作り始めたら、文を見ずに動画から想像力で作り始めました。大方8割くらいは動画と同じ動きをしていてそれはそれでよくできていました。一部、端に触れた時の動きができないと困っていたので、紙を見ながらこう言ったコードが使えるよと共有しました。 テストという言葉に拒否反応を示していたので、こういった軽をやるには力を試すような言葉を使わないでやり進めていくのがいいと思います。', null, '盛り上がり: ゲームをやっているテンションはとても楽しそうでした。'),
  ('4ff62f05-53ac-50ea-861e-e3fdda331cf0', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-09-19', '17:30:00', null, '通常 / 検定練習', '制限時間の30分で解いてもらいましたが、発生したバグを直すのに時間がかかってしまいアレンジまで行きつくことができませんでした。模範解答と照らし合わせて確認したところ、次のような改善点が見つかりました。 ・「①のあとの動作」は①と別のブロックではなく、①のブロックの下につける(プログラムは上から順番に一行ずつ処理されるということを説明しました) ・同時に行う処理は違うブロックで作る ・問題文に「ずっと～」とあるが、「ずっと」のブロックに入れ忘れていた 解き終わったあとアレンジしてもらいましたが、いくつか案が浮かんで作れていたので、本番は一つだけ作れば大丈夫そうです。全体的に、検定は普段と違って制限時間や厳密さが必要なので難しいと言っていました。', null, 'タイピング: 集中していました
盛り上がり: 難しいと言いつつも、楽しみながら問題を解いていました。'),
  ('5a7a02ae-16ce-5067-b1bd-e4ba0d290762', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-09-19', '16:30:00', null, '通常 / 検定の練習しよう', '3級の検定の練習をしました。全体的にコードは正しく選べていました。「（変数）歩動かす」で歩数のところに変数を持ってくる表現がなかなか思いつかなくてなんだそうです。 ただ、コードを直列につなげがちで、動きとしては問題はないが、検定では問題文に沿わないことを注意しました。それを注意して、もう一度練習すれば、安心だと思います。 アレンジの時間がなかったので、残り10分でアレンジをする時間配分にするよう提案しました。', null, 'タイピング: 正答率が高かったです
盛り上がり: 今週末の発表頑張れ'),
  ('bcd836bb-9466-5abe-8290-a9a089b600d0', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-19', '16:30:00', null, '通常 / 単元別演習 メッセージ/分岐 忘れていたようで欠席でした。', null, null, null),
  ('b33c200b-6ba5-5ab0-a04e-ebad9099b0ba', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-16', '16:30:00', null, '通常 / ３３７拍子（新しい機能を知る）', '337拍子は知っているそうです。真剣に動画をみて作成していました。 スプライトに動きを加えて自分なりの作品を作成していました。コスチュームを見せるための時間を設定し忘れていて、困っていました。「ずっと」を使ったときのプログラムの実行順序に意識を配れるようになりたいです。音もドラムからピアノに変えて楽しんでいました。', null, 'タイピング: 前回から各段にタイピング速度、正答率が上がっていました！
盛り上がり: 音楽は嫌いではない印象を受けました。ここしばらくで一番楽しそうでした。'),
  ('9fc77221-ff4f-5a4b-9e88-1901975ecf54', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-16', '16:30:00', null, '通常 / 迷路 チーズを探せ！ （復習（座標））', '向きについて忘れてしまっていたので復習しました。滑らかに動くプログラムも考えてもらいました。「もし」の使い方もすこし忘れてしまっていたようです。 壁で跳ね返るプログラムにはかなり苦戦していましたが、「もどる」というキーワードが出てきたので良かったです。その後「-10歩」というアイデアがでてきました！！ チーズ、得点についてはスラスラとプログラムできていました！ 最後、クリア画面を表示させるときに演算（＝、＞）の使い方で少し困っていました。今回復習して少し思い出してくれたようです。', null, 'タイピング: 何度も取り組んでいました。
盛り上がり: かわいいクリア画面を作ってくれました！'),
  ('a0c57757-cf24-5591-b38e-adb8c165d338', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-16', '17:30:00', null, '通常 / 迷路でチーズを探せ！（座標・跳ね返り）', 'キーがおされたら」のブロックを使ってネズミの動きをプログラムしました。見本と違ってカクカク動いているのも本人は分かっていました。滑らかに動く方法は最後にさらちゃんと確認できました。 壁にぶつかったときのプログラムが難しようでした。もどるというキーワードもなかなかでてきませんでした。±0になるというところで少しピンときたようです。 チーズの動きは自分なりに作ってくれたものの、見本に似せて作ってくれました。スコアの設定はばっちりでした。 虫の動きは、見本をみて説明してくれました。乱数で回転を変えているところは分からなかったようです。乱数の使い方について説明しました。', null, 'タイピング: 楽しく取り組めていました！！
盛り上がり: ほぼ一時間取り組めていたので良かったです！'),
  ('44ed3148-8a7a-59d4-b0ae-922d4dea019a', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-16', '17:30:00', null, '通常 / アイテムで脱出ゲーム続き→→迷路 チーズを探せ！（座標・向きの確認）', '脱出ゲームはゴール条件の設定をしました。プログラムする順番でつまったので、上から順にプログラムを確認していきました。最後は自分でプログラムできて満足そうでした。 迷路チーズは、ねずみの動きに苦戦していました。動かすことは出来るのですが、ねずみの向きにあまり注意がいかないようです。壁に跳ね返る挙動は、「とまる」というところで思考停止していました。 スコア、チーズのプログラムは全てひとりで取り組めていたので素晴らしかったです！！', null, 'タイピング: 集中して取り組めていました！すごい！'),
  ('ddde87eb-0160-5f33-aa66-1d3ef6b312e5', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-16', '18:40:00', null, '通常 / クリエイティビティを出す！（素材だけシリーズ・カーレースなど）', '本人のリクエストでクイズを作りたいとのことだったので、一緒に取り組みました。リストは使いませんでしたが、しっかりと条件分岐を使ってプログラムできていました。スコアの加算も、演算を使って分かりやすくプログラムされていて素晴らしかったです。欲をいえばプログラム順に問題が出題されてしまうのが少し残念でした。最後に乱数を使ったり、リストを使ったりすることを提案しました。', '検定準備に入る予定です！', 'タイピング: 高スコアでした！ホームポジションにはまだ自信がないようです。
盛り上がり: 会話しながら作成できました！とても楽しそうでした！'),
  ('e39897c6-62c8-5a28-9f0c-b78ab53601f4', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-09-16', '17:30:00', null, '通常 / 迷路脱出ゲーム', 'タイピングが終わったらスクラッチで検索したゲームをやり始め、熱中してしまいました。今日はブロックくずしの続きをやる予定だったのですが、どうしても気乗りしないみたいで、前に作った迷路脱出ゲームの製作を続けることになりました。人形のキャラクターを追加して、ゲームの場面が変わったとき、送られたメッセージに応じてその人形を動かすことができました。', 'ブロックくずしの続き', 'タイピング: 集中して長い時間やっていました。'),
  ('42691794-aedd-509b-9e91-21948522a00d', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-09-16', '16:30:00', null, '通常 / ２つのスプライトのリレーションの考えをマスターする', '前回までは、名前を動かそう・世界を創造しようの単元で、動きの基本をやったので。今日は「２つのスプライトリレーションして動かすのをマスターしよう」と完成動画をみせながら説明したところ、即イメージと目的を理解していました。 最初の場面で2人のスプライトを設定し、メッセージを使って背景を変えるところまではOK。次の場面でネコを走らせたかったのですが、そのコードを忘れており。 体験会でよくやる、足をバタバタさせて端についたらはねかえる動きを一通り復習しました。（←この最初の基本コードを完全に忘れていました） その他、何かにつけて「秒」でコントロールするのを先に思い浮かぶようで。 この辺りは意識的に「秒でコントロールした時」と「メッセージを使う時」とでの違いを体験させると良さそうです。', 'しばらく、「前回までの復習」をしてから進めるのが良いと思う。 前回まで作った作品のコードをみながら、覚えてるか確認ですね(^^)v', 'タイピング: 最後に画面を閉じてしまって、どこまで進んだか記録できなかったです。 後ろで様子をみていた感じでは、1文字タイピングを熱心にやっていました。2～３コース進めていたようでした。
盛り上がり: ２つのキャラクターを登場させて背景を変えるというショートストーリを考えると言った時、あれこれイメージが浮かんでいたみたいです(*^^)v'),
  ('cf132e7d-9891-5a3d-9a21-674ab4dc0e90', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-09-16', '16:30:00', null, '通常 / 動画を見ながら写経を進める', '動画を見ながら、前回の脱出ゲームの続きを作りました。1面から2面に移行するところまでは作り終わったはずなのに、実行してみたら移らなかったのでバグの原因を考えました。すると、送っているはずのメッセージが送られていなかったことをトラくん自身が発見して直すことができました。バグ取りができるくらいにはコードの構造を理解しているみたいです。', '続き(あと少し)', '盛り上がり: 前回よりもやる気をもって取り組めていたと思います。'),
  ('63005f76-44c4-586d-a920-806df6b1a735', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-09-15', '17:30:00', null, '通常 / 細分化に慣れよう', 'チーズを探せを使って細分化の練習をしていきました。細分化した文は最初は見たままの文であったが、コードを見ながら書き直した文はよりよせて書くことができました。コードを作り始めると、ゆきちゃんのレベルにしては易しいものなので、細分化した紙を見ながら迅速につくっていました。ただ、迷路にぶつかると跳ね返るという動きがコードでなかなか思い浮かんでいなかったんで、前後と正負の歩数の関係性を一緒に考えながら共有していきました。全体的に手際よく進められいました。 きょうは、チーズの乱数で移動するところまで作れました。あとは邪魔者を作るだけです', '検定練習', 'タイピング: 継続してプラチナ級でした
盛り上がり: 前回の練習も生きたのか細分化した紙を見ながらコードつくりははやかったです'),
  ('f6fb34f1-e16f-55f2-80d8-e85dda1b9dd6', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-09-15', '17:30:00', null, '通常 / ジャンプのの基礎を固めよう', 'ジャンプの応用で、１あたりを作っていたころは、まだ簡単なコードであったので、気持ちを下げずに集中して作っていました。２の段階では、黙々と動画を見ながら作っていましたが、モチベは下がってしまいました。 作り終わっては、ロボの方に気が向いてしまい、あとロボいじりをしていました。', null, 'タイピング: タイピングもスコアをゼロにするまでミスタイプするっていうように遊んでいて、集中力が悪い方向に働いています
盛り上がり: まさきくんが持ってきたお土産を2つも食べてしまうほど、この空間に好んでいるような感じしました。'),
  ('b4d55c27-82bf-5268-922f-90018f533634', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-09-15', '16:30:00', null, '通常 / 基本操作コース踊ろう、音をつけよう', '前回までに作っていたものに付け足しながら、背景の色変化やスタンプの新しいコードを使っていきました。背景の色変化は前回、明るさの変化のコードを使っていたため、楽しんでスムーズに使いこなしとても鮮やかなものになりました。 つぎに、ダンスパートに基本操作コースの音を鳴らそうに沿って、キーボードで音を追加していきました。ドラムやシンバルの音はこだわり持って選んで、元のBGMと合わせてより華やかなものになりました。', null, 'タイピング: 右手だけに偏りがちで左手の活用も慣れてほしいです
盛り上がり: アイデアが次から次へと出てくるのでその発想力を続けてほしいです'),
  ('df123e1a-505d-5d66-9cee-6e84ac436bfd', 'b2246586-4496-52f9-a825-be2488a00a31', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-15', '17:30:00', null, '通常 / オリジナルゲームの作成', '今日は前回と違うゲームを作成していました。 「50回クリックしたら表示させるようにしたい」とのことだったので、カウンターとしての変数の使い方を紹介しました。理論的には理解できたようです。 もしを使うときにずっとを使うのを忘れてしまっていて、困っていました。プログラムするスプライトを間違えたときには自分で気づいて直すことができていたので良かったです！授業時間しっかり取り組めていました！すごい！！', 'ゲームはまだ技が全て完成していないので、来週続きをやるかもしれません。', '盛り上がり: 最後じょうたろうくんの作品で遊んでいました！楽しそうでした！'),
  ('fe91a10b-d11e-53d0-b388-52df0a725d81', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-15', '16:30:00', null, '通常 / 大会に出す作品制作', 'メッセージの文字がオリジナルのものになっていたので、誰が見ても分かるものにするのはどうかと提案しました。提出までには変更するようです。 乗客が必ず一人取り残されてしまうバグが発生していましたが、自分でプログラムを確認して修正を加えられていました。 エンディングが流れない不具合がありましたが、一緒にプログラムを見直すと「全てを止める」が原因でした！自分で原因のありそうな箇所を探すことができていました。 アピールポイントなどは自分で考えてくるようです。', '（もしかしたら）プレゼンで話す内容を一緒に確認するかもしれません。', 'タイピング: ホームポジションを意識してスムーズに取り組めていました！
盛り上がり: ホームポジションを使うときには小指を使わないそうです。清水にある神社についても教えてくれました！
備考: 作品提出は自分で行うようです！'),
  ('52276662-b870-5e9d-b522-a5bab6b6776d', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-15', '17:30:00', null, '通常 / 大会提出作品を作る', '前々回に洗い出したバグはほぼ修正できたようです。すごい！ エンドロール部分のビームとドラゴンの動き部分がまだ少しプログラムし終えていないようです。最後のストーリーがなかったので、最後の画面に言葉で表現することを提案しました。 大会提出時のアピールポイント、作品説明なども考えてくるようにお願いしました。最後にまさきくんにプレイしてもらっていました。', '作品の手直し(少し)と作品の提出準備をします。', 'タイピング: 集中して取り組めていました。
盛り上がり: 2級の問題をまだ確認できていないので心配そうでした。
備考: 教室で提出をしたいみたいです。'),
  ('07512282-f376-5c39-9a78-0b5e47a829ca', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-13', '17:30:00', null, '通常 / 迷路チーズ 障害物アリver（追跡ゲーム応用）', 'ねずみの動き、チーズの動きは自分で考えてプログラムできていました、スコアの設定もできていました。 虫の動きに大苦戦していました。独自路線を作ろうとしてくれましたが、見本の虫の動きに注目してもらい、「乱数を使って表現できる」ということに気づいてもらいました。乱数の使い方についてはコイン例に説明しました。ピンと来たようです。 見本とそっくりではありませんが、現段階ではかなり論理的なプログラムを組み立てることができていました！', null, 'タイピング: 気乗りがしないようでしたが、取り組んでくれました。
盛り上がり: Scratchのマイクラが気になるようでした。'),
  ('cdb8aa0e-76db-5a32-8348-b6e51809f65e', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-13', '17:30:00', null, '通常 / 迷路チーズ（基本がメイン、思い出す）', 'ねずみの動きにかなり苦戦していました。x, y座標の向きも少し忘れてしまっていました。「もっと」を使うときも「ずっと」を使うのを忘れていたり、「～にする」「～ずつ変える」の違いを考えられていなかったりしました。跳ね返るという動作も、「震える」という言葉で説明してくれましたが、ブロックにある言葉で説明するのに苦戦していました。 チーズの動き、スコアの設定はスムーズにできていました。算数的な要素がなくなると手が進む印象でした。虫の動きは、壁に当たったときの動きに注目してもらい乱数でプログラムできることを確認しました。乱数の使い方をコインに例えて説明すると、なんとなく理解できたようです。 最後に正解のコードを見て揃えていました。正解が気になるようです。', null, 'タイピング: 集中して取り組むことができていました！'),
  ('f1977496-e8d1-5d35-b0fd-39bbbcaef342', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-13', '16:30:00', null, '通常 / スロットマシーン（見た目、メッセージ）', '最初にプレイしたとき、プログラムの内容がピンとこないようすでした。さらにスプライトの動きを日本語で説明するのに苦労していました。なんとなく手を動かして「できてしまっている」という感じです。 メッセージを知らなかったようなので説明をしました。新しいブロック（コスチュームの番号など）も紹介しました。少し内容が重すぎたのかもしれないです。粘り強く取り組み、最後には質問もくれました！えらい！！（作品は完全に完成していませんが、深追いする必要はあまりないように感じています）', null, 'タイピング: タイピング速度はゆっくりですが、ホームポジションを意識してタイピングできていました！'),
  ('25c7b904-f25a-5921-b3d2-1714b3e2eacc', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-12', '16:30:00', null, '振替え / プレゼン準備', '発表準備として体裁を整えました。フォントの大きさを整理して、全体の統一感を出せました。シンプルで見やすいスライドになりました。一分間に話せる文字数についても共有しました。 大会用作品を作成しました。最初のストーリーをとてもうまく作ってくれていたので、アフターストーリーを提案しました。ショートカットのコースを作って動きを検証したい部分だけ再生できるような仕組みを作っていて素晴らしかったです。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: パソコンのショートカットキーについてとても詳しいみたいです！！いろいろ教えてくれました！'),
  ('1e81a74b-f3d7-5a45-a9bc-68eb413212e2', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-12', null, null, '通常 / レースゲーム続き！', '素材だけシリーズです！前回の続きでしたが、再度ゲームの構成をなんとなく家で考えてきてくれました。ステージの配色がプログラムに与える影響も考慮してくれていました。 プレイヤーが動かす車はスムーズにプログラムできていました。対戦相手のプログラムに苦戦していたので、対戦相手の役割を一緒に考えました。プログラミング的に難しい表現したい事象をブロックの言葉で表すのはまだ少し難しい様子でした。 次回続きを作ります！', null, '時間帯: その他
タイピング: うでだめしは苦手なようで、なかなか取り組んでくれません。'),
  ('736e802f-3aa6-57f0-ae56-b182bef74a24', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-12', null, null, '通常 / 教室に慣れる、Scratchでの課題に慣れる', 'さすがによく慣れていて、カードの問題面を見せて自力で作成してもらうという繰り返しでスムーズに進みました。知らないブロックの場合は本人がしっかり申し出るため、その際はヒントを出すことで、きちんと理解できていたようでした。 座標の理解もスムーズでした。', null, '時間帯: その他
タイピング: まだキーを探すこともありますが、ほぼ問題なくできていました。
盛り上がり: 一つ一つの動きを、楽しんで作成していました。 背景の変更やメッセージによってコードの開始を制御できるところが楽しかったようです。 それなりに満足そうに作ってくれましたが、ゲーム作成の方がもっともっと好きだそうです。
備考: お母さんから、今日は楽しみすぎて早く行くと言って聞かなかった、と伺いました！'),
  ('7a709adc-c89a-5dac-89a5-3db6cd84bfa6', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-12', '16:30:00', null, '通常 / プレゼン準備', '大会用のスライドを準備しました。タイトルを決定したり体裁を整えたりしました。色合いがとてもきれいでした。 5分間のプレゼンにしては文字数が多いように感じたので、人間が1分間に喋れる文字数（1500文字）について共有しました。また重点を置いて話すポイントを決めるようにアドバイスしました。', null, null),
  ('4c6a9e54-9ec2-56be-81bc-7941ff297d9e', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-12', null, null, '通常 / ゴルフ完成させる・コードモンキー', 'ゴルフを見直してもらいました。不具合として最初のボールの位置を挙げてくれました。猫の位置ではなく、ボールの位置として不具合を考えられていたのがとても良かったです。見本のプログラムと齟齬が見つけられなかった（数字はきちんと撃たれていた）ので、論理構造のみ一緒に確認しました。 コードモンキーは28まで進みました！とてもスムーズに進められていました。', null, '時間帯: その他
タイピング: 集中して取り組めていました。速度も少し上がってきたように感じます。'),
  ('35b45d75-7c06-583d-822a-bc277c025b49', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-12', '17:30:00', null, '通常 / ブロック崩し続き（しっかり完成させる）', '前回はコードの中身について確認したので、今回はプログラムの大枠（条件分岐・メッセージなど）について深く共有しました。ボールが跳ね返るときの能動と受動の関係を考え、メッセージを送るタイミングについて考えました。 また、プログラムストップの条件としてy座標を使うことを提案しました。等号不等号の向きにはまだ自信がない様子でした。 集中力がいつもよりも低かったですが、何度かトライを重ね完成させることができました。えらい！', null, 'タイピング: いつもより正確性が薄いように感じました。パソコンの調子が悪かったのでうまく打てなかったようです。'),
  ('539c3482-6d54-519a-a06f-0ff633f98487', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-09-12', '17:30:00', null, '通常 / スロットマシーンの作成', '・前回作りかけだった「アイテムで脱出ゲーム」は時間前からやりたいと言ってとりかかり、バグを取ってレッスン開始前に完成させてしまいました。スプライトを緑色にするブロックと青色にするブロックが同時に動いてしまっていることが原因のバグでした。 ・今回のレッスンはスロットゲームを作りました。「ずっと～」の中に「もし～」を入れているところを「～まで待つ」に置き換えれば簡単に書けることを伝えると、理解して自分で書き換えていました。メッセージを使うと上手くコードが書ける場面で、そのことに気付くのに時間がかかってしまいました。前回の脱出ゲームでもメッセージは使っていたのですが、使いこなすには練習が必要かもしれません。全体的に、「この動きを作るためにはどんなコードにすればいいんだろう？」と積極的に考えていました。', 'スロットゲームの続き(3桁そろったときの演出)', 'タイピング: 正答率が高くなってきています。
盛り上がり: とても集中力が高かったです'),
  ('029445be-48e5-57d7-b4bd-b83d4ea887b6', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-09-12', '17:30:00', null, '通常 / 脱出ゲームの完成', '脱出ゲームの続きを作っていきました。2面に代わる時、鍵の位置や、変数の初期化、ゴールポイントの変化など、変更すべき点をすべて把握できていたので全体が見えていてすごかったです。コードも1面の作りまねして作っていったが、2面のゴールについた時、2面のスタートに戻ってしまうバグが発生しました。一旦、1人で考えさせましたが、思うように進みませんでした。だから、1面と2面で違うところは何と、尋ねたところ、背景と即答できたので、、背景番号を用いた条件文系を共有島hした。ただ、バグはそれでは解消されず、色判定が、原因でした。協力してバグ原因を発見したが、改善案はオウスケ君が自ら考え付いたので、良かったと思います。そして、完成できました。', null, 'タイピング: 順調にスコアを伸ばしていました
盛り上がり: お母さんがいたため、いつもより静かだったが、歌は歌っていました。'),
  ('deb8bb5b-fc29-5063-8263-a1612c51d9b2', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-12', '17:30:00', null, '通常 / コードとしっかり向き合う/水泳またはスロット', 'タイピングを熱心に25分くらいやっていて、それが終わった時点で少し疲れていました…。 写経に飽きてしまったようで、今日は水泳の続きをやりたがらなかったたため、8月に途中まで作成していたシューティングゲームの完成を目指しました。 弾丸の動きはできていたので、プレイヤーである戦闘機のコードを一から作成していきましたが、久しぶりに自分で作成したせいか、上下キーで上下に移動させるのも危うかったです。（向きを変えてから10歩動かすのは覚えていましたが、座標で変えるのは覚えていないようでした）戦闘機を動かしながら、座標と向きの復習をしました。 弾丸がスペースキーで発射するようになっていたのを、スペースキーが押されたらメッセージを送って、メッセージを受け取ったら弾丸が発射するようにしたいとコードをいじっていたら、弾丸がうまく発射されなくなったようで、そこで嫌になってしまったようでした。 一応、コードはなるべくシンプルな方がよく、間に入れなくても良い手順は入れない方がスムーズに動くのではないかと伝えて、えにしくんも納得していました。 次にする課題をさがすということで、ビルのすき間と射的ゲーム応用をプレイして終了しました。', null, 'タイピング: ステージを4つくらい進めていました
盛り上がり: 自分の過去の作品を見直して、「完成させたい」「アレンジしたい」と言い始める時点では、やる気になっているように見受けられました。 ただ、最近「自分で考えて作成する」ということをあまりやっていなかったせいか、行き詰まるとすぐに嫌になってしまう様子が懸念されます…。'),
  ('62de999e-dd91-5409-8f5a-87c2a14d1e2a', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-09-12', '16:30:00', null, '通常 / 「もし」「ずっと」乱数を活用しよう', '最初にゲームを遊んでからどのようなコードが作れそうか一緒に考えながらやっていきました。ネズミの動きがどうなっているか問いただしながら答えて自分が目盛っていく形式でやっていき、ネズミが迷路にぶつかると跳ね返るとおいう細かい動きも自ら発見できて、全体的に把握できていました。 コードを作り始めると、ネズミの上下左右の動きはスムーズに作れ、跳ね変える動きも、前に進むことはプラス歩進むだから、後ろは？というように誘導して、原理を共有できました。ただ通り抜けるバグが発生し、見本を見ながら直していき確認させました。 チーズの移動も乱数を使ってみて提案したところ、スムーズにコードを持ってこれました。乱数の範囲がわからなかったため、チーズを動かして座標の位置を知れることを共有できました。', 'チーズの乱数範囲指定', 'タイピング: ひとつひとつの指を確認ながらよくできていました
盛り上がり: ゲームの構造理解鋭かったです'),
  ('b70985b8-2183-5661-9d54-c34f66c5c786', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-09-09', '18:40:00', null, '通常 / 遊んだバレーボールゲームを再現する', 'けっこう難しい内容になってしまいましたが、滑らかな放物線の動きを作ることができました。縦の動きと横の動きを分けて考えるというところがポイントで、そこを説明したら自分なりにコードが書けていました。縦の速さは段々小さくなっていくというところも具体的に説明してみたらイメージがつかめた様子でした。', null, '盛り上がり: ゲームオーバーの演出に凝っていてゆまちゃんらしさが出ていました'),
  ('ae26dcd1-088c-5cea-988f-fecfa87dc4e0', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'dc644af3-66ab-5d65-b3dc-15b9c980b8d5', '2022-09-09', '16:30:00', null, '通常 / 写経の意味を理解する', '多少めんどうそうにはしていたものの、写経しなきゃいけないと理解してできていたと思います。ブロックの説明もメモに書いていて、内容もある程度わかっているようでした。ボールのスプライトのコードはすべて完成しました。', null, '盛り上がり: ボールの動きのバグが直ったときはうれしそうにしていました。'),
  ('5c7ada68-a8a5-51ea-9f03-0d16407ac9c7', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'dc644af3-66ab-5d65-b3dc-15b9c980b8d5', '2022-09-09', '17:30:00', null, '通常 / キャッチゲーム', '今日は作り始めるまでにかなり時間がかかってしまいました。マウスのポインターに沿ってバーを動かす、ボールに当たったらブロックは隠すなど基本的な動きは少しずつ作れました。', null, 'タイピング: けっこう長い時間続けていました。「両手でタイピングできるようになったら便利じゃない？」と両手打ちを促しましたが、あまり気が乗らなかったようです。
盛り上がり: ブロックの色にグラデーションをつけているときはとても楽しそうにやっていました。'),
  ('8716b1f4-714b-543e-af9f-b367904b044c', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-09', '17:30:00', null, '通常 / アイテムで脱出ゲーム(簡単ver・座標、条件分岐の復習)', '次に何をすればいいのか順序だてて考えるのは苦手なようです。最初何から手をつければ良いのかが分からないようでした。 ボールの動きはスムーズにプログラムできていました。「鍵を取ったとき」などの言葉では表せる事象をプログラムの言葉に落とし込むのに苦戦していました。焦っていい加減にプログラムしているようなこともありましたが、今日は比較的自分で考えてくれている時間が長かったように感じました。 ゴール条件の設定がまだ終わっていないです。', null, 'タイピング: 集中して取り組めていました！2回挑戦していました！ 薬指なども使えるようになりたいです！
盛り上がり: レッスン後けいと君とゲームプレイしていました！'),
  ('ef93dfa2-8ef0-5089-bba6-36f0214fbc4c', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-09', '17:30:00', null, '通常 / ジャンプゲームの完成（スコア）', 'スコアの設定、ゴール設定をしました。 スコアのプログラムは基本的なことは出来ていました。ずっと触れてしまってずっとスコアが加算されてしまっていたので、加点のタイミングとプログラムのコードの進行具合について説明し、「〇秒待つ」という考えにたどり着いていたので良かったです。 ゴール設定は変数をうまく使って自力でプログラミングできていました。「余裕」だったそうです。最後に「アイテムで脱出ゲーム」を見てもらい、次回作る予定であることを伝えました！', null, 'タイピング: 大文字と小文字の差に少し戸惑っていました！
盛り上がり: アレンジとしておばさんにサングラスをつけていました！「最前面にする」のブロックを紹介しました！'),
  ('a9a61134-00ae-500e-a92f-fdf695a64bd5', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-09', '16:30:00', null, '通常 / チーズを探せ！（追跡ゲームの応用として）', 'プログラムの中身をなんとなく考えてもらいました。チーズの場所の出現について「どこかの場所へ行く」の言葉を使って説明できていました。 ネズミのプログラミングから始めていました。壁で跳ね返る挙動のプログラムに困っていましたが、「ぶつかったら後ろにいく」と説明してくれました。ただ、角度・座標（特にマイナス）が苦手なようです。角度についてはなんとなく思い出してくれたようです。「もし～なら」を使ったときと「～キーが押されたとき」を使ったときの違いを紹介しました。 順序立てて考えることは嫌いではないようですが、算数的な要素が加わると手が止まる印象です。チーズのプログラムはひとりでできていました！', null, 'タイピング: 集中して取り組めていましたが、ミスタイプ率は少し高かったです。
盛り上がり: 前回よりも集中して取り組んでいました！'),
  ('c992254b-c684-5550-82c1-0269cc6a8f4f', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-09', '17:30:00', null, '通常 / シューティングゲームを作る', '前回シューティングゲームを作りたがっていたため（スプライトを大量に複製して終わっていて、修正が難しかったため、新しいゲームに誘導）同じようなシューティング系のゲームを勧めました。 ゾンビを倒せ1を数回プレイしたら、おおまかな構成を理解できたようでした。 背景とスプライトを用意し、プレイヤーと敵の動きなどもプログラミング用語でしっかり答えることができていました！ プレイヤーの動きについては、「回転方法を左右のみにする」以外は自分で作成できました。 「もしビームに触れたら」の条件分岐も自分で作成できました！', null, 'タイピング: タイピングの後半になると、めちゃくちゃにキーを叩くこともありますが、キーを教えて誘導するとそれなりに覚えてきちんと打つこともできます。
盛り上がり: ビームがプレイヤーから発射されるため「表示するときにプレイヤーのところへいく」、回転方法の指定以外は、ほぼノーヒントで自分で作れていました。 30分ほどで思い通りのゲームができて、満足そうでした。
備考: マイクラをかなり集中してやっています。'),
  ('8e00d5e8-8f53-5585-becf-50cbeee58679', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-09', '16:30:00', null, '通常 / スプライトの動きを作る', '国語の教科書で習ったきつねのお話を作ろうとして、一生懸命にスプライトの動きやセリフの設定、タイミングの調整をしていました。 作りたい「世界」が明確にあるので、単元のクリアにこだわらず、創造性を大事に進めていきたいと思います。 矢印キーで動かすところは自分だけで作成していました。', null, 'タイピング: 指使いが丁寧です。時間がかかってもきちんと打とうとしているところが良いです！
盛り上がり: 自分の世界観をしっかりもって、丁寧に作品作りをしていました。 イメージ通りに物語を進めようと一生懸命でした。 長いセリフもタイピング表を見ながら自力で丁寧に打っていました。 背景がかわったら、というイベントに感激していました。'),
  ('bb739b4a-b738-56f7-b4a4-1f2028ea0d6b', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-08', '16:30:00', null, '通常 / 基本操作コース10_キャッチゲーム、ブロックのことばを使って細分化する', 'ゲームをプレイした後に文章で細分化をすることはよくできているのですが、その文章からブロックにコーディングしていくときに、どこから手をつけていいのか悩む傾向がみられます。そのため、間にワンクッションおいて、なるべくブロックにある言葉を使って細分化をする練習をしてみました。 「ずっと」の入れ忘れの防止や、演算式をじっくり見る効果がありました。 日本語からたどっていくと、「座標を〇にする」「座標を〇ずつ変える」の使い分けがわかりやすいようでした。 ゆきちゃんが作成した日本語とブロックを丁寧にみていくことにより、キャッチの際に音を鳴らしたりコスチュームを変えたりする順序によって動きが変わることもよくわかり、順次処理の意味もよく理解できたようでした。', null, 'タイピング: プラチナ級を出せていました。
盛り上がり: コーディングの際は指示待ち、ヒント待ちのことが多かったゆきちゃんですが、今日は細分化シートを見ながらスムーズにプログラミングができていました。 本人の達成感もいつもよりあったのでは、と思われます。'),
  ('99682b92-00ee-50a0-8114-83bfedd3d3c6', 'b2246586-4496-52f9-a825-be2488a00a31', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-09-08', '17:30:00', null, '通常 / 自作ゲーム作りとスプラもどきのつくり', '前半はストーリー性のある死ニゲーを作っていました。画面上にあるボタンを押すと、場面が変わっていくことをメッセージとコスチューム変化のコードでうまく表現できていました。ただ、途中で画面が真っ暗になったといってきて、バグができたからやめると作品制作が止まってしまいました。一緒に見て直していこうと提案してみましたが、かたくなに拒否してしまいました。 後半は、スプラのもどきを説明を加えながら作っていきました。完成形と今作っている段階で比べて、だんだんと近いづいていることを実感しながらやる気が継続できたのでよかったと思う。', null, '盛り上がり: 色が塗られている様子がとても楽しくできていました。'),
  ('2a638bc7-7341-5ba8-9040-f5af2df6a209', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-08', '17:30:00', null, '通常 / （アクションゲームで使われているような）ジャンプの方法を学びつつ 楽しくプログラミングする！', '初めにプレイしてもらい、プログラムのコードを想像してもらいました。ジャンプについては「下に下がる」とだけコメントしてくれたので、どこまで下がるのかを深く掘り下げました。コードを見てプログラムしてもらいましたが、かなりはやくプログラムし終えました。 アレンジとして偽クリア画面を作成していました。次のステージに進まない不具合が生じたので、ステージ画面を次に送るコードを一緒に確認し、手を加えました。条件分岐を上から読み確認するのは、まだ苦手なようです。新たに作ったステージでジャンプさせるため、コードを変化させるのではなくステージの色を変えていたのがとても良かったです。', null, 'タイピング: 粘って取り組めていました！
盛り上がり: いつもよりも集中して取り組めていたように感じました！！'),
  ('16a4f6a0-0066-53a1-bdce-16a523a22914', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-08', '17:30:00', null, '通常 / 作品提出に向けてバグ探し（3つはつぶしたい！）', '検定と大会のスケジュールについて細かく確認しました。 前回に引き続きバグの修正をしました。ドラゴンの攻撃が当たる（ダメージを当たる）ように修正していました。剣の位置をマウスの位置と対応させて画面の混乱を減らしました。ドラゴンとビームの出現タイミングについても修正を加えていました。何度も試行錯誤を繰り返していました。 次回直す予定のバグについて最後に確認しました。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: とても集中して取り組めていました！学校の宿題提出がピンチみたいです！'),
  ('68490dfb-5ef5-590e-8877-fbfe58cc15eb', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-08', '16:30:00', null, '通常 / プレゼン作成・大会準備', 'プレゼン用に家で書いてきた紙を忘れてしまっていたようなので、明日プレゼンに取り組むことになりました。 大会準備として、前回に引き続きストーリー作成を行いました。最前面。最背面のコントロールに苦戦し、何度も試行錯誤していました。こちらが声をかけても自分で解決したい様子でした！粘り強かったです。 最後に得点を条件分岐させて表示させる言葉を変える部分で混乱したので、説明しました。＝を使って解決しようとしていたので、不号を使ったときの論理構造について説明を加え、実際に使ってもらいました。理解できた様子でした！ 提出する大会のテーマについて再度説明しました。', '明日来てくれます。プレゼン準備の予定です！', 'タイピング: ミス率5%ととても正確にタイピングできていました。
盛り上がり: とても集中して取り組んでくれました！！！！すごい！！'),
  ('3ecabc6f-e051-5872-8509-33e6b2113f8f', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-08', '16:30:00', null, '通常 / 基本操作コース さあ踊ろう', 'そうちゃんの意見を聞いているとどんどんオリジナルに突き進んでしまうので、今日は本人の想像に付け足すような感じで単元の項目の提案を混ぜていきました。 こちらの提案を前向きに受け入れてくれて、スタンプ以外の項目を終えることができました。 明るさの変化については数値を変えてどういう変化になるかを試してもらったところ、面白がっていました。 コスチュームの使い分けを駆使して楽しそうにダンスのポーズを作成していました。 BGMが思うように流れないところに気付いたため、「～の音を鳴らす」「終わるまで～の音を鳴らす」の違いを両方のブロックを使って確かめました。', null, 'タイピング: 下段のキーもだいぶ覚えてきました。 初めはbとdの混同が見られましたが、終盤ではほぼできていました。 同じキーが続くときはほぼ右手で打ってしまう癖がありますが、キーが混在してくると両手を使って打てています。
盛り上がり: 基本的に、自分のアイディアもこちらの提案も楽しそうに取り組んでいました。 キー操作でコスチュームを変えてうまくダンスにできたときは満足そうでした。'),
  ('b47418a8-61a5-5b65-877e-7ab04b91b413', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-06', '17:30:00', null, '通常 / 素材からゲームを考える', '前回作成していた自作ゲームに手を加えていました。剣が当たると、敵が赤くなって後方へ飛ぶところは、マイクラの動きを参考に自分で考えてみたそうです。 素材だけのバレーボールとカーレースに取り組もうとしていましたが、「ちょっと難しそうだからもう少し他のをやってから」とのこと。 【Prg】56 シューティングゲームを作ろう！を見て横スクロールに興奮し、一生懸命にコードを見て「予想があたった！」となっていたので、「スクロールの演習」のコードを一緒に見ていきました。コードの内容を把握してから、オリジナルのアスレチックゲームの作成に取りかかっていました。', '自作アスレチックゲームの横スクロールを作成したいところです。 それが済んだら縦スクロールにもチャレンジしたいとのこと。', '盛り上がり: 新しい素材を見つけた時のワクワク度が高く、本人も熱心に吸収しようとしています。「この動きがいい！」となったときに、それをコピペしないでじっくり読み込み、必ずゼロの状態から自作ゲームを構築していく根性はなかなかです！ 教室に入ってから、やれることが増えたし、スムーズにできるようになった実感があると言ってくれました！'),
  ('870abfaa-c2f2-5e51-b95a-dbb1a8bda6b4', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-06', '16:30:00', null, '通常 / ジャンピングゲームの完成', '04の、ジャンプの時に音を鳴らすから入りました。 ジャンプの高さと障害物の速さの兼ね合いで、ジャンプから降りた時にぶつかってしまうことが多く、それぞれのスプライトの速さや高さの調整に苦労していました。 変数や座標はよく覚えていますが、ブロックを入れる場所などに迷う場面が見られました。', '葉くんがやっていたジャンプを何度も見ていたので、いろいろなジャンプに入るか、検定を一度させてみるか…', 'タイピング: 覚えているキーはよく打てていますが、まだ画面上に表示される大文字と、キーボードの小文字が一致せず、形が異なるアルファベットには苦労しているようです。
盛り上がり: 葉くんがよくしゃべるせいか、競うようにしゃべるようになってきました。 対抗して「先生、わからないからきてー」と声をかけてくることが増えましたが、見に行くと自分でできることが多いので、できているときに褒めながら、自分でやれるところを増やしていったら、最後の変数などはスラスラと作成することができました。
備考: 検定について、お家ではお父さんが乗り気でしょうたくんに練習？をさせているそうで、かえってしょうたくんが「無理～」となるときもあるとか…。しょうたくん本人は、「きっとできるよ」と声をかけると、「じゃあやろっかなあ」といいますが、お母さんのお話だと、少ししり込みしてしまっているところもあるそうです…'),
  ('4933789a-c9f1-5e5d-b651-cfe8d41a8af2', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-06', '16:30:00', null, '通常 / ジャンプの動きを学ぶ', 'ジャンプを土台の上で止めたり、土台を突き抜けないようにしたりするにはどうしたらよいのかを考えてもらい、何とか「スプライトの色と土台の色がぶつかった時に何かする？」というアイディアを出すことができました。 参考のゲームをプレイしてからコードを見て、色同士が触れたらどんなことが起きているかを読み取ってもらい、これを参考にして少し自力で考えることを促しました。 写経になった部分もありますが、前回よりは少し、考える時間が取れたかと思われます。', '自作ジャンプの修正をする予定です。', 'タイピング: うつことはだいぶ早くなりましたが、その分飽きもきているようで…今日は2ステージだけ取り組みました。
盛り上がり: コードを読み取ることには少し慣れてきたようで、「土台にぶつかったときに先に進めないコード」「土台に着地するコード」など、自力で探し当てることができました。 そこから応用して作成するのはまだ難しそうですが、チャレンジしたい意欲はあるので、徐々に進めていければと思います。
備考: 祥太くんが葉くんに慣れてきたせいか、プログラミングでもおしゃべりでも、二人でおおいに盛り上がっていました。 おかあさんは検定に興味津々でしたが、ようくんはまだちょっと厳しそうなので、「今やっている単元が途中なので、来月までに検定の範囲を終えるのは難しい」とお伝えして、興味がおありならこの次の検定のときにまた、進度や様子をみてご検討いかがですか？とお伝えしてあります。 ようくんは検定よりもロボット、ロボット！とアピールしていましたが、お母さんは、土日はイマイチの反応でした…。'),
  ('03ddd298-3f3d-54a4-b4ec-75b052890e9e', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-03', null, null, '通常 / 教室に慣れる！', 'ゆうきくんと同様に、やりたいことが06寄りになったため、こちらの単元のほとんどを扱うことになりました。 先に入室した30分で、基本操作コースの名前を動かそうの内容はほぼさらうことができました。スプライトが動いたり変化したりするたびに面白がってくれました。', null, '時間帯: その他
盛り上がり: 一つ一つの単元によく反応してくれて、楽しんでいたと思われます。 学ぼうとする意欲もあり、今後が楽しみです。'),
  ('1e95619a-c816-5e5e-81c4-2c74c1313c6d', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-03', null, null, '通常 / 授業の形式に慣れる', '当初は基本操作コース02で進めようとしていたのですが、やりたがることが06に近かったのと、理解が出来そうだったため、途中から06の流れに沿って進めました。 自分の考えた物語が形になるのがとても嬉しそうで、終始生き生きと進めていました。 キーボードも良く打てていて、長いセリフも楽しそうに入力していました。', null, '時間帯: その他
タイピング: タイピングの経験があるようで、よくできていました。
盛り上がり: スプライトやセリフを考えるときにとても嬉しそうでした。 話がどんどんふくらんで、メッセージ機能まで使うことができるようになりました！
備考: 折を見て02の内容の補足をしながら、物語作成系の作品を作って単元の確認をします。'),
  ('652f3570-07df-520a-bc13-3b71bb91ce07', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-09-05', '17:30:00', null, '通常 / 脱出ゲームの作成', '脱出ゲームを自分の手で作りました。ブロックを分けすぎたことでコードがごちゃごちゃしてしまったので、まとめるとすっきりしました。また、同じ内容のコードを二か所に書いてしまったことによるバグを発見して修正しました。', null, 'タイピング: 楽しくタイピング練習ができていました。
盛り上がり: レッスンが始まる前から製作に取り掛かっていて、かなりやる気があるようでした。'),
  ('ed99a7b8-aff3-5851-9887-7ef75539321d', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-05', '16:30:00', null, '通常 / プレゼンの準備', '今まで作っていたはずのスライドが消滅してしまったので、新らしく作ることになりました。 ポイントとして「魔法の数字3」「言いたいことを書かない」ということを伝えました。言いたいことを並べて見にくくなってしまっていました。箇条書きの見やすさ、フォントの大きさについて説明しました。どれも納得してくれたようで、その後のスライドでは言いたいポイントを3つに絞ったりまとめたりできていました！', null, '盛り上がり: 色合いが素敵でした！'),
  ('2bdc32b9-e530-5e44-b753-034ae489b6d0', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, null, '2022-09-05', '17:30:00', null, '休み', null, null, null),
  ('53668179-c389-55a8-a5a0-a4d0f8b8b5df', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-05', null, null, '通常 / ゴルフゲームのバグ探し、コードモンキー', '前回完成したゴルフゲームのバグを探しました。自分で怪しいと思うコードを見直し、それでも見つからなかった場合は動画の見直しをして修正しました。さすがに中学生の集中力で、地道に修正ができていました。 うったボールがうまく止まらないところだけ、修正ができずに残ってしまいましたが、少し疲れたようだったので、最後のバグ探しは次回にし、コードモンキーに初挑戦してもらいました。 コードモンキーは17まで進めました。簡単なことの繰り返しですが、コードの書き方に慣れることが目的だということは理解してくれたようで、淡々と進めていました。 テキスト言語の書き方として、1行で一つのコードということと、turnとturnToの使い分け、命令する対象が変わるときの書き方などをマスターできていました。', 'ゴルフゲームのバグ修正、コードモンキー18～', '時間帯: その他
タイピング: 安定しています。
盛り上がり: Scratchもコードモンキーも、どちらも集中して取り組めていました。
備考: コードモンキーの動きでしばらく考えることもあったので、レベルが上がってコードが複雑になってきたら、簡単なフローチャートを書いてからコードを書く手順を踏んでも良いかもしれません。'),
  ('9733d1eb-1cdc-5443-9017-c9fb829a5f89', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-05', '17:30:00', null, '通常 / ブロック崩しでリアルな反射を学ぶ', 'ブロック崩しに挑戦しました。まだ角度には少し苦手意識のある様子でした。 パドルの動きは、ポインターとパドルの動きの似ている点に注目してもらうとすぐに気づいてプログラムすることができていました。 リアルな反射のプログラムの仕方を説明すると、完全に理解できてはいませんでしたが、質問をしてくれたり、自分で具体的な数を入れられていてとても良かったです。 ブロック消去のタイミングとボールの反射のタイミングをもう少し調整する必要がありそうです。', null, 'タイピング: ホームポジションにも意識して取り組めていました！はやい！
盛り上がり: とても集中して取り組めていました！すごい！'),
  ('f7a76640-a987-59a7-85a7-9cbc3fbac370', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-05', '16:30:00', null, '通常 / ピンポンゲームの完成、音楽のブロックを学ぶ', '複製したブロックをそのままにしていたりして、同じブロックが7個くらいできていて、変数のカウントアップがおかしいことになっていました。Scratchは書かれたコードを全部律義に実行していることを伝え、自分のコードを見直しさせたところ、重複ブロックに気が付いて修正することができました。 他にも条件を満たしたときに「すべてを止める」を何か所にもあり、他のスプライトのコードを実行する前に止まってしまうところがあり、自分のコードを見直してもらいました。その結果、コードを整理し、実行される順番に気を配れるようになってきました！ スプライトAがBに触れた時と、スプライトBがAに触れた時、のように、同じ命令をすべてのスプライトで作成する癖がありました。いっぺんに命令されたらScratchも混乱するので、一つの動きに対して命令は1度で良いことを説明したら、自分のスプライトをひとつずつ 丁寧に見直してコードを確認することができるようになりました。', 'ピンポンゲームは一応完成です。 変数の初期設定や変更を複数個所でする癖があるので、何度か同じような問題にチャレンジして慣れていけると良いかと…', 'タイピング: まだ速さや正確さは学年相応という感じですが、丁寧にやろうとしていました。
盛り上がり: ピンポンゲームに加えたいアレンジの希望がはっきりしていて、楽しそうに作成していました。 作成しているときに、どのスプライトにコードを作成しているかが曖昧になって重複コードがたくさんできていたりしたのですが、自分のコードを見直してすっきりすることによって動きが安定したことが嬉しそうでした。'),
  ('77b3d9e6-ca23-5258-9117-804c34fe79ec', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-09-02', '17:30:00', null, '通常', 'キャッチゲームが完成した後は自分の作りたいゲームを作りました。ピストルでコウモリを撃つゲームを作りたいようでした。弾がコウモリに触れたらポイントが入る仕組みは作れていました。最後の方まで集中していました。', null, '盛り上がり: 自由にゲームを作るときは、やりたいことをどんどん言葉にしていてやる気がある様子でした。'),
  ('04dfd8fd-2d57-5de6-b6a6-67599c459b04', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-02', '16:30:00', null, '通常 / 写経の必要性を理解する。', '脱出ゲームを動画を見ながら作りました。 たまにめんどくさいような感じのことを言ってましたが、なんだかんだ50分間集中してできていました。', '脱出ゲームの続き', 'タイピング: タッチタイピングができるようになりたいと言ってました。 左手をほぼaとzを打つためだけに使っているため、そこを矯正できるとより早くなると思いいます。
盛り上がり: けいとくんにゲームをプレイしてるところを楽しそうに見せてました。'),
  ('fb2fdf59-7d68-52fd-9826-8346e74f1306', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '761a91b5-63ed-547d-8524-e06abcc55967', '2022-09-02', '17:30:00', null, '通常 / 変数、ジャンプゲームの復習', 'ピンポンゲームの復習 ライフがなくなったときにゲームオーバーにするという部分ができていなかったのでそこを完成させました。 ジャンピングゲーム スプライト選びにこだわっていました。 障害物が動く動作を少し迷っていました。 「ずっと」と「もし」の入れ子がどっちが先になるみたいなのがこんがらがっていたようです。', 'ジャンプゲームを完成させる。', 'タイピング: 集中してできていました。
盛り上がり: スプライトで熱帯魚を選んだのですが、その際に家族旅行で恵比寿島(？)に行った時の話を楽しそうにしてくれました。'),
  ('8430d0ec-cf29-5bbb-8f08-8ed1bc182e0f', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-02', '18:40:00', null, '通常 / 自分でゲームを組み立てる', 'コードなしのスプライトと背景だけを素材に、「バレーボールゲームを作る」というお題で、ゆまちゃん、まっつん、こうくんの3人に自由に「バレーボール」ゲームを作ってもらいました。 矢印キーによってむらっちと手の向きが変わるように工夫をしていました。', null, 'タイピング: 安定しています。
盛り上がり: 「向きを変える」「向きによって手やボールの向きを変える」という本来の出題意図をしっかりと汲んで作成していました。 3人で作成して見せ合いをするのは、楽しんでくれていたように見えました。 発表終了後にボールを剣に変えてホラーゲーム？に改造していました。'),
  ('bda26e82-26fa-5eaf-a389-11602d3c3778', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-02', '17:30:00', null, '通常 / 基本操作コース10_ キャッチゲーム、自分の力で考える', 'わからないことがあるたび（場合によっては新しい課題にあたるたびに…）先生に頼る傾向があるので、毎回教えずに自分でもう少し考えること、どうしても先に進めない場合は実行する部分を限定して動かしてみて、正しく動いているところとそうでないところを見極めるやり方などだけを説明して、「こたえを教える」ことをなくしてみました。 本人はとても疲れたようですが、それでも「先生わからない」ではなく、「先生できた」という発言がいつもより多くなりました！ 分割しなくてもよいところを2本のコードにしていたため、片方がうまく動いていなかったところを自分で直すことができました。 ゲーム完成後にこちらが与えた課題、「点数が20ぴったりでなくても終了させる」「ゲーム中とゲームクリア時で背景を変える」を、自力でクリアできました。', null, '盛り上がり: 完成後の5分間は少しぐったりしていましたが、達成感はいつもより得られたのではないかと思われます。 自分で解決できた時は、とても嬉しそうに先生を呼んでいました。'),
  ('4ea8b7f4-0d15-5af0-8c81-52b5c93361b4', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-02', '16:30:00', null, '通常 / 教室に慣れる、基本操作コース02 名前を動かそう', '一つ一つの単元を、どれも興味を持って熱心に取り組んでいました。新しいコードを覚えるたびに、納得して面白がってくれるので、教える側にも張り合いのある生徒さんです。 プログラムを実行するきっかけとして、旗が押されたときとスプライトが押されたときを使い分けられること、繰り返しの使い方、座標の指定の仕方等、問題なくマスターできました。 スプライトが画面上を移動して最初の位置に戻るとき、既存のブロックを一度外してスタート位置に戻すプログラムを実行してから「座標に移動する」ブロックを使うなど、状況に応じて上手にブロックの操作をしながら進めていました。', null, 'タイピング: 学校でやったことがあるとのことで、第2ステージの途中まで危なげなくクリアしていました。タイピング中の姿勢がとても良いです。
盛り上がり: 一つの動きを作成するたびに、心から楽しそうに実行をしていました。 出来上がった作品にも満足してくれたようで、お母さんにも嬉しそうに見せていました。 新しいことを覚えるのが楽しい！という感じでした。'),
  ('3c50883f-3935-5497-88be-9f21f27ddeb1', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-02', '16:30:00', null, '通常 / キャッチゲーム→You Winの表示（制御） 星とり:応用編に挑戦（できる範囲で）', '「勝ち」の表示に挑戦してもらいました。自分で全てプログラムできていたので良かったです。犬がフルーツに触れたときと、フルーツが犬に触れたときをうまく考え分けるのは苦手なようです。表示のタイミングに関しては自分で考えてプログラムできていたので良かったです。スコアのタイミングとフルーツの表示非表示のタイミングが重なってしまうとうまく動かず、分けて考えてはいけないということが少し難しかったようです。 星取りゲームの内容を一緒に確認して授業を終えました。ゲームのポイントについてこちらが質問したら、明確にはっきり答えられていたので良かったです。', null, 'タイピング: 自分からPlayGramがしたいと言ってくれました！頑張れていました！
盛り上がり: 少しお疲れの様子でした。'),
  ('6dbd60b9-8583-5d23-bd99-50731f544271', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-02', '17:30:00', null, '通常 / 迷路脱出ゲーム（ポインターへ行く・壁での跳ね返り）', 'マウスのポインターで動かすのは気が乗らなかったようです。プログラムは「マウスポインターへ行く」を使おうとしていましたが、「～へ向く」との使い方の違いについて説明しました。ポインターで動かすプログラムは完成したのですが、挙動が気に入らなったので矢印キーで動かすことになりました。壁で跳ね返るコードもスムーズに自分で作ることができていました。 最近はまっているゲームの要素をいくつか取り出してアレンジをしていました。最後、オリジナルで変更を加えた部分（ボタンを押した後の白黒点滅部分）がうまく動かなかったので、来週再度挑戦したいそうです。', null, 'タイピング: 集中して取り組めていたので良かったです。
盛り上がり: 絵を描きたいようでしたが、タッチパネルではなかったので断念していました。タッチパネルのパソコンの方がいいかもしれません。'),
  ('992024f7-8bc7-52ef-b320-656ebfbc9bec', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-09-01', '17:30:00', null, '通常 / 検定準備、バグ取りの練習', '軽いバグ取りについてはいったん自分で考えてもらう時間をとりましたが、まだヒントや問いかけが必要な段階みたいです。変数の初期設定、座標の変化などはできていました。変数の更新については、バグ取りというよりは一から組みなおすような感じでした。 キャッチゲームは細分化し、スプライトの準備が終わり、少しコードを書き始めました。少し問いかければ細分化はできていたので、ゲームの全体像をイメージできたようでよかったです。', 'キャッチゲームのコーディングを進めましょう', 'タイピング: playgramは久しぶりみたいですが、プラチナランクに到達していてとても良いです
盛り上がり: 発言は比較的少なかったのですが、地道に作業を進めていて集中できていたと思います。'),
  ('424e92d6-832e-5c99-86cb-b91e18a4914a', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-01', '17:30:00', null, '通常 / スケジュール作成・大会に向けて作成', 'スケジュールの話をしましたが、どうしても中身の修正の方に気が傾いてしまうそうです。エンディングの修正をするのかと思いましたが、エンディングよりもバグの修正に力を入れるそうです。修正したいバグの一覧を作っていました。（ファイルに挟んであります）今日は弾の速度を修正しました。 最後のドラゴンも思うように動いていないので修正したいようでした。締め切りを意識してもらいたいです。', null, 'タイピング: ときどきホームポジションが崩れていましたが、スムーズに取り組めていました。
盛り上がり: ストーリー作成よりもバグを意識していて素晴らしかったです！'),
  ('f5c27354-d93f-5863-b0f3-73db75f4ffdb', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-09-01', '16:30:00', null, '通常 / 発表準備・作品アレンジ', 'プレゼンの内容の大枠を紙に書いて考えてもらいました。5分間のプレゼンだそうです。 ①タイトル ②ゲーム紹介 ③この作品を作った理由 ④こだわったところ ⑤苦労したところ ⑥次にどんなゲームを作ってみたいのか について説明するそうです。 作品紹介の部分では、動画ではなくゲームの画面の画像を貼って、口頭で操作を説明するそうです。音楽は別にして流すようです。 ストーリー性を追加を提案しました。あるくんとあるごんが一緒にのる設定にしたそうです。写真を使って面白くプログラムできていました！', 'パワポを使う予定なので、Windowsのパソコンがいいと思います。', 'タイピング: 集中して取り組めていました！かなりの高得点でした。
盛り上がり: パワポ作成もとても慣れている様子でした！喋る内容を考えられるように、プリントしたものを渡しました！
備考: 振替分込みで2時間やりました(16:30~18:30)'),
  ('6e3fbdf6-1397-5421-a0d0-8796745aa7ed', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, null, '2022-09-01', '17:30:00', null, '休み', null, null, null),
  ('3dbb2f89-c506-5e07-80a6-458ff1d7cb83', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, null, '2022-08-29', '17:30:00', null, '休み', null, null, null),
  ('2d889674-5a67-5c73-b236-226807998895', 'b2246586-4496-52f9-a825-be2488a00a31', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-01', '17:30:00', null, '通常 / 一つの作品を完成させる', 'タイマーとHP、2つの変数を使ったゲームを作成していました。 HPの変数がうまく減らない原因を自分で探して発見することができました。', null, '盛り上がり: 薬のスプライトに触れると、いろいろなエフェクトがかかるという設定をしていて、斬新なおもしろいゲームができていました。')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

